INSERT INTO questions (id, deck_id, title, content, difficulty, hint, category) VALUES
  ('q-0001', 'react-basics', 'Virtual DOM Explained', 'What is the Virtual DOM in React, and how does it improve rendering performance compared to direct DOM manipulation? Walk through what happens conceptually when setState is called and how React decides what to update.', 'EASY', 'Think about a lightweight JavaScript representation of the UI and the diffing process.', 'Virtual DOM'),
  ('q-0002', 'react-basics', 'Props vs State', 'Explain the difference between props and state in React. When should a component use state versus receive data through props, and what are the implications for data flow and reusability?', 'EASY', 'Consider who owns the data and whether it should change from within the component.', 'State'),
  ('q-0003', 'react-basics', 'useState Hook Basics', 'How does the useState hook work, and why must it be called at the top level of a component rather than inside conditionals or loops? Explain what would break if you violated this rule.', 'EASY', 'React relies on call order to match state values to hooks across renders.', 'Hooks'),
  ('q-0004', 'react-basics', 'useEffect Dependency Array', 'Explain the role of the dependency array in useEffect. What happens when you omit it, pass an empty array, or list specific values? Describe a scenario where an incorrect dependency list causes a stale closure or infinite loop.', 'MEDIUM', 'The array controls when the effect re-runs after the initial render.', 'Hooks'),
  ('q-0005', 'react-basics', 'React.memo and Memoization', 'When should you wrap a component with React.memo, and when is it counterproductive? Discuss the relationship between memo, useMemo, and useCallback, and explain the cost-benefit tradeoff of memoization.', 'MEDIUM', 'Memoization has a memory and comparison cost that must be outweighed by avoided re-renders.', 'Performance'),
  ('q-0006', 'react-basics', 'Context API Use Cases', 'Describe scenarios where the Context API is a better choice than prop drilling or a state management library. What are the performance implications of context, and how can you mitigate unnecessary re-renders of consumers?', 'MEDIUM', 'Any consumer re-renders when the context value changes by reference.', 'Context'),
  ('q-0007', 'react-basics', 'Keys in Lists', 'Why does React require a key prop for items rendered in a list, and what goes wrong if you use the array index as a key? Explain how keys affect reconciliation when items are reordered, inserted, or deleted.', 'MEDIUM', 'Keys give elements a stable identity across renders for the diffing algorithm.', 'Rendering'),
  ('q-0008', 'react-basics', 'useReducer vs useState', 'Compare useReducer and useState. Under what conditions does useReducer produce more maintainable code, and how does it interact with child components that need to trigger state transitions?', 'MEDIUM', 'Think about state with multiple interdependent sub-values and complex transition logic.', 'Hooks'),
  ('q-0009', 'react-basics', 'Concurrent Rendering Features', 'Explain React''s concurrent rendering features such as useTransition, useDeferredValue, and Suspense. How do they help keep the UI responsive during expensive renders or data fetching, and what are the tradeoffs when opting into concurrent updates?', 'HARD', 'Concurrent rendering lets React interrupt, pause, or discard in-progress renders.', 'Performance'),
  ('q-0010', 'react-basics', 'HOCs vs Custom Hooks', 'Compare Higher-Order Components and custom hooks as patterns for sharing stateful logic. What are the nesting, typing, and debugging implications of each, and which approach is preferred in modern functional React and why?', 'HARD', 'HOCs wrap components and add nesting; hooks compose inside the component body.', 'Patterns'),
  ('q-0011', 'javascript-essentials', 'let const var Compared', 'Compare let, const, and var with respect to scope, hoisting, and reassignment. Explain why var is generally avoided in modern code and what temporal dead zone means for let and const.', 'EASY', 'Consider block vs function scope and when the variable actually becomes accessible.', 'Scope'),
  ('q-0012', 'javascript-essentials', 'JavaScript Promise Fundamentals', 'Explain what a Promise is and describe the states it can be in. Walk through how then, catch, and finally chain together, and what happens when a handler returns another promise.', 'EASY', 'A promise represents a value that may be available now, later, or never.', 'Async'),
  ('q-0013', 'javascript-essentials', 'Type Coercion Rules', 'Explain the difference between implicit and explicit type coercion in JavaScript. Describe how the == operator differs from ===, and give an example where loose equality produces a surprising result.', 'EASY', 'Loose equality performs abstract comparison with conversion; strict equality does not.', 'Types'),
  ('q-0014', 'javascript-essentials', 'JavaScript Closures Explained', 'What is a closure in JavaScript, and how does it enable data privacy and function factories? Write a short example of a counter function that uses closure to protect its internal count variable.', 'MEDIUM', 'A closure retains access to variables from its lexical scope even after that function returns.', 'Closures'),
  ('q-0015', 'javascript-essentials', 'Event Loop and Microtasks', 'Describe how the JavaScript event loop processes tasks and microtasks. Given a snippet mixing setTimeout, Promise.then, and queueMicrotask, predict the order of console output and justify your reasoning.', 'MEDIUM', 'Microtasks drain completely before the next macrotask runs.', 'Event Loop'),
  ('q-0016', 'javascript-essentials', 'this Keyword Binding', 'Explain how the value of this is determined in regular functions versus arrow functions. Describe how call, apply, bind, and method invocation each affect this, and a common bug that arises in callbacks.', 'MEDIUM', 'Arrow functions inherit this lexically; regular functions depend on the call site.', 'this'),
  ('q-0017', 'javascript-essentials', 'JavaScript Prototype Chain', 'Explain the JavaScript prototype chain and how property lookup works when accessing a property on an object. Describe the relationship between Object.create, the prototype property of a function, and Object.getPrototypeOf.', 'MEDIUM', 'Each object has an internal link to another object: its prototype.', 'Prototypes'),
  ('q-0018', 'javascript-essentials', 'async await Error Handling', 'How does error handling work with async/await, and how does it differ from promise chains using catch? Discuss the implications of forgetting try/catch and a strategy for handling errors in parallel async operations.', 'MEDIUM', 'An awaited rejected promise throws, which can be caught with try/catch.', 'Async'),
  ('q-0019', 'javascript-essentials', 'Implement Promise all', 'Implement a simplified version of Promise.all that accepts an iterable of promises and resolves to an array of results in order, or rejects with the first rejection. Explain how you handle non-promise values and an empty iterable.', 'HARD', 'Track completion count and resolve only when all promises have settled.', 'Async'),
  ('q-0020', 'javascript-essentials', 'Memory Leaks in SPAs', 'Identify three common causes of memory leaks in long-running JavaScript applications such as single-page apps. For each, describe how the leak occurs and the strategy you would use to detect and fix it.', 'HARD', 'Look for unintended references retained by closures, timers, listeners, or caches.', 'Memory'),
  ('q-0021', 'typescript-deep-dive', 'interface vs type Alias', 'Compare the interface and type alias declarations in TypeScript. When are they interchangeable, and in what situations does one offer capabilities the other lacks, such as declaration merging or union types?', 'EASY', 'Both can describe object shapes, but only one supports declaration merging.', 'Types'),
  ('q-0022', 'typescript-deep-dive', 'Primitive and Literal Types', 'Explain the difference between primitive types, literal types, and union of literal types in TypeScript. Show how literal types enable narrowing in conditional branches and how they are used in discriminated unions.', 'EASY', 'Literal types restrict a value to a single specific value like a string or number.', 'Types'),
  ('q-0023', 'typescript-deep-dive', 'Type Inference Behavior', 'Describe how TypeScript infers types in variable declarations, function returns, and object literals. Explain when you should add explicit annotations versus rely on inference, and the role of noImplicitAny.', 'EASY', 'Inference flows from right to left and from context, but parameters default to any.', 'Inference'),
  ('q-0024', 'typescript-deep-dive', 'TypeScript Generic Functions', 'Write a generic function that takes an array and a key, and returns an object indexed by that key''s value. Explain how the type parameter preserves the relationship between input and output types.', 'MEDIUM', 'Use a type parameter constrained to keyof T to index the element type.', 'Generics'),
  ('q-0025', 'typescript-deep-dive', 'Built-in Utility Types', 'Explain the behavior of Partial, Required, Pick, Omit, and Record utility types. Show how to combine them to model a PATCH endpoint where every field is optional except the id.', 'MEDIUM', 'These are built-in mapped types that transform existing types.', 'Utility Types'),
  ('q-0026', 'typescript-deep-dive', 'User-Defined Type Guards', 'What is a type guard in TypeScript, and how do user-defined type guards using the x is T predicate differ from instanceof or typeof checks? Write a guard that distinguishes between two members of a discriminated union.', 'MEDIUM', 'A type predicate narrows the type within the branch where the guard returns true.', 'Narrowing'),
  ('q-0027', 'typescript-deep-dive', 'TypeScript Conditional Types', 'Explain conditional types and the distributive property when the checked type is a naked type parameter. Show how to use infer within a conditional type to extract the return type of a function.', 'MEDIUM', 'Conditional types select one of two types based on a relationship test.', 'Types'),
  ('q-0028', 'typescript-deep-dive', 'TypeScript Declaration Files', 'Explain the purpose of .d.ts declaration files and how they relate to the type system. Describe how to write an ambient module declaration for a JavaScript library that ships without its own types.', 'MEDIUM', 'Declaration files describe types without providing runtime implementations.', 'Modules'),
  ('q-0029', 'typescript-deep-dive', 'Advanced Generic Constraints', 'Design a generic FormBuilder class whose methods can be chained and whose type tracks which fields have been added, so that calling build before required fields exist is a compile error. Explain the techniques you would use.', 'HARD', 'Use a type parameter that accumulates added keys, and constrain build on a required set.', 'Generics'),
  ('q-0030', 'typescript-deep-dive', 'Implementing a Mapped Type', 'Implement a DeepReadonly<T> mapped type that recursively marks every property of an object (and its nested objects) as readonly. Explain how mapped types, conditional types, and keyof combine to achieve recursion.', 'HARD', 'Recurse only when the property type is an object, otherwise apply the readonly modifier.', 'Types'),
  ('q-0031', 'html-css-fundamentals', 'CSS Box Model', 'Explain the CSS box model, including content, padding, border, and margin. Describe how box-sizing: border-box changes width calculations compared to the default content-box, and why border-box is often preferred.', 'EASY', 'border-box includes padding and border within the declared width.', 'Box Model'),
  ('q-0032', 'html-css-fundamentals', 'Semantic HTML Elements', 'Why does semantic HTML matter for accessibility and SEO? Compare using a div for everything versus semantic elements like header, nav, main, article, and footer, and describe how screen readers use them.', 'EASY', 'Semantic elements convey meaning about the structure to assistive tech and crawlers.', 'Semantics'),
  ('q-0033', 'html-css-fundamentals', 'CSS Position Property', 'Explain the values static, relative, absolute, fixed, and sticky for the position property. For each, describe how the element is positioned relative to its normal flow and its containing block.', 'EASY', 'Each value changes what the element is positioned relative to and whether it stays in flow.', 'Positioning'),
  ('q-0034', 'html-css-fundamentals', 'Flexbox Layout System', 'Describe the flexbox model including main and cross axes, justify-content, and align-items. Design a horizontal navigation bar that distributes its items evenly and vertically centers their content.', 'MEDIUM', 'Flexbox is one-dimensional; the axis depends on flex-direction.', 'Flexbox'),
  ('q-0035', 'html-css-fundamentals', 'Grid vs Flexbox Choice', 'When should you choose CSS Grid over Flexbox, and vice versa? Describe a two-dimensional layout where Grid is clearly superior and a one-dimensional distribution where Flexbox is the better fit.', 'MEDIUM', 'Grid is two-dimensional; Flexbox is one-dimensional.', 'Grid'),
  ('q-0036', 'html-css-fundamentals', 'CSS Specificity Rules', 'Explain how CSS specificity is calculated and how it affects which rule wins when multiple selectors target the same element. Describe how inline styles and !important interact with the specificity cascade.', 'MEDIUM', 'Specificity is a tuple of inline, ID, class, and type selector counts.', 'Selectors'),
  ('q-0037', 'html-css-fundamentals', 'Responsive Design with Media Queries', 'Explain how media queries enable responsive design and the difference between min-width and max-width mobile-first approaches. Describe a breakpoint strategy for a layout that adapts from phone to desktop.', 'MEDIUM', 'Mobile-first starts with base styles and adds complexity at larger widths.', 'Responsive'),
  ('q-0038', 'html-css-fundamentals', 'CSS Centering Techniques', 'Compare at least three different techniques for centering a div both horizontally and vertically within its parent. Discuss the tradeoffs of each approach in terms of browser support and required markup.', 'MEDIUM', 'Options include flexbox, grid with place-items, and absolute positioning with transforms.', 'Layout'),
  ('q-0039', 'html-css-fundamentals', 'CSS Containment Property', 'Explain the CSS contain property and how layout, paint, and size containment can improve rendering performance. Describe a realistic scenario where adding contain meaningfully reduces browser work during scrolling.', 'HARD', 'Containment tells the browser a subtree is independent, allowing scoped reflow and repaint.', 'Layout'),
  ('q-0040', 'html-css-fundamentals', 'Custom Properties for Theming', 'Design a theming system using CSS custom properties that supports light and dark modes plus brand color overrides. Explain how custom properties differ from preprocessor variables in terms of cascade, inheritance, and runtime mutation.', 'HARD', 'Custom properties are live, inherited, and can be changed at runtime via JavaScript.', 'Layout'),
  ('q-0041', 'nodejs-backend', 'Node.js Runtime Architecture', 'Describe Node.js''s single-threaded, event-driven architecture and how it achieves non-blocking I/O despite JavaScript running on one main thread. Explain why this model is well-suited for I/O-heavy workloads but not CPU-bound tasks.', 'EASY', 'Offload I/O to the OS or libuv thread pool and handle results via callbacks.', 'Architecture'),
  ('q-0042', 'nodejs-backend', 'Express Middleware Explained', 'What is middleware in Express, and how does the request-response cycle flow through the middleware stack? Explain the role of next(), the order of registration, and the difference between app-level and router-level middleware.', 'EASY', 'Each middleware receives req, res, and next and must call next or end the response.', 'Middleware'),
  ('q-0043', 'nodejs-backend', 'Express Routing Basics', 'Explain how Express routing matches requests to handlers, including path patterns, HTTP methods, and route parameters. Describe how to structure routes into separate modules using express.Router.', 'EASY', 'Routes match a method plus a path pattern and can extract params from the URL.', 'Routing'),
  ('q-0044', 'nodejs-backend', 'libuv and the Thread Pool', 'Explain the roles of the event loop and the libuv thread pool in Node.js. Describe which kinds of operations are handled on the thread pool versus the event loop, and how the UV_THREADPOOL_SIZE setting affects throughput.', 'MEDIUM', 'Some operations like fs and crypto are delegated to a pool of worker threads.', 'Event Loop'),
  ('q-0045', 'nodejs-backend', 'Node Streams Types', 'Compare Readable, Writable, Duplex, and Transform streams in Node.js. Describe how backpressure works and how piping handles it, and outline when you would implement a custom Transform stream.', 'MEDIUM', 'Backpressure occurs when a consumer cannot keep up with the producer.', 'Streams'),
  ('q-0046', 'nodejs-backend', 'Async Error Handling Patterns', 'Compare strategies for handling errors in async Express route handlers, including try/catch, promise chains, and wrapper higher-order functions. Explain why unhandled promise rejections can crash a process and how to guard against them.', 'MEDIUM', 'Errors in async handlers do not propagate to Express error middleware unless you pass them along.', 'Async'),
  ('q-0047', 'nodejs-backend', 'Securing an Express App', 'List and explain the most important security practices for a production Express application, covering HTTP headers, CORS, input validation, rate limiting, and dependency management. Describe how each mitigates a specific class of attack.', 'MEDIUM', 'Think about helmet for headers, express-validator for input, and express-rate-limit for abuse.', 'Security'),
  ('q-0048', 'nodejs-backend', 'Clustering for Multi-Core', 'Explain how the Node.js cluster module allows a single process to utilize multiple CPU cores. Describe the relationship between the master and worker processes, and the tradeoffs versus using a process manager like PM2.', 'MEDIUM', 'The master forks workers that each run their own event loop on a separate core.', 'Performance'),
  ('q-0049', 'nodejs-backend', 'Microtasks and nextTick', 'Compare the ordering of process.nextTick, microtasks (Promise callbacks), and macrotasks (timers, I/O) in the Node.js event loop. Given a snippet that interleaves all three, predict the execution order and explain the rationale.', 'HARD', 'nextTick callbacks run before microtasks, which run before the next phase of the event loop.', 'Event Loop'),
  ('q-0050', 'nodejs-backend', 'Implementing Stream Backpressure', 'Implement a simple scenario where a fast Readable stream writes to a slow Writable stream, and explain how to handle backpressure correctly without using pipe. Describe what goes wrong if you ignore the drain event.', 'HARD', 'Check the return value of write and pause the source until drain fires.', 'Streams'),
  ('q-0051', 'python-interview', 'Lists vs Tuples', 'Compare Python lists and tuples in terms of mutability, performance, and typical use cases. Explain when you would choose a tuple over a list, and how tuple immutability affects its use as a dictionary key.', 'EASY', 'Tuples are immutable and therefore hashable when their contents are hashable.', 'Data Model'),
  ('q-0052', 'python-interview', 'Classes and Instances', 'Explain how classes and instances work in Python, including the role of __init__ and self. Describe how instance attributes differ from class attributes and the subtlety that arises when a class attribute is a mutable object.', 'EASY', 'self refers to the instance being initialized; class attributes are shared.', 'OOP'),
  ('q-0053', 'python-interview', 'Mutable vs Immutable Types', 'Explain the difference between mutable and immutable types in Python, giving examples of each. Describe the surprising behavior that can occur when a mutable default argument is used in a function definition.', 'EASY', 'Default argument values are evaluated once at function definition time.', 'Types'),
  ('q-0054', 'python-interview', 'Writing a Decorator', 'Write a decorator that times the execution of any function and prints the elapsed time. Then extend it to a version that correctly preserves the original function''s metadata and supports functions with arbitrary arguments.', 'MEDIUM', 'Use functools.wraps and accept *args, **kwargs in the wrapper.', 'Decorators'),
  ('q-0055', 'python-interview', 'Generators and yield', 'Explain what a generator is in Python and how yield differs from return. Describe the memory benefits of generators for processing large datasets, and how to compose generators with yield from.', 'MEDIUM', 'A generator produces values lazily, suspending its state between yields.', 'Generators'),
  ('q-0056', 'python-interview', 'Python asyncio Basics', 'Explain the asyncio event loop and the roles of async def, await, and asyncio.gather. Describe a scenario where asyncio outperforms synchronous code and one where it does not.', 'MEDIUM', 'asyncio is cooperative concurrency that shines on I/O-bound work.', 'Concurrency'),
  ('q-0057', 'python-interview', 'Python Dunder Methods', 'Explain the purpose of dunder (magic) methods such as __repr__, __eq__, __hash__, and __len__. Describe how implementing __eq__ without __hash__ can break an object''s usability as a dictionary key.', 'MEDIUM', 'The data model hooks Python syntax and built-ins into your class behavior.', 'OOP'),
  ('q-0058', 'python-interview', 'The GIL Explained', 'What is the Global Interpreter Lock in CPython, and how does it affect multi-threaded Python programs? Explain why threading can still improve throughput for I/O-bound code but not CPU-bound code.', 'MEDIUM', 'The GIL allows only one thread to execute Python bytecode at a time.', 'Memory'),
  ('q-0059', 'python-interview', 'Multiprocessing vs Threading', 'Compare the multiprocessing and threading modules in Python, explaining when each is appropriate. Discuss the tradeoffs around shared memory, startup cost, and the impact of the GIL on each approach.', 'HARD', 'Multiprocessing sidesteps the GIL but pays serialization and startup costs.', 'Concurrency'),
  ('q-0060', 'python-interview', 'Python Metaclasses Explained', 'Explain what a metaclass is in Python and how it differs from a regular class. Describe a realistic use case where a metaclass is the right tool, and a simpler alternative that often suffices.', 'HARD', 'A metaclass controls the creation and behavior of classes themselves.', 'Data Model'),
  ('q-0061', 'java-interview', 'Interfaces vs Abstract Classes', 'Compare interfaces and abstract classes in Java, including default methods introduced in Java 8. When would you choose one over the other, and what are the implications for class hierarchies and multiple inheritance?', 'EASY', 'A class can implement many interfaces but extend only one class.', 'OOP'),
  ('q-0062', 'java-interview', 'ArrayList vs LinkedList', 'Compare ArrayList and LinkedList in terms of time complexity for get, add, remove, and iteration. Explain when LinkedList would ever be preferable and why ArrayList is usually the better default choice.', 'EASY', 'ArrayList is backed by an array; LinkedList is a doubly linked list of nodes.', 'Collections'),
  ('q-0063', 'java-interview', 'JVM Runtime Overview', 'Describe the major components of the Java Virtual Machine including the classloader, runtime data areas, and execution engine. Explain what just-in-time compilation does and how it improves performance over time.', 'EASY', 'The JVM loads bytecode, manages memory areas, and interprets or compiles it at runtime.', 'JVM'),
  ('q-0064', 'java-interview', 'synchronized and Lock', 'Compare the synchronized keyword with the explicit Lock interface from java.util.concurrent.locks. Describe the additional capabilities Lock provides such as tryLock, fairness, and interruptibility, and the responsibility tradeoff.', 'MEDIUM', 'synchronized is implicit and block-scoped; Lock must be released in a finally block.', 'Concurrency'),
  ('q-0065', 'java-interview', 'Dependency Injection in Spring', 'Explain dependency injection in Spring and the difference between constructor, setter, and field injection. Describe why constructor injection is generally recommended and how it interacts with final fields and immutability.', 'MEDIUM', 'Constructor injection makes dependencies required and supports immutability.', 'Spring'),
  ('q-0066', 'java-interview', 'Stream API Operations', 'Describe the difference between intermediate and terminal operations in the Java Stream API. Explain how lazy evaluation works, and why peeking inside a stream with no terminal operation produces no output.', 'MEDIUM', 'Streams are lazy and only execute their pipeline when a terminal operation is invoked.', 'Streams'),
  ('q-0067', 'java-interview', 'Garbage Collection Basics', 'Explain how garbage collection works in the JVM, including the concepts of reachability, generations, and common collectors like G1. Describe how a memory leak can still occur in a garbage-collected language.', 'MEDIUM', 'Unreachable objects in the heap are reclaimed; leaks happen via unintended references.', 'Memory'),
  ('q-0068', 'java-interview', 'Generics and Type Erasure', 'Explain Java generics and the concept of type erasure. Describe the implications of erasure for runtime type checks, method overloading, and the need for bounds like <T extends Comparable<T>>.', 'MEDIUM', 'Generics are a compile-time feature; the runtime sees raw types.', 'Generics'),
  ('q-0069', 'java-interview', 'Composing Async CompletableFutures', 'Explain how CompletableFuture enables composing asynchronous tasks in Java. Compare thenApply, thenCompose, and thenAccept, and describe how to combine multiple futures with allOf and anyOf while handling exceptions.', 'HARD', 'thenCompose flattens nested futures the way flatMap does for streams.', 'Concurrency'),
  ('q-0070', 'java-interview', 'Spring Bean Lifecycle', 'Walk through the full lifecycle of a Spring bean from instantiation to destruction, including instantiation, dependency injection, BeanPostProcessor callbacks, initialization, and destruction. Explain where @PostConstruct and @PreDestroy fit in.', 'HARD', 'BeanPostProcessor hooks run before and after initialization callbacks.', 'Spring'),
  ('q-0071', 'c-sharp-dotnet', 'Value vs Reference Types', 'Explain the difference between value types and reference types in C#, including where instances of each are allocated. Describe the behavior of assigning a struct versus assigning a class instance to a new variable.', 'EASY', 'Value types copy on assignment; reference types copy the reference.', 'Types'),
  ('q-0072', 'c-sharp-dotnet', 'Properties vs Fields', 'Compare fields and properties in C#, and explain why exposed properties are generally preferred over public fields. Describe auto-implemented properties and how expression-bodied members simplify property definitions.', 'EASY', 'Properties look like fields but are methods under the hood, enabling encapsulation.', 'OOP'),
  ('q-0073', 'c-sharp-dotnet', 'Common Collection Types', 'Describe the most commonly used collections in .NET such as List<T>, Dictionary<TKey, TValue>, HashSet<T>, and LinkedList<T>. Explain when you would choose each based on lookup, insertion, and ordering requirements.', 'EASY', 'Each collection optimizes different access patterns and ordering guarantees.', 'Collections'),
  ('q-0074', 'c-sharp-dotnet', 'async await Internals', 'Explain how async and await work in C#, including the role of the state machine generated by the compiler. Describe what happens to the calling thread when it awaits an uncompleted task and how continuation resumes.', 'MEDIUM', 'The compiler rewrites async methods into a state machine that resumes on continuation.', 'async'),
  ('q-0075', 'c-sharp-dotnet', 'LINQ Syntax Comparison', 'Compare LINQ query syntax and method syntax, explaining when each is more readable. Describe deferred execution versus immediate execution, and how calling ToList changes the timing of a query.', 'MEDIUM', 'Most query operators defer execution until the query is enumerated.', 'LINQ'),
  ('q-0076', 'c-sharp-dotnet', 'C# Generic Constraints', 'Explain generic type constraints in C# including where T : class, where T : struct, where T : new(), and where T : IComparable<T>. Describe a scenario where a constraint is necessary for the code to compile.', 'MEDIUM', 'Constraints let the compiler assume capabilities of the type parameter.', 'Generics'),
  ('q-0077', 'c-sharp-dotnet', 'Delegates and Events', 'Explain the relationship between delegates and events in C#. Describe why events restrict external code to only subscribing and unsubscribing, and how this differs from a plain public delegate field.', 'MEDIUM', 'An event is a delegate with restricted access: only += and -= from outside.', 'Delegates'),
  ('q-0078', 'c-sharp-dotnet', 'Garbage Collection Generations', 'Explain the generational garbage collector in .NET, including generations 0, 1, and 2 and the large object heap. Describe the performance rationale for generational collection and how the using statement relates to non-memory resources.', 'MEDIUM', 'Generations exploit the assumption that new objects die young.', 'Memory'),
  ('q-0079', 'c-sharp-dotnet', 'Task vs ValueTask', 'Compare Task and ValueTask in C#, explaining when ValueTask can improve performance and the restrictions it imposes. Describe the risks of awaiting a ValueTask multiple times or after it has completed.', 'HARD', 'ValueTask can avoid allocation when the result is available synchronously.', 'async'),
  ('q-0080', 'c-sharp-dotnet', 'IDisposable and Dispose Pattern', 'Explain the IDisposable interface and the dispose pattern in C#, including the role of Dispose(bool), GC.SuppressFinalize, and finalizers. Describe the consequences of forgetting to dispose a resource that owns unmanaged handles.', 'HARD', 'The pattern distinguishes managed from unmanaged cleanup and supports both manual and finalizer-driven disposal.', 'Memory'),
  ('q-0081', 'go-programming', 'Pointers in Go', 'Explain how pointers work in Go and how they differ from pointers in languages like C. Describe when you should pass a pointer to a function versus passing a value, and how this affects performance and mutability.', 'EASY', 'Go has pointers but no pointer arithmetic; passing a pointer lets the callee mutate.', 'Basics'),
  ('q-0082', 'go-programming', 'Slices vs Arrays', 'Compare arrays and slices in Go, including how slices reference an underlying array. Explain how the length and capacity of a slice relate, and what happens when you append beyond the current capacity.', 'EASY', 'A slice is a header of pointer, length, and capacity referencing an array.', 'Types'),
  ('q-0083', 'go-programming', 'Idiomatic Error Handling', 'Explain Go''s approach to error handling using the error interface and multiple return values. Describe the philosophy of treating errors as values, and how errors.Is and errors.As improve on direct comparison.', 'EASY', 'Errors are returned values the caller must check; wrap them for context.', 'Error Handling'),
  ('q-0084', 'go-programming', 'Goroutines and Channels', 'Explain goroutines and how channels enable safe communication between them. Describe the difference between unbuffered and buffered channels, and what it means for a send or receive to block.', 'MEDIUM', 'Goroutines are lightweight threads; channels synchronize and pass values between them.', 'Concurrency'),
  ('q-0085', 'go-programming', 'Go Implicit Interfaces', 'Explain how Go interfaces are satisfied implicitly rather than explicitly. Describe the benefits and drawbacks of structural typing, and the convention of defining interfaces at the point of use.', 'MEDIUM', 'A type satisfies an interface by implementing its methods, with no declaration.', 'Interfaces'),
  ('q-0086', 'go-programming', 'Garbage Collection in Go', 'Describe Go''s concurrent garbage collector and the tradeoffs it makes for low latency. Explain how the GOGC environment variable controls the collector and what setting GOGC=off implies.', 'MEDIUM', 'Go''s GC targets low pause times by running concurrently with the program.', 'Memory'),
  ('q-0087', 'go-programming', 'Go select Statement', 'Explain the select statement in Go and how it handles multiple channel operations. Describe the default case for non-blocking communication and how select with a time.After can implement timeouts.', 'MEDIUM', 'select chooses one ready case at random, or default if no case is ready.', 'Concurrency'),
  ('q-0088', 'go-programming', 'sync Mutex and RWMutex', 'Compare sync.Mutex and sync.RWMutex in Go, and explain when each is appropriate. Describe the consequences of forgetting to unlock a mutex and how defer can be used to prevent it.', 'MEDIUM', 'RWMutex allows many concurrent readers or one exclusive writer.', 'Concurrency'),
  ('q-0089', 'go-programming', 'Context for Cancellation', 'Explain the context package in Go and how context.Context propagates cancellation, deadlines, and request-scoped values. Describe why context should flow from parent to child goroutines and why it should be the first parameter.', 'HARD', 'Contexts form a tree where cancelling a parent cancels all descendants.', 'Concurrency'),
  ('q-0090', 'go-programming', 'Channel Patterns Design', 'Design a worker pool in Go using channels to distribute jobs and collect results. Explain how you would implement graceful shutdown, limit concurrency, and signal completion to the caller without leaking goroutines.', 'HARD', 'Use a buffered jobs channel, a sync.WaitGroup, and close the results channel after workers finish.', 'Concurrency'),
  ('q-0091', 'rust-programming', 'Rust Ownership Basics', 'Explain Rust''s ownership model and the three rules that govern it. Describe what happens when you assign one variable to another for a heap-allocated type like String, and why this prevents double-free errors at compile time.', 'EASY', 'Each value has a single owner that is dropped when it goes out of scope.', 'Ownership'),
  ('q-0092', 'rust-programming', 'Enums and Pattern Matching', 'Explain how enums in Rust differ from enums in C or Java, and how pattern matching with match works. Describe Option<T> and why it is safer than using null.', 'EASY', 'Rust enums can carry data per variant; match must be exhaustive.', 'Types'),
  ('q-0093', 'rust-programming', 'Result and Option Handling', 'Explain the Result<T, E> and Option<T> types in Rust and the difference between unwrap, expect, and the ? operator. Describe why the ? operator is preferred in library code over unwrap.', 'EASY', 'The ? operator propagates errors early without explicit match boilerplate.', 'Error Handling'),
  ('q-0094', 'rust-programming', 'Rust Borrowing Rules', 'Explain Rust''s borrowing rules: you can have either one mutable reference or any number of immutable references, but not both. Describe why these rules prevent data races at compile time, and a common situation that trips up newcomers.', 'MEDIUM', 'References must always point to valid data and cannot alias mutable access.', 'Borrowing'),
  ('q-0095', 'rust-programming', 'Traits and Trait Bounds', 'Explain traits in Rust and how they compare to interfaces in other languages. Describe trait bounds on generic functions, and the difference between static dispatch with trait bounds and dynamic dispatch with trait objects.', 'MEDIUM', 'Trait bounds are monomorphized at compile time; dyn Trait uses a vtable at runtime.', 'Traits'),
  ('q-0096', 'rust-programming', 'Rust Lifetimes Explained', 'Explain what lifetimes are in Rust and why the compiler needs them. Describe the purpose of lifetime annotations on function signatures and what the compiler checks when it validates them.', 'MEDIUM', 'Lifetimes tell the compiler how long references are valid relative to each other.', 'Lifetimes'),
  ('q-0097', 'rust-programming', 'Send and Sync Markers', 'Explain the Send and Sync marker traits in Rust and how they relate to thread safety. Describe why Rc<T> is not Send but Arc<T> is, and how these markers are enforced at compile time.', 'MEDIUM', 'Send moves ownership across threads; Sync allows shared references across threads.', 'Concurrency'),
  ('q-0098', 'rust-programming', 'Smart Pointer Types', 'Compare Box<T>, Rc<T>, and Arc<T> in Rust, explaining when each is appropriate. Describe how RefCell<T> and Mutex<T> provide interior mutability, and the difference between runtime and compile-time borrowing checks.', 'MEDIUM', 'Box owns on the heap, Rc shares single-threaded, Arc shares across threads.', 'Memory'),
  ('q-0099', 'rust-programming', 'Lifetime Annotations in Practice', 'Write a function that takes two string slices and returns the longer one, with correct lifetime annotations. Explain why the compiler cannot infer the relationship and how the chosen lifetime constrains the caller.', 'HARD', 'The returned reference must live as long as the shorter of the two inputs.', 'Lifetimes'),
  ('q-0100', 'rust-programming', 'Async Runtime and tokio', 'Explain Rust''s async/await model and why an external runtime like tokio is required. Describe how a Future works under the hood, the role of the executor and the reactor, and how spawning tasks differs from awaiting them.', 'HARD', 'Async functions return Futures that are inert until polled by an executor.', 'Concurrency'),
  ('q-0101', 'sql-databases', 'SQL JOIN Types', 'Explain the difference between INNER JOIN, LEFT JOIN, RIGHT JOIN, and FULL OUTER JOIN. Using two tables (users and orders) where some users have no orders and some orders have no matching user, describe the row set each join would produce.', 'EASY', 'Think about which side''s unmatched rows are preserved (or both, or neither).', 'JOINs'),
  ('q-0102', 'sql-databases', 'Database Normalization', 'Define First, Second, and Third Normal Form in your own words. Why do we normalize, and what trade-offs do we accept when we choose to denormalize for read performance?', 'EASY', 'Each NF removes a specific kind of redundancy: atomic values, then partial key dependencies, then transitive dependencies.', 'Normalization'),
  ('q-0103', 'sql-databases', 'WHERE vs HAVING Clause', 'What is the difference between WHERE and HAVING? Write a query that uses both clauses together on an orders table grouped by customer, filtering individual rows and then aggregated groups.', 'EASY', 'WHERE filters rows before grouping; HAVING filters groups after aggregation.', 'Query Syntax'),
  ('q-0104', 'sql-databases', 'Indexing Strategy', 'A table with 50M rows runs a slow query filtering by status and created_at. How would you decide what index to add, and how does column order in a composite index affect which queries can use it? Discuss the trade-offs of adding indexes on a write-heavy table.', 'MEDIUM', 'Consider the leftmost-prefix rule, selectivity of leading columns, and the write-amplification cost of maintaining indexes.', 'Indexing'),
  ('q-0105', 'sql-databases', 'ACID and Transactions', 'Explain each letter of ACID and give a concrete banking-transfer example that would violate each property if it were missing. Then explain how a database achieves isolation using locks and MVCC.', 'MEDIUM', 'Isolation can be implemented either pessimistically (locks) or optimistically (multi-version snapshots).', 'Transactions'),
  ('q-0106', 'sql-databases', 'Window Functions', 'Write a SQL query using window functions to rank employees within each department by salary, and to compute a running total of salaries ordered by hire date. Explain the difference between ROW_NUMBER, RANK, and DENSE_RANK.', 'MEDIUM', 'The OVER(...) clause partitions and orders rows; the ranking function decides tie-breaking behavior.', 'Window Functions'),
  ('q-0107', 'sql-databases', 'Connection Pooling', 'What problem does connection pooling solve, and what configuration parameters (pool size, max lifetime, idle timeout) matter most? Describe what happens to a connection when a transaction is left open and how the pool reclaims it.', 'MEDIUM', 'Each physical TCP connection is expensive to establish; pools reuse them but must guard against leaks and stale connections.', 'Connections'),
  ('q-0108', 'sql-databases', 'Reading EXPLAIN Output', 'Given an EXPLAIN ANALYZE plan showing a sequential scan on a large table, a nested loop join, and a high row estimate, walk through how you would diagnose and fix the performance problem. What does a high vs low cost number actually represent?', 'MEDIUM', 'Look at row estimates vs actual rows, scan types (seq vs index), and join strategies; mismatched estimates often point to stale statistics.', 'Query Optimization'),
  ('q-0109', 'sql-databases', 'Isolation Levels and Anomalies', 'Compare Read Uncommitted, Read Committed, Repeatable Read, and Serializable. For each level, give a concrete example of an anomaly (dirty read, non-repeatable read, phantom read, write skew) that can occur. Then explain why Snapshot Isolation prevents some but not all of these.', 'HARD', 'Each stronger level rules out anomalies the previous level allowed; Snapshot Isolation uses timestamps but still permits write skew under concurrent updates to disjoint rows.', 'Isolation'),
  ('q-0110', 'sql-databases', 'Composite Index Cardinality', 'You have a composite index on (country, city, zip). For each of these WHERE clauses, state whether the index is usable and which prefix is used: (a) country = ''US'', (b) city = ''NYC'', (c) country = ''US'' AND zip = ''10001'', (d) country = ''US'' AND city = ''NYC'' AND zip = ''10001''. Justify your answers and propose a covering index for a specific query.', 'HARD', 'Apply the leftmost-prefix rule strictly; range conditions break the prefix chain for subsequent columns.', 'Indexing'),
  ('q-0111', 'mongodb-nosql', 'SQL vs NoSQL Trade-offs', 'Compare relational databases with document databases like MongoDB. When would you choose one over the other, and what specific application characteristics (schema volatility, query patterns, consistency needs) drive that choice?', 'EASY', 'Think about schema flexibility, join-heavy vs aggregate-heavy workloads, and transactional requirements.', 'Data Modeling'),
  ('q-0112', 'mongodb-nosql', 'Embedding vs Referencing', 'Explain the difference between embedding documents and referencing them by ID in MongoDB. For a blog application with posts and comments, describe when you would embed comments inside the post document versus storing them in a separate collection.', 'EASY', 'Consider document growth (the 16MB limit), read patterns, and whether the child entity is queried independently.', 'Schema Design'),
  ('q-0113', 'mongodb-nosql', 'CRUD Operations in MongoDB', 'Write the MongoDB shell commands to insert a document, find all documents matching a field, update a single document, and delete by ID. Then explain the difference between updateOne and updateMany and what happens if the filter matches nothing.', 'EASY', 'Most CRUD operations take a filter document and a modifier document; upserts handle the missing-match case.', 'CRUD'),
  ('q-0114', 'mongodb-nosql', 'MongoDB Indexing', 'Explain how indexes work in MongoDB and how they differ from SQL indexes. When would you use a compound index, a multikey index, or a text index? Describe what an ESRN rule is and why index field order matters.', 'MEDIUM', 'The ESRN rule (Equality, Sort, Range, Notes) guides the optimal ordering of fields in a compound index.', 'Indexing'),
  ('q-0115', 'mongodb-nosql', 'Aggregation Pipeline', 'Design an aggregation pipeline that, given an orders collection, returns the top 5 customers by total spend in the last 30 days. Explain each stage ($match, $group, $sort, $limit) and how the pipeline''s ordering affects performance.', 'MEDIUM', 'Push $match as early as possible to reduce the number of documents flowing through later stages.', 'Aggregation'),
  ('q-0116', 'mongodb-nosql', 'Replica Sets', 'Explain how a MongoDB replica set works: the roles of primary and secondaries, how elections happen, and what happens during a primary failover. What consistency guarantees does reading from a secondary provide?', 'MEDIUM', 'Secondaries apply the primary''s oplog asynchronously; reads from secondaries may lag (eventual consistency).', 'Replication'),
  ('q-0117', 'mongodb-nosql', 'Schema Design Patterns', 'Describe at least three schema design patterns used in MongoDB (for example, the attribute pattern, the extended reference pattern, and the bucket pattern). For each, give a use case where it shines and a downside it introduces.', 'MEDIUM', 'Patterns are tricks for modeling specific shapes of data; each trades query simplicity against document size or duplication.', 'Schema Design'),
  ('q-0118', 'mongodb-nosql', 'CAP and Consistency Models', 'Explain the CAP theorem and where MongoDB sits on the consistency-availability spectrum for a given read preference and write concern. How do tunable consistency settings let an operator trade latency against durability?', 'MEDIUM', 'During a network partition you must choose between C and A; in normal operation, write concern and read preference tune per-operation trade-offs.', 'CAP'),
  ('q-0119', 'mongodb-nosql', 'Sharding Strategy', 'Design a sharding strategy for a multi-tenant SaaS application storing billions of events. Choose a shard key, justify why a monotonically increasing key (like a timestamp) would be problematic, and explain how hashed sharding and ranged sharding differ. How do you handle a hot shard?', 'HARD', 'A good shard key provides even write distribution and supports the most common query patterns without scatter-gather.', 'Sharding'),
  ('q-0120', 'mongodb-nosql', 'Write and Read Concern', 'Compare write concern levels w1, w:majority, and w:0, and read preferences primary, primaryPreferred, and nearest. For a payment-processing system, justify your choices and explain the failure modes (including rollback of uncommitted writes) that each combination protects against or exposes.', 'HARD', 'Durability and read-your-write consistency depend on how many replicas acknowledge writes and which replica you read from.', 'Consistency'),
  ('q-0121', 'redis-caching', 'Introduction to Redis', 'What is Redis and what problems does it solve that a relational database cannot? Describe three distinct use cases (caching, session store, rate limiting) and explain why Redis is a good fit for each.', 'EASY', 'Redis is an in-memory data-structure store; its single-threaded event loop gives predictable, sub-millisecond latency.', 'Fundamentals'),
  ('q-0122', 'redis-caching', 'Cache-Aside Pattern', 'Explain the cache-aside (lazy-loading) caching pattern. Walk through the read and write paths step by step, and compare it with read-through and write-through patterns in terms of consistency and complexity.', 'EASY', 'In cache-aside the application manages the cache explicitly; the database is the source of truth and the cache is populated on misses.', 'Caching Patterns'),
  ('q-0123', 'redis-caching', 'TTL and Eviction Policies', 'What is a TTL in Redis and what problem does it solve? Compare eviction policies like noeviction, allkeys-lru, allkeys-lfu, and volatile-lru, and explain when you would choose each.', 'EASY', 'Eviction policy decides which key to remove when maxmemory is reached; the choice depends on whether all keys are cacheable.', 'Eviction'),
  ('q-0124', 'redis-caching', 'Cache Stampede Prevention', 'Describe the cache stampede (thundering herd) problem that occurs when a popular cache key expires. Implement a solution using request coalescing or probabilistic early expiration, and explain the trade-offs of each.', 'MEDIUM', 'When the cache misses, many concurrent requests all hit the database at once; you need a way to let only one refill the cache.', 'Stampede'),
  ('q-0125', 'redis-caching', 'Redis Data Structures', 'Describe five Redis data structures (string, list, hash, set, sorted set) and give a realistic use case for each. For sorted sets, explain how the score is used and write a command to fetch the top 10 players in a leaderboard with their scores.', 'MEDIUM', 'Each data structure is backed by an optimized structure (ziplist, hashtable, skiplist) that influences time complexity.', 'Data Structures'),
  ('q-0126', 'redis-caching', 'Persistence RDB vs AOF', 'Compare Redis RDB snapshots and AOF (Append-Only File) persistence. What does each protect against, what are the durability and performance trade-offs, and how does the modern hybrid approach (RDB + AOF) combine the two?', 'MEDIUM', 'RDB is point-in-time and compact; AOF appends every write and can be replayed for finer-grained recovery.', 'Persistence'),
  ('q-0127', 'redis-caching', 'Cache Invalidation Strategies', 'Explain the four common cache invalidation strategies: TTL expiration, write-through invalidation, write-behind, and event-driven invalidation. For an e-commerce product catalog updated infrequently but read heavily, which strategy would you choose and why?', 'MEDIUM', 'The classic hardest problem in CS is naming and cache invalidation; pick the strategy whose consistency window matches your tolerance.', 'Invalidation'),
  ('q-0128', 'redis-caching', 'Distributed Locks with Redis', 'Implement a distributed lock using Redis SET NX with a TTL. Explain why a naive SETNX+EXPIRE two-step is unsafe, how Redlock attempts to improve safety, and what failure modes remain (e.g., GC pauses, clock drift).', 'MEDIUM', 'The lock must be acquired atomically with its expiration, and released only by the owner using a unique token and a Lua script.', 'Distributed Locks'),
  ('q-0129', 'redis-caching', 'Cache-Database Consistency', 'Design a caching layer in front of a PostgreSQL database such that reads never return stale data after a write. Compare the cache-aside update-then-invalidate approach with the write-through approach, and explain how a concurrent read between the DB write and cache invalidation can cause inconsistency. How would you prevent it?', 'HARD', 'The window between DB update and cache invalidation is the danger zone; delayed double deletion or versioned keys can close it.', 'Consistency'),
  ('q-0130', 'redis-caching', 'Cluster Mode and Slot Migration', 'Explain how Redis Cluster shards data across nodes using 16384 hash slots, how key tags affect slot assignment, and what happens during a slot migration (ASK vs MOVED redirections). Describe a resharding operation and its impact on availability.', 'HARD', 'CRC16 of the key (or key tag) modulo 16384 selects the slot; during migration the source and target nodes cooperate on a per-slot basis.', 'Clustering'),
  ('q-0131', 'system-design', 'Load Balancing Basics', 'What is a load balancer and what problems does it solve? Compare layer-4 and layer-7 load balancing, and describe at least three load-balancing algorithms (round-robin, least connections, consistent hashing) with their trade-offs.', 'EASY', 'Layer 4 operates on TCP/UDP; layer 7 inspects HTTP. The algorithm choice depends on session affinity and backend heterogeneity.', 'Load Balancing'),
  ('q-0132', 'system-design', 'Horizontal vs Vertical Scaling', 'Explain the difference between horizontal (scale-out) and vertical (scale-up) scaling. For each, give two advantages and two limitations, and describe a workload where horizontal scaling is clearly preferable and one where vertical scaling wins.', 'EASY', 'Vertical scaling hits a hardware ceiling but is simple; horizontal scaling needs stateless services and distributed coordination.', 'Scaling'),
  ('q-0133', 'system-design', 'Monolith vs Microservices', 'Compare a monolithic architecture with a microservices architecture. What forces push a team toward microservices, and what new operational complexities (deployment, observability, consistency) do they take on?', 'EASY', 'Microservices trade in-process calls for network calls; you gain independent deployment but pay with distributed-systems complexity.', 'Architecture'),
  ('q-0134', 'system-design', 'Design a URL Shortener', 'Design a URL shortening service (like bit.ly) handling 100M shortening requests and 10B redirects per month. Cover the URL generation strategy (hashing vs counter-based), storage choice, read scaling with caching, and how you would handle collisions and analytics.', 'MEDIUM', 'Reads vastly outnumber writes; the redirect path should be cached and the encoding strategy must be deterministic and short.', 'URL Shortener'),
  ('q-0135', 'system-design', 'Rate Limiting', 'Compare token bucket, leaky bucket, fixed window, and sliding window rate-limiting algorithms. For a public API with per-user and global limits, which would you choose and how would you implement distributed rate limiting across multiple servers?', 'MEDIUM', 'Algorithms trade memory and accuracy against burst tolerance; distributed enforcement needs a shared store like Redis.', 'Rate Limiting'),
  ('q-0136', 'system-design', 'Database Sharding', 'Explain horizontal sharding and compare range-based, hash-based, and directory-based sharding strategies. For a global user database, design a sharding scheme that supports both geographic locality and even distribution, and explain how you would handle resharding without downtime.', 'MEDIUM', 'Each strategy distributes data differently; resharding requires careful split-and-migrate with double writes during the transition.', 'Sharding'),
  ('q-0137', 'system-design', 'CDN and Edge Caching', 'How does a Content Delivery Network (CDN) reduce latency and origin load? Describe how cache keys, TTLs, and cache invalidation work at the edge, and explain how you would configure a CDN for both static assets and dynamic API responses.', 'MEDIUM', 'The CDN serves content from a PoP geographically close to the user; cacheability is controlled by headers and TTLs.', 'CDN'),
  ('q-0138', 'system-design', 'Message Queues and Async Processing', 'Explain the role of a message queue in decoupling producers from consumers. Compare point-to-point queues with pub/sub topics, and describe at least once, at most once, and exactly once delivery semantics with a concrete example where each matters.', 'MEDIUM', 'Delivery semantics depend on producer acknowledgments and consumer idempotency; exactly once usually requires deduplication on the consumer side.', 'Messaging'),
  ('q-0139', 'system-design', 'Design a Real-Time Chat System', 'Design a real-time chat application supporting 1:1 and group chats with delivery status and presence. Cover the connection layer (WebSocket vs long polling), message routing, fan-out for group messages, message ordering, and offline message storage.', 'HARD', 'Persistent connections need a sticky-session or fan-out layer; group messages require a write amplification strategy for offline users.', 'Chat System'),
  ('q-0140', 'system-design', 'Design a News Feed', 'Design the news feed for a social network with 500M users. Compare fan-out-on-write (push) vs fan-out-on-read (pull) models, justify your choice for celebrities vs regular users, and describe how you would rank, paginate, and cache the feed.', 'HARD', 'Fan-out-on-write precomputes feeds but explodes write cost for users with many followers; celebrities often need a hybrid approach.', 'News Feed'),
  ('q-0141', 'dsa-fundamentals', 'Arrays vs Linked Lists', 'Compare arrays and linked lists across access, insertion, deletion, and memory usage. For each operation, give the time complexity and explain the underlying reason. When would you choose one over the other?', 'EASY', 'Arrays are contiguous in memory enabling O(1) random access; linked lists trade that for O(1) insertion at a known node.', 'Data Structures'),
  ('q-0142', 'dsa-fundamentals', 'Big-O Notation', 'Explain Big-O, Big-Omega, and Big-Theta notation. For a function f(n) = 3n^2 + 5n + 7, give its tightest Big-O bound and justify why lower-order terms and constants are dropped. Why do we focus on worst-case rather than average-case analysis?', 'EASY', 'Asymptotic notation describes growth as n grows to infinity; lower-order terms become negligible.', 'Complexity'),
  ('q-0143', 'dsa-fundamentals', 'Stacks vs Queues', 'Explain the difference between a stack (LIFO) and a queue (FIFO). Give a real-world use case for each, and describe how you would implement a queue using two stacks with amortized O(1) enqueue and dequeue.', 'EASY', 'The two-stack queue uses one stack for input and one for output; moving elements only when the output stack is empty amortizes the cost.', 'Data Structures'),
  ('q-0144', 'dsa-fundamentals', 'Binary Search', 'Implement binary search on a sorted array and explain why its time complexity is O(log n). Then describe how to adapt binary search to find the first or last occurrence of a duplicate value, and how it can be applied to a rotated sorted array.', 'MEDIUM', 'Halve the search space each iteration; for first/last occurrence, decide which half to keep when the middle matches the target.', 'Searching'),
  ('q-0145', 'dsa-fundamentals', 'Hash Table Collision Handling', 'Explain what a hash collision is and compare chaining and open addressing (linear probing, quadratic probing, double hashing) as resolution strategies. Describe the load factor and how it affects performance, and explain when you would resize the table.', 'MEDIUM', 'Chaining stores colliding entries in a list at each bucket; open addressing finds another bucket deterministically.', 'Hash Tables'),
  ('q-0146', 'dsa-fundamentals', 'Tree Traversals', 'List the four common depth-first traversals of a binary tree (pre-order, in-order, post-order, and reverse in-order) and the breadth-first (level-order) traversal. Implement in-order traversal both recursively and iteratively using an explicit stack.', 'MEDIUM', 'The iterative version simulates the call stack: push left children to the bottom, then visit, then descend right.', 'Trees'),
  ('q-0147', 'dsa-fundamentals', 'BFS and DFS on Graphs', 'Compare Breadth-First Search and Depth-First Search on a graph in terms of data structure used, memory, and the kinds of problems each is suited for. Implement BFS to find the shortest path in an unweighted graph and explain why it produces the shortest path.', 'MEDIUM', 'BFS explores layer by layer using a queue; DFS dives deep using a stack (or recursion).', 'Graphs'),
  ('q-0148', 'dsa-fundamentals', 'Sorting Algorithms Comparison', 'Compare quicksort, mergesort, heapsort, and insertion sort on time complexity, space complexity, stability, and best/worst cases. When would you choose mergesort over quicksort, and why do many standard library sorts use a hybrid (like Timsort)?', 'MEDIUM', 'Quicksort is in-place but worst-case O(n^2); mergesort is stable with guaranteed O(n log n) but uses O(n) extra space.', 'Sorting'),
  ('q-0149', 'dsa-fundamentals', 'Dynamic Programming Approach', 'Explain the two main approaches to dynamic programming (top-down with memoization vs bottom-up with tabulation) using the classic longest common subsequence problem. Compare their space and time trade-offs and describe when you can apply space optimization.', 'HARD', 'Both approaches compute the same recurrence; tabulation can often drop unneeded previous rows to reduce space to O(min(m,n)).', 'Dynamic Programming'),
  ('q-0150', 'dsa-fundamentals', 'Implement an LRU Cache', 'Design and implement an LRU (Least Recently Used) cache supporting get and put operations in O(1) average time. Explain which data structures you combine and why, and describe how eviction works when capacity is exceeded.', 'HARD', 'Combine a hash map for O(1) lookup with a doubly linked list for O(1) reordering of recency.', 'Implementation'),
  ('q-0151', 'api-design', 'HTTP Methods and Idempotency', 'List the main HTTP verbs (GET, POST, PUT, PATCH, DELETE) and explain which are safe and which are idempotent. For each, give a RESTful example and explain what idempotency means in practice for a client retrying a failed request.', 'EASY', 'Safe methods do not modify state; idempotent methods produce the same effect no matter how many times they are called.', 'HTTP Methods'),
  ('q-0152', 'api-design', 'REST Principles', 'Explain the six constraints of REST (client-server, stateless, cacheable, uniform interface, layered, code-on-demand) in your own words. Which of these are mandatory and which are optional, and what does statelessness specifically require of the server?', 'EASY', 'Statelessness means every request carries all the context the server needs; no server-side session state between requests.', 'REST Principles'),
  ('q-0153', 'api-design', 'HTTP Status Codes', 'Group HTTP status codes into 1xx, 2xx, 3xx, 4xx, and 5xx categories and give two examples per group. Explain the difference between 401 Unauthorized and 403 Forbidden, and between 200 OK and 204 No Content, with a concrete REST endpoint example for each.', 'EASY', '4xx indicates a client error (auth, validation, not found); 5xx indicates a server error. 401 is about identity, 403 about permission.', 'Status Codes'),
  ('q-0154', 'api-design', 'API Versioning Strategies', 'Compare URI path versioning (/v1/users), query parameter (?version=1), header (Accept: application/vnd.api+json;version=1), and content negotiation. For a public API consumed by mobile and web clients, which would you choose and how would you deprecate an old version?', 'MEDIUM', 'Each strategy trades URL visibility against header complexity; deprecation needs a clear sunset policy and monitoring of usage.', 'Versioning'),
  ('q-0155', 'api-design', 'Pagination Patterns', 'Compare offset-based pagination (LIMIT/OFFSET), cursor-based pagination, and keyset pagination for an API returning a list of orders. Explain the performance and consistency problems of offset pagination on large datasets and how cursors solve them.', 'MEDIUM', 'OFFSET must scan and discard rows; cursors encode the last-seen position so the database can use an index seek.', 'Pagination'),
  ('q-0156', 'api-design', 'Authentication in REST APIs', 'Compare session-based auth, token-based auth (JWT), and OAuth 2.0 for a REST API. Describe the token flow for a JWT-issued access token and refresh token, and explain how you would revoke a JWT before its expiry.', 'MEDIUM', 'JWTs are self-contained and stateless, which makes revocation hard; revocation usually requires a server-side blocklist or short lifetimes plus refresh tokens.', 'Authentication'),
  ('q-0157', 'api-design', 'HATEOAS and Hypermedia', 'What is HATEOAS and how does it differ from a plain JSON REST API? Show what a hypermedia response for an order resource might look like with links to cancel, ship, and pay, and explain what benefit (and cost) this adds for API clients.', 'MEDIUM', 'HATEOAS embeds links in the response so clients can discover available transitions without out-of-band knowledge.', 'HATEOAS'),
  ('q-0158', 'api-design', 'API Rate Limiting and Throttling', 'Design a rate-limiting scheme for a public REST API. Describe how you would enforce per-user and per-IP limits, communicate limits to clients via response headers (Retry-After, X-RateLimit-Remaining), and handle authenticated vs anonymous traffic differently.', 'MEDIUM', 'Use a token bucket per identity in Redis; return 429 Too Many Requests with headers that tell the client when to retry.', 'Rate Limiting'),
  ('q-0159', 'api-design', 'Idempotency Keys for Payments', 'Design an idempotent POST /payments endpoint that safely retries on network failure. Explain how idempotency keys work, where you store them, how you handle a key that arrives with a different payload than the original, and how long you retain results.', 'HARD', 'The client sends a unique key; the server stores the key with its response and replays the stored response on retries within a TTL.', 'Idempotency'),
  ('q-0160', 'api-design', 'Designing a Complex Resource API', 'Design the REST API for a multi-tenant project management tool with projects, tasks, comments, and attachments. Cover resource naming, nested vs flat URLs (e.g. /projects/123/tasks vs /tasks?projectId=123), bulk operations, partial updates, and how you would model task assignment and transitions.', 'HARD', 'Choose URLs that match access patterns; deep nesting hurts when resources are accessed independently, flat URLs hurt when access is always scoped.', 'Resource Design'),
  ('q-0161', 'graphql', 'GraphQL vs REST', 'Compare GraphQL with REST. What problems does GraphQL solve that REST does not, and what new challenges (caching, rate limiting, security) does it introduce? Give an example of over-fetching and under-fetching in REST and how GraphQL addresses each.', 'EASY', 'GraphQL gives the client control over the shape of the response; REST gives the server control via fixed endpoints.', 'Fundamentals'),
  ('q-0162', 'graphql', 'Schema and Type System', 'Explain the GraphQL type system: scalar types, object types, enums, interfaces, unions, and input types. Write a small schema for a blog with Post and Author types, and explain when you would use an interface versus a union.', 'EASY', 'Interfaces share fields across types; unions let a field return one of several unrelated types.', 'Schema'),
  ('q-0163', 'graphql', 'Queries, Mutations, and Subscriptions', 'Explain the difference between Query, Mutation, and Subscription operations in GraphQL. Write an example of each for a chat application, and describe how subscriptions are typically transported over the network.', 'EASY', 'Queries read, mutations write and return a result, subscriptions hold a persistent connection (usually WebSocket) to stream server-pushed events.', 'Operations'),
  ('q-0164', 'graphql', 'The N+1 Problem and DataLoader', 'Explain the N+1 query problem in GraphQL resolvers and show how it arises when resolving a list of authors with their posts. Implement a solution using the DataLoader pattern and explain how request-scoped batching and caching work.', 'MEDIUM', 'DataLoader coalesces all resolve calls in a single tick into one batched call and memoizes results within the request.', 'N+1'),
  ('q-0165', 'graphql', 'Resolvers and the Info Object', 'Explain how a GraphQL resolver function receives (parent, args, context, info) and how the execution engine walks the query. Describe how the info object can be used for advanced features like lookahead and persisted queries.', 'MEDIUM', 'The info object exposes the field''s position in the query AST, letting resolvers inspect what subfields are requested.', 'Resolvers'),
  ('q-0166', 'graphql', 'Authentication and Authorization', 'Compare two approaches to authorization in GraphQL: at the resolver level (field-level checks) and at the business-logic layer. Describe a schema directive for @auth and how it could enforce role-based access declaratively across fields.', 'MEDIUM', 'Resolver-level auth is fine-grained but easy to forget; directives centralize policy but require tooling to enforce.', 'Authorization'),
  ('q-0167', 'graphql', 'Schema Federation', 'Explain Apollo Federation''s concepts of entity types, the @key directive, and the _entities root field. Describe how a gateway composes multiple subgraphs and how a field owned by one subgraph is resolved when a query starts in another.', 'MEDIUM', 'The gateway splits a query across subgraphs and joins results by entity reference (a type plus its key fields).', 'Federation'),
  ('q-0168', 'graphql', 'Error Handling in GraphQL', 'Compare the GraphQL approach of always returning HTTP 200 with an errors array to REST''s use of HTTP status codes. Describe how to structure partial-success responses, how to add extensions for machine-readable error codes, and how to handle errors thrown deep in a resolver chain.', 'MEDIUM', 'GraphQL returns data and errors side by side; structured error extensions let clients branch on error codes.', 'Errors'),
  ('q-0169', 'graphql', 'Caching Strategies in GraphQL', 'Explain why HTTP caching is harder for GraphQL than REST, and describe at least three strategies: persisted queries for CDN-friendly GETs, automatic persisted queries, server-side response caching with directives, and client-side normalized caches (Apollo/Relay). Compare their trade-offs.', 'HARD', 'GraphQL uses a single POST endpoint, defeating normal HTTP caching; persisted queries turn stable queries into cacheable GETs.', 'Caching'),
  ('q-0170', 'graphql', 'Designing a Federation Gateway', 'Design a federated GraphQL gateway for an e-commerce platform with separate teams owning products, reviews, inventory, and users. Address schema ownership conflicts, cross-service joins, error isolation when one subgraph is down, and how to version the gateway without breaking clients.', 'HARD', 'Treat subgraphs as bounded contexts; the gateway must compose contracts, isolate failures, and route entity fetches gracefully.', 'Federation'),
  ('q-0171', 'microservices-patterns', 'Introduction to Microservices', 'What are microservices and what core characteristics (independent deployability, bounded contexts, decentralized data) define them? Describe two benefits and two costs of adopting a microservices architecture compared to a well-modularized monolith.', 'EASY', 'The defining property is independent deployability with each service owning its own data store.', 'Fundamentals'),
  ('q-0172', 'microservices-patterns', 'Service Discovery', 'Explain why service discovery is needed in a dynamic microservices environment. Compare client-side discovery, server-side discovery, and the role of a service registry (like Consul or Eureka). Describe how health checks and deregistration work.', 'EASY', 'Service instances come and go; a registry tracks live instances and clients (or a load balancer) query it before each call.', 'Service Discovery'),
  ('q-0173', 'microservices-patterns', 'API Gateway Pattern', 'What role does an API gateway play in a microservices architecture? Describe the responsibilities it can take on (routing, authentication, rate limiting, request aggregation, response transformation) and the trade-offs of pushing too much logic into it.', 'EASY', 'The gateway is the single entry point; it centralizes cross-cutting concerns but can become a bottleneck or God service.', 'API Gateway'),
  ('q-0174', 'microservices-patterns', 'Saga Pattern for Distributed Transactions', 'Explain the Saga pattern as an alternative to distributed two-phase commit. Compare choreography-based and orchestration-based sagas using an order-processing flow (payment, inventory, shipping), and describe how compensating transactions roll back completed steps.', 'MEDIUM', 'A saga is a sequence of local transactions; if one fails, previously completed steps are undone by compensating actions.', 'Saga'),
  ('q-0175', 'microservices-patterns', 'Circuit Breaker Pattern', 'Explain the circuit breaker pattern and its three states (closed, open, half-open). Describe how it protects a service from cascading failures, how you choose thresholds and timeout values, and how it interacts with retries and bulkheads.', 'MEDIUM', 'When failures exceed a threshold the breaker opens and fails fast; after a cooldown it lets a probe request through to test recovery.', 'Resilience'),
  ('q-0176', 'microservices-patterns', 'CQRS Pattern', 'Explain Command Query Responsibility Segregation (CQRS). Describe how it differs from a single-model CRUD service, when it adds value (separate read vs write scaling, complex projections), and what eventual-consistency implications it introduces for the read side.', 'MEDIUM', 'CQRS splits the model into a write side (commands) and a read side (queries), often fed by events projecting the write model.', 'CQRS'),
  ('q-0177', 'microservices-patterns', 'Event Sourcing', 'Explain event sourcing, where the system stores a sequence of domain events rather than current state. Describe how the current state is reconstructed, the role of snapshots for performance, and the trade-offs against a state-based model.', 'MEDIUM', 'State is the projection of all past events; snapshots cache the projected state at a point in time to avoid replaying from epoch.', 'Event Sourcing'),
  ('q-0178', 'microservices-patterns', 'Database per Service', 'Explain the database-per-service pattern and why it is considered essential to microservice autonomy. Describe the challenges it creates for cross-service queries and joins, and at least two techniques (API composition, CQRS materialized views) for addressing them.', 'MEDIUM', 'Each service owns its data; shared reads are achieved by composing APIs or by projecting events into a shared read model.', 'Data Ownership'),
  ('q-0179', 'microservices-patterns', 'Distributed Transactions and Consistency', 'Compare 2PC (two-phase commit), Saga, and TCC (Try-Confirm-Cancel) for coordinating a transaction across three services. For an airline booking flow (reserve seat, charge card, issue ticket), which would you choose and why? Address failure handling, latency, and isolation.', 'HARD', '2PC gives ACID but blocks; Saga gives up isolation for availability; TCC reserves resources in a try phase before confirming.', 'Transactions'),
  ('q-0180', 'microservices-patterns', 'Strangler Fig Migration', 'Describe the strangler fig pattern for incrementally migrating a monolith to microservices. Walk through the steps (facade, extract service, route traffic, decommission), and explain how you would handle data migration, dual writes, and rollback if the new service misbehaves.', 'HARD', 'A routing facade lets you shift traffic incrementally to new services; dual writes during transition keep old and new data in sync.', 'Migration'),
  ('q-0181', 'aws-cloud', 'Core AWS Services Comparison', 'Explain the purpose of EC2, S3, and RDS and the type of workload each is designed for. For a web application with a stateless front end, a relational database, and user-uploaded images, sketch which services you would use and why.', 'EASY', 'EC2 is compute (VMs), S3 is object storage, RDS is managed relational databases.', 'Core Services'),
  ('q-0182', 'aws-cloud', 'IAM Fundamentals', 'Explain AWS IAM concepts: users, groups, roles, policies, and the principle of least privilege. Describe when you would use a role versus a user, how an EC2 instance obtains AWS credentials safely, and what an IAM trust policy does.', 'EASY', 'Roles are assumed by principals (including EC2 via instance profiles) and grant temporary credentials; users have long-term credentials.', 'IAM'),
  ('q-0183', 'aws-cloud', 'Regions and Availability Zones', 'Explain the relationship between AWS regions, Availability Zones (AZs), and edge locations. Describe how you would deploy a highly available application across AZs and what single-AZ failure you would still be vulnerable to.', 'EASY', 'Regions are geographic, AZs are isolated data centers within a region, edge locations serve CDN traffic.', 'Global Infrastructure'),
  ('q-0184', 'aws-cloud', 'Auto Scaling Strategies', 'Design an auto-scaling strategy for a stateless web tier behind an Application Load Balancer. Describe target-tracking vs step-scaling policies, warm-up times, cooldown periods, and how you would avoid thrashing caused by noisy metrics.', 'MEDIUM', 'Pick a metric that tracks load per instance (like CPU or request count per target) and use cooldowns to prevent oscillation.', 'Auto Scaling'),
  ('q-0185', 'aws-cloud', 'VPC and Networking', 'Design a VPC for a three-tier web application with public, private, and database subnets across two AZs. Explain the role of route tables, NAT gateways, internet gateways, security groups, and NACLs, and how each contributes to defense in depth.', 'MEDIUM', 'Public subnets reach the internet via an IGW; private subnets reach it via a NAT gateway; SGs are stateful and NACLs are stateless.', 'Networking'),
  ('q-0186', 'aws-cloud', 'Lambda and Serverless', 'Explain when you would choose AWS Lambda over EC2 or containers. Describe the Lambda execution model (cold starts, concurrency limits, execution role), and design a serverless image-processing pipeline triggered by S3 uploads.', 'MEDIUM', 'Lambda is event-driven and pay-per-invocation; cold starts and concurrency caps matter for latency-sensitive or bursty workloads.', 'Serverless'),
  ('q-0187', 'aws-cloud', 'S3 Storage Classes', 'List the main S3 storage classes (Standard, Intelligent-Tiering, Standard-IA, One-Zone-IA, Glacier Instant/Deep Archive) and describe when you would choose each. Explain how lifecycle rules automate transitions and what costs (retrieval, early-deletion) you must consider.', 'MEDIUM', 'Choose based on access frequency and retrieval latency tolerance; lifecycle rules move objects to cheaper tiers automatically.', 'Storage'),
  ('q-0188', 'aws-cloud', 'CloudFront and Edge Caching', 'Explain how CloudFront improves performance and reduces origin load. Describe cache behaviors, origin access control for private S3 content, TTLs and invalidations, and how you would serve both a Single Page App and a signed-URL video from the same distribution.', 'MEDIUM', 'CloudFront caches at edge PoPs; cache behaviors route URL patterns to origins, and signed URLs/cookies gate private content.', 'CDN'),
  ('q-0189', 'aws-cloud', 'Multi-Region Active-Active Architecture', 'Design a multi-region active-active architecture for a global SaaS application. Address data replication (DynamoDB Global Tables, Aurora Global Database, Route 53 latency routing), write conflict resolution, and the cost and consistency trade-offs versus an active-passive design.', 'HARD', 'Active-active needs conflict-tolerant replication and region-aware routing; last-writer-wins and CRDTs are common resolution strategies.', 'Multi-Region'),
  ('q-0190', 'aws-cloud', 'Disaster Recovery Strategies', 'Compare the four classic disaster recovery strategies (backup-restore, pilot light, warm standby, multi-site active-active) on RTO and RPO. For a regulated financial application, justify your choice and describe the testing and failover automation you would put in place.', 'HARD', 'RTO is how fast you recover, RPO is how much data you lose; lower targets cost more and require more automation.', 'Disaster Recovery'),
  ('q-0191', 'docker-k8s', 'What Is a Container', 'Explain what a container is at the operating-system level (namespaces, cgroups, union filesystem) and how it differs from a virtual machine. Describe two benefits and two limitations of containers compared to VMs.', 'EASY', 'Containers share the host kernel and isolate processes via namespaces; VMs virtualize hardware and run a full guest kernel.', 'Fundamentals'),
  ('q-0192', 'docker-k8s', 'Writing a Dockerfile', 'Write a multi-stage Dockerfile for a Node.js application that builds the bundle in a build stage and copies only the production artifacts into a slim runtime image. Explain each instruction and how multi-stage builds reduce final image size and attack surface.', 'EASY', 'Use FROM ... as builder, run the build, then FROM a slim image and COPY --from=builder only the artifacts you need.', 'Dockerfile'),
  ('q-0193', 'docker-k8s', 'Docker vs Virtual Machines', 'Compare Docker containers with traditional virtual machines across isolation, startup time, resource overhead, portability, and security. Give a concrete scenario where VMs are preferable to containers and explain why.', 'EASY', 'Containers are lighter and faster but share the kernel; VMs offer stronger isolation at the cost of overhead.', 'Fundamentals'),
  ('q-0194', 'docker-k8s', 'Image Layering and Build Caching', 'Explain how Docker images are composed of layers and how the build cache works. Given a Dockerfile where the COPY of source code appears before npm install, explain why the cache is invalidated on every code change and how you would reorder instructions to maximize cache hits.', 'MEDIUM', 'Each instruction creates a layer; a layer is rebuilt (and all subsequent layers) whenever its inputs change.', 'Images'),
  ('q-0195', 'docker-k8s', 'Pods and Deployments', 'Explain the relationship between Pods, ReplicaSets, and Deployments in Kubernetes. Describe how a Deployment performs a rolling update, how maxSurge and maxUnavailable tune the rollout, and how you would roll back to a previous revision.', 'MEDIUM', 'A Deployment manages a ReplicaSet which manages Pods; rolling updates swap old and new Pods while honoring surge/unavailable limits.', 'Workloads'),
  ('q-0196', 'docker-k8s', 'Services and Networking', 'Explain the Kubernetes Service resource and the types ClusterIP, NodePort, and LoadBalancer. Describe how kube-proxy and label selectors route traffic to Pods, and how an Ingress differs from a LoadBalancer Service.', 'MEDIUM', 'A Service provides a stable virtual IP and DNS name backed by label-selected Pods; Ingress operates at L7 and routes by host/path.', 'Networking'),
  ('q-0197', 'docker-k8s', 'Volumes and Persistent Storage', 'Compare emptyDir, hostPath, PersistentVolume, and PersistentVolumeClaim. Describe the access modes (ReadWriteOnce, ReadOnlyMany, ReadWriteMany) and when each is appropriate. For a stateful workload like a database, explain why you would use a StatefulSet with PVCs.', 'MEDIUM', 'emptyDir is ephemeral; PVCs bind to PVs from a storage class; ReadWriteMany requires a networked filesystem.', 'Storage'),
  ('q-0198', 'docker-k8s', 'Health Probes and Graceful Shutdown', 'Explain the difference between liveness, readiness, and startup probes and how each affects traffic and restarts. Describe how to implement graceful shutdown for a Pod serving in-flight HTTP requests, including preStop hooks and terminationGracePeriodSeconds.', 'MEDIUM', 'Liveness restarts unhealthy Pods; readiness removes them from the Service endpoints; preStop and SIGTERM handling drain in-flight work.', 'Probes'),
  ('q-0199', 'docker-k8s', 'StatefulSets vs Deployments', 'Explain why StatefulSets exist alongside Deployments. Describe how StatefulSets provide stable network identities, stable persistent storage, and ordered rollout and how these properties are essential for distributed data stores like Cassandra or Kafka.', 'HARD', 'StatefulSets give each Pod a stable name and ordinal, with its own PVC; Deployments treat Pods as interchangeable replicas.', 'Stateful Workloads'),
  ('q-0200', 'docker-k8s', 'Rolling Updates and Scaling Strategy', 'Design a zero-downtime scaling and rollout strategy for a high-traffic service. Address HPA with custom metrics, PDBs to protect quorum, canary releases via traffic splitting (e.g. Istio or Argo Rollouts), and how to detect and abort a bad rollout automatically.', 'HARD', 'Combine HPA for load-based scaling, PDBs to prevent over-eviction, and canary traffic shifting with automated metric-based promotion or rollback.', 'Rollouts'),
  ('q-0201', 'terraform-iac', 'Infrastructure as Code Fundamentals', 'Explain what Infrastructure as Code means and why it has become the standard way to provision cloud resources. Compare it to manually configuring infrastructure through a cloud console, highlighting the tradeoffs of each approach. What specific problems does IaC solve that click-ops cannot?', 'EASY', 'Think about reproducibility, auditability, and the gap between what is documented versus what actually exists.', 'IaC Basics'),
  ('q-0202', 'terraform-iac', 'Terraform vs CloudFormation', 'Compare Terraform with AWS CloudFormation across at least three dimensions such as provider support, state management, and language expressiveness. When would you recommend one over the other for a multi-cloud organization? Justify your reasoning with concrete scenarios.', 'EASY', 'Consider whether the team needs to manage resources across more than one cloud provider.', 'Tools'),
  ('q-0203', 'terraform-iac', 'Version Controlling Terraform Code', 'Why is it considered a best practice to store Terraform configuration in version control alongside application code? Describe how pull requests and code review fit into an IaC workflow. What risks arise when engineers apply changes that bypass this review process?', 'EASY', 'Think about who knows what the infrastructure looked like last week and who approves a risky change.', 'Workflow'),
  ('q-0204', 'terraform-iac', 'Terraform State Management', 'What is Terraform state and why is it critical? Compare local versus remote state backends, and explain the role of state locking. Describe what can go wrong if multiple engineers run terraform apply concurrently against the same state file.', 'MEDIUM', 'State is how Terraform remembers which real-world objects it created and maps them to config resources.', 'State'),
  ('q-0205', 'terraform-iac', 'Designing Terraform Modules', 'When should you extract Terraform configuration into a reusable module rather than keeping it inline? Describe the inputs, outputs, and versioning considerations for a well-designed module. What are signs that a module has grown too large or too tightly coupled?', 'MEDIUM', 'A good module has a clear contract of inputs and outputs and a single responsibility.', 'Modules'),
  ('q-0206', 'terraform-iac', 'Writing a Resource Block', 'Write a Terraform resource block that provisions an AWS S3 bucket with versioning enabled and a lifecycle rule that transitions objects to GLACIER after 90 days. Explain each attribute you include and how Terraform determines the desired state. How would you safely rename this resource later without destroying it?', 'MEDIUM', 'Use the moved block or terraform state mv to update the resource address without destroying it.', 'HCL'),
  ('q-0207', 'terraform-iac', 'Variables and tfvars Best Practices', 'Explain the difference between input variables, local values, and outputs in Terraform, and when to use each. Describe how you would manage different values for dev, staging, and production environments using tfvars files. What are the risks of storing secrets in variable files, and how should secrets be handled instead?', 'MEDIUM', 'Secrets should come from a vault, SSM, or environment-specific secure inputs, never plain tfvars files.', 'Variables'),
  ('q-0208', 'terraform-iac', 'Plan, Apply, and Destroy Lifecycle', 'Walk through the Terraform workflow from init to apply, explaining what each command does to state and infrastructure. What does the plan output tell you, and why is it unsafe to apply a plan that is stale? Describe how targeted applies and destroys can be both useful and dangerous.', 'MEDIUM', 'A saved plan is a snapshot of the world at plan time, and the real world may have moved on since.', 'Lifecycle'),
  ('q-0209', 'terraform-iac', 'Refactoring State with Moved Blocks', 'You need to reorganize a large Terraform configuration by splitting one module into two without recreating any existing cloud resources. Explain how you would use the moved block and terraform state mv commands to achieve this. What happens if you forget to update state and just edit the configuration files? Describe how to validate the refactor is safe before applying.', 'HARD', 'Without a moved block, Terraform sees a removed resource plus a new one and will destroy and recreate.', 'State'),
  ('q-0210', 'terraform-iac', 'Workspaces for Multiple Environments', 'Compare Terraform workspaces with separate directories (or separate state backends) as strategies for managing multiple environments. What are the hidden dangers of using workspaces for environments that should be strongly isolated, such as production versus dev? Design an approach that lets developers spin up ephemeral preview environments safely.', 'HARD', 'Workspaces share the same configuration and backend, which can blur isolation between environments.', 'Workspaces'),
  ('q-0211', 'ci-cd-devops', 'What is CI/CD', 'Define Continuous Integration, Continuous Delivery, and Continuous Deployment, and explain how they differ. Describe the value each practice provides to a development team and the prerequisites required to adopt them. What are common signs that a team is doing CI in name only?', 'EASY', 'Look at how often code integrates, whether builds are green, and whether deploys require manual steps.', 'Fundamentals'),
  ('q-0212', 'ci-cd-devops', 'Delivery vs Deployment', 'Explain the distinction between Continuous Delivery and Continuous Deployment, two terms that are frequently confused. What organizational and technical factors determine whether a team can move from delivery to deployment? Give an example of a scenario where Continuous Deployment would be inappropriate.', 'EASY', 'Delivery means every change is releasable; deployment means every change is automatically released.', 'Terminology'),
  ('q-0213', 'ci-cd-devops', 'Benefits of Small Commits', 'Why do CI/CD best practices encourage developers to commit small, frequent changes rather than large batched updates? Describe how commit size affects build time, code review, and rollback. What would you change about a workflow where engineers merge a week of work in a single pull request?', 'EASY', 'Small changes are easier to review, test, and bisect when something breaks.', 'Best Practices'),
  ('q-0214', 'ci-cd-devops', 'Writing a Pipeline YAML', 'Write a GitHub Actions (or GitLab CI) pipeline that runs lint, unit tests, and builds a Docker image on every push, then publishes the image only on merges to main. Explain how you would control which jobs run on which branches. How would you prevent secrets from leaking into pull requests from forks?', 'MEDIUM', 'Use branch filters and pull_request_target carefully, and never expose repo secrets to forked PRs.', 'Implementation'),
  ('q-0215', 'ci-cd-devops', 'Blue-Green vs Canary Deployments', 'Compare blue-green and canary deployment strategies, including their infrastructure requirements and rollback characteristics. When is each preferable, and what kinds of failures does each catch? Describe how feature flags can complement or replace these strategies.', 'MEDIUM', 'Blue-green swaps traffic between two full environments; canary shifts a small percentage gradually.', 'Deployment Strategies'),
  ('q-0216', 'ci-cd-devops', 'Secrets Management in Pipelines', 'Describe how secrets should be stored and injected into a CI/CD pipeline without being exposed in logs or artifacts. Explain the risks of committing secrets to source control even briefly, and how tools like vaults or OIDC trust reduce those risks. How would you detect and rotate a secret that was accidentally committed?', 'MEDIUM', 'Think about masked environment variables, OIDC for cloud auth, and secret-scanning tools like trufflehog.', 'Security'),
  ('q-0217', 'ci-cd-devops', 'Pipeline Caching Strategies', 'Explain how dependency caching and build artifact caching can reduce pipeline execution time. Describe the cache key strategies you would use for a Node.js project and a Python project, and what can go wrong if the cache key is too broad. How do you balance cache hit rate against stale dependency risks?', 'MEDIUM', 'Cache keys usually include a lockfile hash so the cache invalidates when dependencies change.', 'Optimization'),
  ('q-0218', 'ci-cd-devops', 'Structuring Test Stages', 'Design a multi-stage testing strategy for a CI pipeline, deciding which tests run on every commit versus only on nightly or pre-merge runs. Explain how you would partition unit, integration, and end-to-end tests to keep feedback fast. What metrics would you track to know the testing strategy is working?', 'MEDIUM', 'Fast feedback comes from running unit tests first; heavier tests run later or on a schedule.', 'Testing'),
  ('q-0219', 'ci-cd-devops', 'Designing a Multi-Stage Pipeline', 'Design a deployment pipeline for a microservice that must promote builds across dev, staging, and production environments with manual approvals at certain gates. Describe how artifacts, environment configuration, and rollback are handled at each stage. How would you ensure that what is tested in staging is exactly what ships to production?', 'HARD', 'Promote an immutable artifact through stages; only configuration should differ between environments.', 'Architecture'),
  ('q-0220', 'ci-cd-devops', 'Handling Flaky Tests', 'Flaky tests erode trust in CI and can cause engineers to ignore failures. Describe strategies for detecting, quarantining, and ultimately fixing flaky tests in a large suite. How would you balance the cost of rerunning tests against the risk of merging a broken change? Discuss the tradeoffs of automatic retries versus test quarantine.', 'HARD', 'Track per-test flakiness rates and quarantine offenders rather than silently retrying everything.', 'Reliability'),
  ('q-0221', 'linux-admin', 'What is a Linux Process', 'Explain what a process is in Linux and how it differs from a program. Describe the relationship between parent and child processes, including the role of init or systemd. What happens to child processes when their parent terminates?', 'EASY', 'Think about the difference between an executable file on disk and a running instance with a PID.', 'Processes'),
  ('q-0222', 'linux-admin', 'Linux File Permissions', 'Explain the Linux file permission model including the meaning of read, write, and execute bits for the owner, group, and others. Given a file with mode 750, describe exactly which users can do what. How would you recursively change ownership and permissions on a directory tree?', 'EASY', 'Three groups of three bits: owner, group, others; each rwx maps to 4, 2, 1 in octal.', 'Filesystem'),
  ('q-0223', 'linux-admin', 'Understanding the Shell', 'What is a shell in Linux, and how does it differ from the kernel? Compare popular shells like bash and zsh, and explain what happens when you type a command and press enter. How do environment variables propagate from a parent shell to a child process?', 'EASY', 'The shell parses your command, looks up the binary on PATH, and forks a child process to run it.', 'Shell'),
  ('q-0224', 'linux-admin', 'Writing a Bash Script', 'Write a bash script that takes a directory path as an argument, finds all files larger than 100 MB, and logs their paths with timestamps to a file. Include error handling for missing arguments and nonexistent directories. Explain how you would make this script robust against filenames containing spaces.', 'MEDIUM', 'Quote your variables, use find with -print0, and check argument count with $# at the top.', 'Scripting'),
  ('q-0225', 'linux-admin', 'Signals and the Kill Command', 'Explain what signals are in Linux and compare SIGTERM, SIGKILL, and SIGHUP. Describe how a well-behaved service should handle SIGTERM during a graceful shutdown. What is the difference between kill and kill -9, and why is the latter considered dangerous?', 'MEDIUM', 'SIGTERM can be caught and handled; SIGKILL cannot, so cleanup may not run.', 'Processes'),
  ('q-0226', 'linux-admin', 'Managing Services with systemd', 'Describe the role of systemd in modern Linux distributions and how it differs from traditional init scripts. Explain how you would create a unit file to run a service as a specific user with automatic restart on failure. What are the tradeoffs of Restart=always versus Restart=on-failure?', 'MEDIUM', 'A unit file declares ExecStart, User, Restart policy, and WantedBy target for the service.', 'systemd'),
  ('q-0227', 'linux-admin', 'File Descriptors and Pipes', 'Explain what file descriptors are and how the standard streams stdin, stdout, and stderr are represented. Describe how anonymous pipes connect processes, and contrast them with named pipes (FIFOs). Why does the order of redirections in a command matter, and what does 2>&1 actually do?', 'MEDIUM', 'File descriptors are integer handles; 0, 1, 2 are standard streams, and 2>&1 dupes stderr to stdout.', 'I/O'),
  ('q-0228', 'linux-admin', 'Text Processing with awk and sed', 'Given a CSV file with columns for username, login time, and IP address, write commands using awk and sed to extract users who logged in from more than three distinct IPs. Explain how these tools differ from grep and when you would reach for each. What are the limitations of using sed for structured data?', 'MEDIUM', 'awk is column-aware and can aggregate per key; sed is best for stream editing with regex.', 'Text Processing'),
  ('q-0229', 'linux-admin', 'Debugging a Slow Shell Script', 'A bash script that processes thousands of files takes several minutes to run, but the same logic in another language finishes in seconds. Explain why bash can be slow for this kind of workload and how you would profile it using tools like strace or bash -x. Describe two concrete optimizations or rewrites you would consider.', 'HARD', 'Bash forks a process per command in a loop; avoid command substitution in loops and batch with find or xargs.', 'Performance'),
  ('q-0230', 'linux-admin', 'DNS Resolution in Linux', 'Describe how name resolution works in Linux, including the roles of /etc/hosts, /etc/resolv.conf, and nsswitch.conf. Explain how systemd-resolved or NetworkManager can complicate troubleshooting, and how you would debug a hostname that resolves differently on two machines. What tools would you use to isolate DNS versus application-level failures?', 'HARD', 'nsswitch.conf controls resolution order; dig and getent reveal what each layer actually returns.', 'Networking'),
  ('q-0231', 'networking-tcp', 'The OSI Model Layers', 'Name and briefly describe the seven layers of the OSI model, giving a concrete example of a protocol at each layer. Explain why the OSI model is useful as a conceptual framework even though the TCP/IP model has fewer layers. What are common misconceptions people have about where protocols like HTTPS fit?', 'EASY', 'Remember Please Do Not Throw Sausage Pizza Away for Physical, Data Link, Network, Transport, Session, Presentation, Application.', 'OSI Model'),
  ('q-0232', 'networking-tcp', 'TCP vs UDP', 'Compare TCP and UDP in terms of reliability, ordering, connection state, and overhead. Give examples of applications that are well suited to each protocol and explain why. How does UDP achieve lower latency than TCP, and what tradeoff does that involve?', 'EASY', 'TCP guarantees delivery and order; UDP is fire-and-forget and used for DNS, video, and VoIP.', 'Protocols'),
  ('q-0233', 'networking-tcp', 'Subnet Masks and CIDR', 'Given the CIDR block 10.0.0.0/22, calculate how many usable host addresses it contains and write out the range. Explain how variable-length subnet masking allows more efficient use of address space than fixed classful addressing. Walk through how you would subnet a /24 to support four equal-sized networks.', 'EASY', 'A /22 gives 32 minus 22 host bits, minus 2 for network and broadcast addresses.', 'Subnetting'),
  ('q-0234', 'networking-tcp', 'TCP Three-Way Handshake', 'Describe the TCP three-way handshake and the purpose of sequence and acknowledgment numbers. Explain how this handshake establishes reliable, ordered communication between two endpoints. What vulnerabilities does this design introduce, and how do mechanisms like SYN cookies mitigate them?', 'MEDIUM', 'SYN, SYN-ACK, ACK establishes a connection and initial sequence numbers for both directions.', 'TCP'),
  ('q-0235', 'networking-tcp', 'DNS Resolution Process', 'Walk through what happens when a user types a URL into a browser, focusing on the DNS resolution steps from local cache to authoritative server. Explain the roles of recursive resolvers, root servers, TLD servers, and authoritative servers. How do DNS TTL values affect propagation and caching behavior?', 'MEDIUM', 'Resolution cascades from browser cache to OS cache to recursive resolver to root then TLD then authoritative.', 'DNS'),
  ('q-0236', 'networking-tcp', 'HTTPS and TLS Handshake', 'Explain the steps of a TLS handshake, including the role of certificates, key exchange, and cipher suite negotiation. Describe the difference between TLS 1.2 and TLS 1.3 handshakes and why the newer version is faster. What security best practices should you follow when configuring TLS for a public-facing service?', 'MEDIUM', 'TLS 1.3 collapses the handshake to one round trip and removes weaker cipher suites and key exchange modes.', 'TLS'),
  ('q-0237', 'networking-tcp', 'Network Debugging with tcpdump', 'Describe how you would use tcpdump and wireshark to diagnose a connection that intermittently hangs. Explain how to construct a filter to capture only traffic to a specific host and port, and what to look for in the captured packets. How would you distinguish a network-layer failure from an application-layer timeout?', 'MEDIUM', 'Use a BPF filter like host X and port Y, then look for retransmissions, RSTs, or missing ACKs.', 'Debugging'),
  ('q-0238', 'networking-tcp', 'NAT and Private IP Addresses', 'Explain what Network Address Translation is and why private IP address ranges defined in RFC 1918 cannot be routed on the public internet. Describe the difference between source NAT, destination NAT, and port address translation. What problems does NAT introduce for protocols like VoIP or peer-to-peer connections?', 'MEDIUM', 'NAT rewrites source or destination IPs in packets; PAT overloads many private IPs onto one public IP via ports.', 'NAT'),
  ('q-0239', 'networking-tcp', 'Designing Load Balancer Health Checks', 'Design a health check strategy for an L7 load balancer in front of a stateful web service. Describe what endpoint the health check should hit, how often, and what failure thresholds you would configure. How would you avoid cascading failures when a health check endpoint itself becomes overloaded?', 'HARD', 'A dedicated lightweight endpoint with conservative thresholds and a separate path from heavy queries.', 'Load Balancing'),
  ('q-0240', 'networking-tcp', 'TCP Congestion Control', 'Explain the purpose of TCP congestion control and describe the difference between slow start, congestion avoidance, fast retransmit, and fast recovery. Compare classic algorithms like Reno and CUBIC with newer approaches like BBR. How does the choice of congestion control algorithm affect performance on high-latency or lossy links?', 'HARD', 'BBR models bottleneck bandwidth and RTT instead of reacting to packet loss, which helps on lossy links.', 'TCP'),
  ('q-0241', 'operating-systems', 'Process vs Thread', 'Explain the difference between a process and a thread, including how memory and resources are shared between them. Describe the performance and isolation tradeoffs of using multiple processes versus multiple threads. When would you choose one model over the other for a concurrent server?', 'EASY', 'Processes have separate address spaces; threads within a process share memory and files.', 'Processes'),
  ('q-0242', 'operating-systems', 'What is Virtual Memory', 'Define virtual memory and explain how it gives each process the illusion of a private address space. Describe the role of page tables and the MMU in translating virtual addresses to physical ones. What are the benefits of virtual memory for security and memory utilization?', 'EASY', 'The MMU walks page tables to translate virtual to physical addresses and enforces permissions.', 'Memory'),
  ('q-0243', 'operating-systems', 'What is a System Call', 'Explain what a system call is and why user programs cannot directly access hardware or kernel memory. Describe what a context switch from user mode to kernel mode involves. Give three examples of common system calls and what privilege they require.', 'EASY', 'A syscall is a controlled trap into kernel mode that performs a privileged operation on behalf of the process.', 'Kernel'),
  ('q-0244', 'operating-systems', 'Context Switching Explained', 'Describe what happens during a context switch between two threads, including what state must be saved and restored. Explain why frequent context switching can hurt performance, and how this relates to the choice of thread pool size. What is the difference between a voluntary and involuntary context switch?', 'MEDIUM', 'Registers, program counter, and stack pointer must be saved and restored; too many threads cause thrashing.', 'Scheduling'),
  ('q-0245', 'operating-systems', 'Mutex vs Semaphore', 'Compare a mutex and a semaphore, and explain why a binary semaphore is not exactly the same as a mutex. Describe a concrete scenario where you would use a counting semaphore rather than a mutex. What is the concept of ownership, and why does it matter for mutexes?', 'MEDIUM', 'A mutex has an owner thread that must release it; a semaphore has no ownership and signals capacity.', 'Concurrency'),
  ('q-0246', 'operating-systems', 'Deadlock Prevention Strategies', 'Explain the four necessary conditions for deadlock and describe strategies to prevent each one. Compare deadlock prevention, avoidance, and detection in terms of overhead and applicability. How would you redesign a system that periodically deadlocks due to nested lock acquisition?', 'MEDIUM', 'The four conditions are mutual exclusion, hold and wait, no preemption, and circular wait.', 'Concurrency'),
  ('q-0247', 'operating-systems', 'Implementing the Producer-Consumer Pattern', 'Write pseudocode for a bounded buffer shared between one producer thread and one consumer thread, using a mutex and two semaphores. Explain how each synchronization primitive prevents race conditions or deadlocks. What changes if you scale this to multiple producers and consumers?', 'MEDIUM', 'Use one semaphore for empty slots, one for filled slots, and a mutex protecting the buffer itself.', 'Concurrency'),
  ('q-0248', 'operating-systems', 'Page Faults and the TLB', 'Explain what a page fault is and distinguish between minor and major page faults. Describe the role of the translation lookaside buffer (TLB) in virtual address translation and what a TLB miss costs. How does the operating system decide which page to evict when memory is full, and what is thrashing?', 'MEDIUM', 'A major page fault requires disk I/O; the TLB caches recent virtual-to-physical translations.', 'Memory'),
  ('q-0249', 'operating-systems', 'CPU Scheduling Algorithms', 'Compare FCFS, SJF, round-robin, and multilevel feedback queue scheduling algorithms, including their effect on average wait time and fairness. Describe the convoy effect and which scheduling algorithm suffers from it. How would you design a scheduler that balances throughput, latency, and fairness for a mixed interactive and batch workload?', 'HARD', 'The convoy effect is short jobs stuck behind one long job under FCFS; MLFQ adapts priorities over time.', 'Scheduling'),
  ('q-0250', 'operating-systems', 'Designing a File System Cache', 'Design a page cache for an operating system file layer, describing how you would handle read-ahead, write-back, and cache eviction. Explain the difference between write-through and write-back caching and the durability implications of each. How would you ensure consistency if the system crashes between a write to the cache and a flush to disk?', 'HARD', 'Write-back is fast but needs fsync and journaling to guarantee durability across crashes.', 'File Systems'),
  ('q-0251', 'distributed-systems', 'What is a Distributed System', 'Define a distributed system and explain the main motivations for distributing computation across multiple machines. Describe the key challenges that arise once a system spans more than one node, such as partial failure and concurrency. What does transparency mean in the context of distributed systems?', 'EASY', 'Think about scale, fault tolerance, and geographic distribution versus the cost of coordination.', 'Fundamentals'),
  ('q-0252', 'distributed-systems', 'The CAP Theorem', 'State the CAP theorem and explain what consistency, availability, and partition tolerance mean in this context. Why is partition tolerance not really optional in a distributed system, and what does that imply about the real tradeoff? Give an example of a system that favors CP and one that favors AP.', 'EASY', 'Partitions will happen, so the real choice is between consistency and availability during a partition.', 'CAP'),
  ('q-0253', 'distributed-systems', 'Synchronous vs Asynchronous Messaging', 'Compare synchronous request-response communication with asynchronous message passing between services. Describe the tradeoffs in terms of latency, coupling, and failure handling. When would you choose a message queue over direct HTTP calls, and what new complexities does it introduce?', 'EASY', 'Async decouples sender and receiver but adds a broker, ordering concerns, and operational complexity.', 'Messaging'),
  ('q-0254', 'distributed-systems', 'Quorum and Consistency', 'Explain how quorum-based replication works and how read and write quorums interact to guarantee consistency. Given a cluster of five nodes, describe quorum sizes that ensure strong consistency and what tradeoffs they impose on availability. What is a read repair, and when does it occur?', 'MEDIUM', 'Read and write quorums must overlap so any read sees the latest committed write.', 'Consistency'),
  ('q-0255', 'distributed-systems', 'Idempotency in Distributed Systems', 'Define idempotency and explain why it is critical for operations that may be retried across network failures. Describe how you would make a payment or charge endpoint idempotent using idempotency keys. What are the consequences of an endpoint that is not idempotent being called multiple times due to a timeout?', 'MEDIUM', 'An idempotency key lets the server recognize and dedupe a retried request and return the same result.', 'Reliability'),
  ('q-0256', 'distributed-systems', 'Retries and Exponential Backoff', 'Explain why naive retry loops can worsen outages and how exponential backoff with jitter mitigates this. Describe how you would configure retries for a service calling a flaky downstream API, including max attempts and timeout. What is the thundering herd problem, and how does jitter help?', 'MEDIUM', 'Jitter spreads out retries so all clients do not hammer the server at the same instant.', 'Reliability'),
  ('q-0257', 'distributed-systems', 'Designing a Distributed Counter', 'Design a counter that must support a high rate of increments from many nodes while remaining approximately accurate. Compare a naive approach of serializing all updates through one node with a sharded or CRDT-based approach. What consistency guarantees can you offer, and how would you detect divergence?', 'MEDIUM', 'Shard the counter per node and sum periodically, or use a CRDT like G-Counter that merges deterministically.', 'Design'),
  ('q-0258', 'distributed-systems', 'Leader Election Algorithms', 'Explain the purpose of leader election in a distributed system and compare algorithms such as bully, ring, and consensus-based (Raft) election. Describe what properties a good leader election protocol must have, such as termination and safety. What happens if two nodes both believe they are the leader?', 'MEDIUM', 'Election must terminate with at most one leader even when messages are delayed or nodes restart.', 'Coordination'),
  ('q-0259', 'distributed-systems', 'Designing a Distributed Lock Service', 'Design a distributed lock service that must be correct under network partitions and node failures. Explain how you would use a consensus algorithm like Raft or Paxos to back the lock, and how fencing tokens prevent stale lock holders from corrupting state. Why are TTL-based locks alone insufficient for correctness?', 'HARD', 'A consensus-backed lease plus a monotonically increasing fencing token prevents stale writers.', 'Coordination'),
  ('q-0260', 'distributed-systems', 'Split-Brain and Quorum', 'Explain what split-brain is in a distributed system and how quorum-based mechanisms prevent it. Describe a scenario where a network partition could still cause inconsistency despite a quorum system. How do systems like ZooKeeper or etcd handle the case where a permanent partition leaves a minority partition unable to make progress?', 'HARD', 'Quorum requires a majority to make progress; the minority side must stop accepting writes.', 'Fault Tolerance'),
  ('q-0261', 'cybersecurity-basics', 'The CIA Triad', 'Define the CIA triad of confidentiality, integrity, and availability, and give a concrete security control that supports each goal. Explain how these goals can sometimes conflict, for example when adding encryption that slows down a service. Which leg of the triad is most important for a hospital''s electronic health records, and why?', 'EASY', 'Encryption protects confidentiality, hashing and signatures protect integrity, backups protect availability.', 'Fundamentals'),
  ('q-0262', 'cybersecurity-basics', 'Symmetric vs Asymmetric Encryption', 'Compare symmetric and asymmetric encryption, including their performance characteristics and key distribution challenges. Explain how protocols like TLS combine both types of encryption, and why. What is the role of a public key infrastructure (PKI) in making asymmetric encryption practical at scale?', 'EASY', 'TLS uses asymmetric encryption to exchange a symmetric session key, then uses symmetric for speed.', 'Cryptography'),
  ('q-0263', 'cybersecurity-basics', 'Passwords and Multi-Factor Authentication', 'Explain what multi-factor authentication is and the three categories of factors it draws from. Describe why passwords alone are insufficient and how MFA mitigates credential theft. What are the tradeoffs between usability and security when rolling out MFA to a large user base?', 'EASY', 'Factors are something you know, something you have, and something you are.', 'Authentication'),
  ('q-0264', 'cybersecurity-basics', 'XSS vs CSRF Attacks', 'Compare cross-site scripting (XSS) and cross-site request forgery (CSRF), describing how each attack works and what an attacker can achieve. Explain why CSRF tokens do not protect against stored XSS, and how same-site cookies relate to CSRF defense. How would you test that a web application is resilient to both attack types?', 'MEDIUM', 'XSS runs attacker script in the victim''s browser; CSRF tricks a logged-in browser into making a request.', 'Web Security'),
  ('q-0265', 'cybersecurity-basics', 'SQL Injection and Parameterized Queries', 'Explain how a SQL injection vulnerability arises and what an attacker can do once they exploit one. Describe why string concatenation of user input into queries is dangerous and how parameterized queries or prepared statements prevent injection. How would you identify and remediate SQL injection in a legacy codebase?', 'MEDIUM', 'Parameterized queries separate SQL structure from data so input cannot change the parsed statement.', 'Web Security'),
  ('q-0266', 'cybersecurity-basics', 'Hashing and Salting Passwords', 'Explain why passwords should never be stored in plaintext, and why a plain hash is still insufficient. Describe how a salt and a slow key derivation function like bcrypt or argon2 work together to resist offline attacks. Write pseudocode showing how to verify a stored password against a user-supplied value.', 'MEDIUM', 'A unique per-user salt defeats rainbow tables; a slow KDF makes brute force expensive.', 'Cryptography'),
  ('q-0267', 'cybersecurity-basics', 'Principle of Least Privilege', 'Explain the principle of least privilege and how it applies to both human users and service accounts. Describe how role-based access control (RBAC) helps enforce this principle at scale, and the risk of over-privileged roles. How would you audit an existing system to identify and reduce unnecessary privileges?', 'MEDIUM', 'Grant the minimum permissions needed for a task and remove them when no longer required.', 'Access Control'),
  ('q-0268', 'cybersecurity-basics', 'TLS Certificates and PKI', 'Describe the lifecycle of a TLS certificate from issuance to renewal and revocation, including the role of certificate authorities. Explain what a certificate chain is and why intermediate certificates matter. What happens if a private key is compromised, and how does certificate revocation or short-lived certificates address this?', 'MEDIUM', 'Revocation via CRL or OCSP is unreliable; short-lived certificates reduce the blast radius of compromise.', 'Cryptography'),
  ('q-0269', 'cybersecurity-basics', 'Defense in Depth Strategy', 'Design a defense in depth strategy for a web application that handles sensitive financial data. Describe the layers you would put in place from network perimeter to application logic to data encryption, and what each layer defends against. How do you avoid creating a false sense of security when layers overlap?', 'HARD', 'Layered controls include WAF, network segmentation, authn/authz, input validation, encryption, and monitoring.', 'Defense'),
  ('q-0270', 'cybersecurity-basics', 'Zero Trust Architecture', 'Explain the core principles of zero trust architecture and how it differs from a traditional perimeter-based security model. Describe how identity-based access, micro-segmentation, and continuous verification work together in a zero trust design. What are the practical challenges of migrating a legacy corporate network to zero trust?', 'HARD', 'Never trust, always verify: every request is authenticated and authorized regardless of network location.', 'Architecture'),
  ('q-0271', 'git-version-control', 'Git vs Centralized VCS', 'Explain the difference between a distributed version control system like Git and a centralized system like SVN. Describe what each developer has locally in a DVCS that they would not have in a centralized model. What are the advantages and disadvantages of distributed workflows?', 'EASY', 'In a DVCS every clone has the full history, so most operations are local and offline.', 'Fundamentals'),
  ('q-0272', 'git-version-control', 'Basic Git Workflow', 'Describe the basic Git workflow of cloning a repository, creating a branch, making commits, and opening a pull request. Write the sequence of commands you would use to accomplish this. Explain what each command does to the local repository and the staging area.', 'EASY', 'The flow is git clone, git checkout -b, git add, git commit, git push, then open a PR.', 'Workflow'),
  ('q-0273', 'git-version-control', 'Understanding Git Branches', 'Explain what a branch is in Git and why branching is considered cheap compared to other version control systems. Describe what happens internally when you create and switch branches. How does Git know which branch you are currently on?', 'EASY', 'A branch is just a movable pointer to a commit; HEAD points to the current branch.', 'Branching'),
  ('q-0274', 'git-version-control', 'Resolving Merge Conflicts', 'Describe what causes a merge conflict and walk through the steps to resolve one manually. Explain how to inspect the conflicted file, choose which changes to keep, and finalize the merge. What best practices reduce the frequency and severity of merge conflicts in a team?', 'MEDIUM', 'Conflicts occur when the same lines are changed on two branches; edit, stage, and commit to finish.', 'Merging'),
  ('q-0275', 'git-version-control', 'Rebase vs Merge', 'Compare git merge and git rebase, including the effect each has on commit history. Describe when you would choose one over the other, and the risks of rebasing commits that have already been pushed. What is the golden rule of rebasing, and why does it matter?', 'MEDIUM', 'Rebase rewrites commit history; never rebase commits that others have already pulled.', 'Merging'),
  ('q-0276', 'git-version-control', 'Writing Good Commit Messages', 'Explain why well-structured commit messages matter for code review and for future debugging. Describe a commit message convention you would recommend, including subject line length, body, and tense. How would you split a large change into a series of well-organized commits?', 'MEDIUM', 'Use an imperative subject under 50 chars and a body explaining why, not just what.', 'Best Practices'),
  ('q-0277', 'git-version-control', 'Git Internal Object Model', 'Describe Git''s internal object model including blobs, trees, commits, and tags. Explain how a commit points to a tree and how Git uses content-addressable hashing to deduplicate objects. What does it mean that a SHA is both a name and a checksum of content?', 'MEDIUM', 'Objects are stored by SHA-1 of their content, so identical content is stored once and tampering is detectable.', 'Internals'),
  ('q-0278', 'git-version-control', 'Cherry-Picking Commits in Git', 'Explain what git cherry-pick does and when you would use it instead of a merge. Describe a scenario where cherry-picking a hotfix from main back to a release branch is appropriate. What conflicts or duplication issues can arise, and how would you handle them?', 'MEDIUM', 'Cherry-pick applies a single commit''s diff onto your branch; duplicated commit IDs can cause future conflicts.', 'Workflow'),
  ('q-0279', 'git-version-control', 'Recovering Lost Commits with Reflog', 'A teammate accidentally ran git reset --hard and lost several commits that were never pushed. Explain how you would use git reflog and git fsck to recover those commits. Describe the difference between unreachable and dangling objects, and how long reflog entries are retained. What steps would you take to make the recovery permanent?', 'HARD', 'The reflog records where HEAD and branch tips have been, so you can reset back to the lost commit SHA.', 'Recovery'),
  ('q-0280', 'git-version-control', 'Git Workflow Strategies', 'Compare trunk-based development, GitFlow, and GitHub Flow as branching strategies for a team. Describe the strengths and weaknesses of each, and which type of team or release cadence each suits best. How does the choice of branching strategy interact with continuous integration and release management?', 'HARD', 'Trunk-based favors continuous deployment; GitFlow suits versioned releases; GitHub Flow is a middle ground.', 'Strategy'),
  ('q-0281', 'react-native-mobile', 'React Native vs Native Development', 'Compare React Native with fully native iOS and Android development in terms of performance, developer experience, and access to platform APIs. Explain how React Native renders to native components rather than running in a webview. When might a team choose native development over React Native?', 'EASY', 'React Native maps React components to actual native views via a bridge, not a webview.', 'Fundamentals'),
  ('q-0282', 'react-native-mobile', 'What is a React Component', 'Explain what a component is in React and the difference between functional and class components. Describe how props and state allow components to be reusable and dynamic. What is the virtual DOM and how does it relate to component rendering?', 'EASY', 'A component is a function of props and state that returns a description of the UI to render.', 'Components'),
  ('q-0283', 'react-native-mobile', 'Writing a Functional Component', 'Write a React Native functional component that displays a counter with increment and decrement buttons using the useState hook. Explain what the hook returns and how re-renders are triggered when state changes. How would you make this component accessible to screen readers?', 'EASY', 'useState returns the current value and a setter; calling the setter schedules a re-render.', 'Components'),
  ('q-0284', 'react-native-mobile', 'The React Native Bridge', 'Explain how the React Native bridge allows JavaScript code to communicate with native platform modules. Describe the performance limitations of the legacy bridge and how the new architecture (Fabric and TurboModules) addresses them. What kinds of operations are most affected by bridge overhead?', 'MEDIUM', 'The legacy bridge serializes messages between JS and native threads; the new arch does synchronous calls.', 'Architecture'),
  ('q-0285', 'react-native-mobile', 'useState and useEffect Hooks', 'Explain what the useEffect hook does and how its dependency array controls when effects run. Write a component that fetches data from an API when mounted and cleans up a subscription on unmount. What common mistakes with useEffect lead to infinite re-render loops or stale closures?', 'MEDIUM', 'An empty dependency array runs once on mount; missing deps cause stale closures and wrong values.', 'Hooks'),
  ('q-0286', 'react-native-mobile', 'Mobile Navigation Patterns', 'Compare stack, tab, and drawer navigation patterns in mobile apps and when each is appropriate. Describe how you would structure navigation in React Navigation for an app with authentication flows and a logged-in area. What best practices keep navigation state manageable as an app grows?', 'MEDIUM', 'Use a root switch navigator for auth versus app, then stack or tab navigators inside each area.', 'Navigation'),
  ('q-0287', 'react-native-mobile', 'FlatList and List Performance', 'Explain why rendering a long list with ScrollView can hurt performance in React Native, and how FlatList addresses this. Describe the key props that control item virtualization, windowing, and rendering. What mistakes can still cause a FlatList to feel janky even when virtualization is enabled?', 'MEDIUM', 'FlatList only renders items in view; avoid expensive renderItem functions and keys derived from indices.', 'Performance'),
  ('q-0288', 'react-native-mobile', 'Fetching Data from an API', 'Write a React Native hook that fetches data from a REST API, tracks loading and error state, and supports cancellation when the component unmounts. Explain how you would handle retries and display friendly error messages. What libraries or patterns would you use to standardize this across a large app?', 'MEDIUM', 'Use an AbortController to cancel in-flight fetches on unmount and a state machine for loading/error/data.', 'Networking'),
  ('q-0289', 'react-native-mobile', 'Diagnosing Memory Leaks', 'Describe the common causes of memory leaks in React Native apps, including uncleared timers, subscriptions, and lingering references in closures. Explain how you would use tools like Flipper or the Chrome profiler to identify a leak. How does the new architecture change the way leaks manifest?', 'HARD', 'Leak sources include setInterval, event listeners, and refs held after unmount; capture heap snapshots to find them.', 'Performance'),
  ('q-0290', 'react-native-mobile', 'Offline-First App Architecture', 'Design an offline-first architecture for a React Native app that must keep working without network connectivity and sync changes when back online. Describe how you would persist data locally, queue mutations, and resolve conflicts during sync. What are the tradeoffs between optimistic UI and strict consistency in this design?', 'HARD', 'Local store plus a mutation queue and conflict resolution strategy; optimistic UI is faster but riskier.', 'Architecture'),
  ('q-0291', 'machine-learning', 'Supervised vs Unsupervised Learning', 'Explain the difference between supervised and unsupervised learning, and give a concrete example of each. Describe what a label is in supervised learning and why unsupervised methods are useful when labels are unavailable. Where does reinforcement learning fit relative to these two categories?', 'EASY', 'Supervised learns from labeled input-output pairs; unsupervised finds structure in unlabeled data.', 'Fundamentals'),
  ('q-0292', 'machine-learning', 'What is Overfitting', 'Define overfitting and explain how an overfit model behaves differently on training data versus unseen data. Describe two symptoms that suggest a model is overfitting. What simple techniques can reduce overfitting, and how would you detect it during model development?', 'EASY', 'High training accuracy but poor validation accuracy is the classic overfitting signal.', 'Modeling'),
  ('q-0293', 'machine-learning', 'Training vs Inference', 'Explain the difference between the training phase and the inference phase of a machine learning model. Describe how computational and latency requirements differ between the two phases. Why might a model be deployed using a different framework or precision than it was trained with?', 'EASY', 'Training is throughput-bound and uses backprop; inference is latency-bound and often uses lower precision.', 'Lifecycle'),
  ('q-0294', 'machine-learning', 'The Bias-Variance Tradeoff', 'Explain the bias-variance tradeoff and how it relates to underfitting and overfitting. Describe how you would diagnose whether a model suffers from high bias or high variance using learning curves. What strategies reduce each type of error, and why can improving one worsen the other?', 'MEDIUM', 'High bias underfits and needs a more complex model; high variance overfits and needs regularization or more data.', 'Modeling'),
  ('q-0295', 'machine-learning', 'Train, Test, and Cross-Validation', 'Explain why you cannot evaluate a model on the same data it was trained on, and how train, validation, and test splits address this. Compare k-fold cross-validation with a single holdout set, including when each is preferable. What is data leakage, and how can it silently inflate your evaluation metrics?', 'MEDIUM', 'k-fold uses each sample for both training and validation across folds; leakage is when test info reaches training.', 'Evaluation'),
  ('q-0296', 'machine-learning', 'Feature Scaling Best Practices', 'Explain why feature scaling matters for algorithms like k-nearest neighbors and gradient descent, and why tree-based models are less sensitive to it. Compare standardization and normalization, and describe when to fit a scaler on training data only. What happens if you fit the scaler on the entire dataset including test data?', 'MEDIUM', 'Fit the scaler on training data only and apply the same transform to test data to avoid leakage.', 'Preprocessing'),
  ('q-0297', 'machine-learning', 'How Gradient Descent Works', 'Explain how gradient descent updates model parameters to minimize a loss function, including the role of the learning rate. Describe what can go wrong if the learning rate is too high or too low, and how momentum or adaptive optimizers like Adam help. What is the difference between batch, mini-batch, and stochastic gradient descent?', 'MEDIUM', 'Parameters move opposite the gradient scaled by the learning rate; too large diverges, too small stalls.', 'Optimization'),
  ('q-0298', 'machine-learning', 'Metrics from a Confusion Matrix', 'Given a binary classification confusion matrix, define accuracy, precision, recall, and F1 score, and explain when each is the right metric to optimize. Describe why accuracy can be misleading on imbalanced datasets, and how precision and recall trade off against each other. When would you prefer the F1 score over either precision or recall alone?', 'MEDIUM', 'On imbalanced data, accuracy hides the minority class; F1 balances precision and recall in one number.', 'Evaluation'),
  ('q-0299', 'machine-learning', 'L1 and L2 Regularization', 'Compare L1 (lasso) and L2 (ridge) regularization in terms of the penalty they impose and the effect on model weights. Explain why L1 can drive weights exactly to zero, producing sparse models, while L2 generally does not. How would you choose between the two, and what role does the regularization hyperparameter play?', 'HARD', 'L1 penalty is absolute value, whose gradient drives weights to zero; L2 is squared and shrinks but keeps weights.', 'Modeling'),
  ('q-0300', 'machine-learning', 'Designing an End-to-End ML Pipeline', 'Design an end-to-end ML pipeline that takes raw data, trains a model, evaluates it, and deploys it to production with monitoring. Describe how you would handle data validation, model versioning, and detection of data drift after deployment. What strategies would you use to roll back a deployed model that begins degrading?', 'HARD', 'Pipeline stages: ingest, validate, train, evaluate, register, deploy, monitor, and roll back on drift.', 'MLOps'),
  ('q-0301', 'deep-learning', 'Purpose of Activation Functions', 'What is the purpose of an activation function in a neural network, and why would a network without nonlinear activations behave like a single linear layer? Name two common activation functions and a downside of each.', 'EASY', 'Consider what happens when you compose multiple linear transformations without any nonlinearity between them.', 'Activations'),
  ('q-0302', 'deep-learning', 'MSE Versus Cross-Entropy Loss', 'Explain the difference between mean squared error and cross-entropy loss. When would you use cross-entropy for a regression problem, if ever? Why is cross-entropy preferred for classification?', 'EASY', 'Think about the gradient behavior and the probabilistic interpretation of softmax outputs.', 'Loss Functions'),
  ('q-0303', 'deep-learning', 'Gradient Descent Variants', 'Describe vanilla gradient descent, stochastic gradient descent (SGD), and mini-batch gradient descent. What are the tradeoffs in terms of convergence speed, variance, and computational cost per update?', 'EASY', 'Consider the batch size and how it affects the noise in gradient estimates.', 'Optimization'),
  ('q-0304', 'deep-learning', 'Two-Layer Backpropagation Derivation', 'Derive the backpropagation update for the weights of a two-layer network with sigmoid activations and binary cross-entropy loss. Show how the chain rule produces the gradient with respect to the first layer''s weights.', 'MEDIUM', 'Start from the loss and apply the chain rule layer by layer, keeping track of local derivatives.', 'Training'),
  ('q-0305', 'deep-learning', 'Batch Normalization Mechanics', 'Explain how batch normalization works and why it helps deep networks train faster. What changes during training versus inference, and why must the network track running statistics?', 'MEDIUM', 'Think about internal covariate shift and the difference between batch statistics and population statistics.', 'Regularization'),
  ('q-0306', 'deep-learning', 'Dropout Regularization Mechanism', 'How does dropout regularize a neural network? Explain the difference between training and inference behavior, and why we scale activations during training rather than inference.', 'MEDIUM', 'Consider dropout as approximate ensemble averaging over thinned subnetworks.', 'Regularization'),
  ('q-0307', 'deep-learning', 'Adam Optimizer Equations', 'Explain how the Adam optimizer combines momentum and adaptive learning rates. Write the update equations and discuss the role of bias correction in the first few iterations.', 'MEDIUM', 'Adam stores exponential moving averages of gradients and squared gradients; bias correction corrects for their initialization at zero.', 'Optimization'),
  ('q-0308', 'deep-learning', 'Residual Connections and Gradients', 'Why do vanishing gradients occur in deep networks, and how do residual connections (ResNets) mitigate the problem? Derive why the gradient of a residual block has an additive identity term.', 'MEDIUM', 'Write the forward pass as y = F(x) + x and differentiate with respect to x.', 'Architectures'),
  ('q-0309', 'deep-learning', 'Scaled Dot-Product Attention Derivation', 'Derive scaled dot-product attention from first principles, explaining why the dot products are divided by sqrt(d_k). Show how multi-head attention extends single-head attention, and discuss the tradeoff in choosing the number of heads.', 'HARD', 'The scaling factor controls the variance of the dot product of random unit vectors as d_k grows.', 'Transformers'),
  ('q-0310', 'deep-learning', 'Deep Learning Generalization', 'Modern deep networks have far more parameters than training examples, yet they generalize well. Discuss the roles of implicit regularization (SGD, architecture), overparameterization, and the double descent phenomenon. How does this challenge classical bias-variance tradeoff intuition?', 'HARD', 'Consider the trajectory SGD takes in the loss landscape and the model class selected by the optimizer, not just the hypothesis space.', 'Generalization'),
  ('q-0311', 'nlp-fundamentals', 'Tokenization Methods Compared', 'What is the difference between word-level, character-level, and subword tokenization (e.g., BPE)? Why have subword methods become the default for modern NLP models?', 'EASY', 'Think about out-of-vocabulary words and vocabulary size tradeoffs.', 'Tokenization'),
  ('q-0312', 'nlp-fundamentals', 'Word2Vec Skip-Gram Objective', 'Explain what word2vec learns and why the skip-gram objective produces useful representations. Why does the embedding for king minus man plus woman approximate queen?', 'EASY', 'The skip-gram model learns embeddings such that words appearing in similar contexts end up close in the embedding space.', 'Embeddings'),
  ('q-0313', 'nlp-fundamentals', 'TF-IDF Weighting Derivation', 'Derive the TF-IDF weighting scheme from first principles. Why is the logarithm used in the IDF term, and why is TF-IDF often superior to raw term counts for document retrieval?', 'EASY', 'IDF downweights terms that appear in many documents; the log dampens the effect for extremely common terms.', 'Retrieval'),
  ('q-0314', 'nlp-fundamentals', 'LSTM Versus Vanilla RNN', 'Explain why an LSTM mitigates the vanishing gradient problem that plagues vanilla RNNs. Describe the role of the cell state and the gating mechanisms, and why the cell state enables long-range dependencies.', 'MEDIUM', 'The cell state update is nearly additive, so gradients flow through it with little multiplicative attenuation.', 'Sequence Models'),
  ('q-0315', 'nlp-fundamentals', 'Self-Attention and Positional Encoding', 'Write the equations for self-attention in a Transformer, and explain how positional encodings compensate for the absence of recurrence. Why are sinusoidal positional encodings used, and what alternative does BERT use?', 'MEDIUM', 'Self-attention is permutation-invariant without positional information; the encodings inject order.', 'Transformers'),
  ('q-0316', 'nlp-fundamentals', 'BERT Pretraining Objectives', 'Describe the two pretraining objectives used in BERT (masked language modeling and next sentence prediction). Why is masking used instead of a left-to-right language modeling objective, and what downstream tasks benefit from NSP-style pretraining?', 'MEDIUM', 'Masking lets the model condition on both left and right context, unlike autoregressive objectives.', 'Language Models'),
  ('q-0317', 'nlp-fundamentals', 'BLEU Score Computation', 'Explain how the BLEU score is computed for machine translation evaluation. Why does BLEU use n-gram precision rather than recall, and what role does the brevity penalty play?', 'MEDIUM', 'Pure precision rewards short translations; the brevity penalty prevents gaming the metric.', 'Evaluation'),
  ('q-0318', 'nlp-fundamentals', 'Sequence to Sequence Translation', 'Walk through the encoder-decoder architecture for machine translation. Why does attention improve performance over plain encoder-decoder, and how does the decoder attend to the encoder outputs?', 'MEDIUM', 'A fixed-length context vector is a bottleneck; attention lets the decoder dynamically focus on relevant encoder states.', 'Sequence Models'),
  ('q-0319', 'nlp-fundamentals', 'Transformer Complexity Analysis', 'The Transformer paper replaced recurrence with attention. Derive the time and space complexity of self-attention versus an RNN, and explain why attention scales poorly with sequence length. How do techniques like sparse attention or FlashAttention address this?', 'HARD', 'Self-attention is O(n^2) in sequence length due to the full attention matrix; RNNs are O(n) in time but sequential.', 'Transformers'),
  ('q-0320', 'nlp-fundamentals', 'Masked Language Model Design', 'Design a masked language modeling training procedure that handles multi-token spans and avoids the pretrain-finetune discrepancy. Compare the original BERT masking scheme with SpanBERT and T5''s sentinel-token approach, discussing the tradeoffs.', 'HARD', 'Consider what the model sees at inference time and whether the masking distribution matches that.', 'Language Models'),
  ('q-0321', 'computer-vision', 'Convolution Operations Explained', 'Explain how a 2D convolution works and the difference between a kernel, stride, and padding. Why are convolutions preferred over fully connected layers for image inputs?', 'EASY', 'Convolutions exploit spatial locality and weight sharing, drastically reducing parameters.', 'CNNs'),
  ('q-0322', 'computer-vision', 'Pooling Layers Purpose', 'What is the purpose of pooling layers in a CNN, and what is the difference between max pooling and average pooling? Why has pooling been partially replaced by strided convolutions in modern architectures?', 'EASY', 'Pooling provides translation invariance and downsampling; strided convolutions learn the downsampling.', 'CNNs'),
  ('q-0323', 'computer-vision', 'Image Classification Pipeline', 'Walk through the steps of building an image classifier from raw images: preprocessing, augmentation, model selection, and evaluation. Why is data augmentation particularly important for vision tasks?', 'EASY', 'Augmentation injects invariances the model should have and reduces overfitting when data is scarce.', 'Classification'),
  ('q-0324', 'computer-vision', 'ResNet Architecture Analysis', 'Explain the architecture of ResNet and the role of residual connections. Why do residual connections allow training of much deeper networks, and how does the bottleneck block reduce computation?', 'MEDIUM', 'Residual connections give gradients an identity shortcut; bottlenecks use 1x1 convs to reduce and restore channel dimension.', 'Architectures'),
  ('q-0325', 'computer-vision', 'One-Stage Versus Two-Stage Detectors', 'Compare one-stage detectors (e.g., YOLO) and two-stage detectors (e.g., Faster R-CNN). Explain the role of region proposals and anchor boxes, and discuss the speed-accuracy tradeoff.', 'MEDIUM', 'Two-stage methods first propose regions then classify them; one-stage methods predict boxes and classes directly.', 'Detection'),
  ('q-0326', 'computer-vision', 'IoU and Non-Maximum Suppression', 'Derive the Intersection over Union (IoU) metric and explain how non-maximum suppression (NMS) is used to filter duplicate detections. What is the IoU threshold typically used, and how does it affect precision and recall?', 'MEDIUM', 'NMS keeps the highest-scoring box and suppresses overlapping boxes above an IoU threshold.', 'Detection'),
  ('q-0327', 'computer-vision', 'Data Augmentation for Vision', 'Explain how techniques like random cropping, flipping, color jittering, and CutMix improve CNN generalization. Which of these are appropriate for medical imaging and which are not, and why?', 'MEDIUM', 'Augmentations should preserve the label semantics; flipping a digit 6 into a 9 changes the label.', 'Augmentation'),
  ('q-0328', 'computer-vision', 'Transfer Learning with CNNs', 'Describe how to perform transfer learning with a pretrained CNN backbone for a new classification task. What is the difference between feature extraction (frozen backbone) and fine-tuning, and when would you choose each?', 'MEDIUM', 'Freezing works when the target domain is close to the source; fine-tuning helps when domains differ.', 'Transfer Learning'),
  ('q-0329', 'computer-vision', 'Normalization in Vision Models', 'Discuss the failure modes of batch normalization in vision models, especially with small batch sizes and at inference. Compare with group normalization and layer normalization, deriving why group norm is batch-size independent.', 'HARD', 'Batch norm uses batch statistics that become noisy with small batches; group norm computes statistics across channels within each sample.', 'Normalization'),
  ('q-0330', 'computer-vision', 'Vision Transformer Architecture', 'Explain how a Vision Transformer (ViT) processes an image: patch embedding, positional encoding, and transformer encoder. Derive the number of tokens and parameter count as a function of patch size, image size, and model dimension. Why do ViTs require more data than CNNs to perform well?', 'HARD', 'ViTs lack the inductive biases of CNNs (locality, translation invariance), so they need more data to learn them.', 'Architectures'),
  ('q-0331', 'data-engineering', 'ETL Versus ELT Comparison', 'Explain the difference between ETL (Extract, Transform, Load) and ELT (Extract, Load, Transform). What modern developments made ELT more viable, and when is each approach preferred?', 'EASY', 'ELT leverages the compute power of modern cloud data warehouses; ETL transforms before loading.', 'ETL'),
  ('q-0332', 'data-engineering', 'Warehouse Versus Data Lake', 'Compare a data warehouse and a data lake in terms of data structure, schema, and use cases. What is a data lakehouse, and what problem does it solve?', 'EASY', 'Warehouses store structured, schema-on-write data; lakes store raw data with schema-on-read.', 'Storage'),
  ('q-0333', 'data-engineering', 'Star Schema Design', 'Describe a star schema for a retail sales fact table. What are fact tables and dimension tables, and why is denormalization acceptable in dimensional modeling?', 'EASY', 'Fact tables hold measures and foreign keys; dimension tables hold descriptive attributes. Joins are minimized.', 'Data Modeling'),
  ('q-0334', 'data-engineering', 'Slowly Changing Dimensions', 'Explain Type 1, Type 2, and Type 3 slowly changing dimension (SCD) techniques. When would you use Type 2, and what columns are required to track historical changes?', 'MEDIUM', 'Type 2 preserves history by adding new rows with effective dates and a current flag.', 'Data Modeling'),
  ('q-0335', 'data-engineering', 'Idempotent Pipeline Design', 'What does it mean for a data pipeline to be idempotent, and why is idempotency important for ETL? Describe two techniques to make a pipeline idempotent when loading into a data warehouse.', 'MEDIUM', 'Idempotent pipelines produce the same result no matter how many times they run; think about upserts and partition overwrites.', 'Pipelines'),
  ('q-0336', 'data-engineering', 'Change Data Capture Patterns', 'Explain Change Data Capture (CDC) and compare log-based CDC to query-based CDC. What are the tradeoffs in terms of source system impact, latency, and data completeness?', 'MEDIUM', 'Log-based CDC reads the database transaction log with minimal source load; query-based CDC polls tables.', 'CDC'),
  ('q-0337', 'data-engineering', 'Airflow DAG Orchestration', 'Describe how you would orchestrate a daily ETL pipeline in Apache Airflow. Explain DAGs, tasks, operators, sensors, and how to handle task retries and failures without producing duplicate data.', 'MEDIUM', 'Use sensors for upstream dependencies and idempotent operators; configure retries with exponential backoff.', 'Orchestration'),
  ('q-0338', 'data-engineering', 'Data Quality Framework', 'Design a data quality framework for a pipeline that ingests user events. What dimensions of data quality (completeness, accuracy, consistency, timeliness) would you monitor, and which checks would you implement as blocking versus non-blocking?', 'MEDIUM', 'Blocking checks fail the pipeline; non-blocking checks alert but allow data through. Consider schema, nullability, and referential integrity.', 'Data Quality'),
  ('q-0339', 'data-engineering', 'Exactly-Once Processing Semantics', 'Explain the difference between at-most-once, at-least-once, and exactly-once delivery semantics in data pipelines. Why is true end-to-end exactly-once difficult, and how do systems like Kafka and Spark Structured Streaming achieve it via transactions and idempotent writes?', 'HARD', 'Exactly-once usually means effectively-once: at-least-once delivery plus idempotent or transactional sinks.', 'Reliability'),
  ('q-0340', 'data-engineering', 'Schema Evolution in Lakes', 'Discuss schema evolution in a data lake using formats like Avro, Parquet, and ORC. How does each handle adding, renaming, and deleting columns, and what is the role of a schema registry in a streaming architecture?', 'HARD', 'Columnar formats struggle with column deletion; Avro handles schema evolution via reader/writer schemas. A registry enforces compatibility rules.', 'Schema Management'),
  ('q-0341', 'big-data-spark', 'RDD Versus DataFrame', 'Explain the difference between RDDs and DataFrames in Apache Spark. Why are DataFrames generally faster, and what is the role of the Catalyst optimizer?', 'EASY', 'DataFrames have a schema that enables query optimization; RDDs are opaque to the optimizer.', 'Abstractions'),
  ('q-0342', 'big-data-spark', 'Spark Application Architecture', 'Describe the components of a Spark application: driver, executors, cluster manager, and tasks. How does a Spark job decompose into stages and tasks?', 'EASY', 'A job is divided into stages by shuffle boundaries; each stage contains tasks that run in parallel on partitions.', 'Architecture'),
  ('q-0343', 'big-data-spark', 'Lazy Evaluation in Spark', 'What is lazy evaluation in Spark, and why is it important? Give an example of a transformation and an action, and explain when computation is actually triggered.', 'EASY', 'Transformations build a logical plan; actions (like collect or count) trigger execution.', 'Execution Model'),
  ('q-0344', 'big-data-spark', 'Shuffles and Partitioning', 'Explain what a shuffle is in Spark and why it is expensive. How do partitioning strategies like hash partitioning and range partitioning affect subsequent operations, and what is partition pruning?', 'MEDIUM', 'A shuffle redistributes data across the network; choosing the right partitioner avoids shuffles in downstream joins.', 'Performance'),
  ('q-0345', 'big-data-spark', 'Broadcast Joins in Spark', 'Explain broadcast (map-side) joins in Spark. When should you use one, how does Spark decide to broadcast automatically, and what configuration controls the broadcast threshold?', 'MEDIUM', 'Broadcast joins avoid shuffling the small table by sending a copy to every executor.', 'Joins'),
  ('q-0346', 'big-data-spark', 'Window Functions in Spark', 'Write a Spark SQL query using window functions to compute a running sum and a row number per partition. Explain how window functions differ from groupBy aggregations and when they are necessary.', 'MEDIUM', 'Window functions retain row granularity while adding aggregate results; groupBy collapses rows.', 'SQL'),
  ('q-0347', 'big-data-spark', 'Caching and Persistence', 'Explain when and how to cache or persist a DataFrame in Spark. What storage levels are available, and what are the tradeoffs between MEMORY_ONLY, MEMORY_AND_DISK, and serialized formats?', 'MEDIUM', 'Cache reused intermediate results, but beware of memory pressure and the distinction between cache() and persist().', 'Performance'),
  ('q-0348', 'big-data-spark', 'Data Skew and Salting', 'What is data skew, and how does it manifest as a slow stage in Spark? Describe the salting technique for handling skew in a join, and explain why adding a random prefix helps.', 'MEDIUM', 'Skew means one partition is much larger; salting splits the large key into multiple keys to balance load.', 'Performance'),
  ('q-0349', 'big-data-spark', 'Catalyst Optimizer Phases', 'Explain the phases of Spark''s Catalyst optimizer: analysis, logical optimization, physical planning, and code generation. How does adaptive query execution (AQE) improve on static planning, and what runtime statistics does it leverage?', 'HARD', 'AQE re-optimizes at shuffle boundaries using actual partition sizes and join statistics.', 'Optimization'),
  ('q-0350', 'big-data-spark', 'Structured Streaming Concepts', 'Describe Spark Structured Streaming''s event-time processing, watermarks, and output modes. How does a watermark bound state size, and what is the difference between append, update, and complete output modes for a windowed aggregation?', 'HARD', 'Watermarks define how late data can arrive; append mode requires the watermark to finalize windows before emitting results.', 'Streaming'),
  ('q-0351', 'kafka-streaming', 'Kafka Core Components', 'Describe the core components of Kafka: producers, consumers, brokers, topics, and partitions. How does partitioning enable parallelism and scalability?', 'EASY', 'Each partition is an append-only log; consumers in a group split partitions to read in parallel.', 'Architecture'),
  ('q-0352', 'kafka-streaming', 'Consumer Groups Mechanics', 'Explain how Kafka consumer groups work. What happens when you add or remove a consumer from a group, and how does Kafka ensure each partition is consumed by exactly one consumer within a group?', 'EASY', 'A rebalance reassigns partitions across consumers in the group.', 'Consumers'),
  ('q-0353', 'kafka-streaming', 'Offset Management Strategies', 'What is a Kafka offset, and how do consumers track their position? Compare automatic offset commits with manual commits, and discuss the tradeoffs in terms of at-least-once versus at-most-once semantics.', 'EASY', 'Auto-commit can lead to duplicates if processing fails after commit; manual commit gives finer control.', 'Offsets'),
  ('q-0354', 'kafka-streaming', 'Replication and ISR', 'Explain Kafka''s replication mechanism. What is an ISR (in-sync replica), and how do the acks=0, acks=1, and acks=all settings affect durability and throughput?', 'MEDIUM', 'acks=all waits for the leader and all ISR members; acks=0 waits for none.', 'Reliability'),
  ('q-0355', 'kafka-streaming', 'Exactly-Once in Kafka', 'Explain how Kafka achieves exactly-once semantics with idempotent producers and transactions. What is a transactional ID, and how does the consumer isolation.level setting affect what a consumer reads?', 'MEDIUM', 'Idempotent producers use a PID and sequence numbers; transactions span multiple partitions atomically.', 'Semantics'),
  ('q-0356', 'kafka-streaming', 'Stream Processing Time Concepts', 'Compare event time, ingestion time, and processing time in stream processing. Why is event-time processing preferred, and how do watermarks handle late-arriving data?', 'MEDIUM', 'Event time reflects when the event occurred; watermarks signal the system''s confidence that no earlier events will arrive.', 'Time'),
  ('q-0357', 'kafka-streaming', 'Windowing in Streams', 'Describe tumbling, hopping, and session windows in stream processing. Give a use case for each, and explain how a session window differs when using event time versus processing time.', 'MEDIUM', 'Tumbling windows are non-overlapping and contiguous; session windows are dynamically sized by inactivity gaps.', 'Windowing'),
  ('q-0358', 'kafka-streaming', 'Kafka Streams Versus Flink', 'Compare Kafka Streams and Apache Flink for stream processing. What are the tradeoffs in terms of deployment model, state management, exactly-once guarantees, and event-time handling?', 'MEDIUM', 'Kafka Streams runs as a library in your application; Flink is a separate cluster with a richer windowing and time model.', 'Frameworks'),
  ('q-0359', 'kafka-streaming', 'Partition Rebalancing Protocol', 'Explain the Kafka consumer rebalance protocol (pre-0.10 vs cooperative incremental rebalancing). What problems does rebalancing cause (stop-the-world), and how do static membership and cooperative rebalancing mitigate them?', 'HARD', 'Eager rebalancing revokes all partitions during a rebalance; cooperative rebalancing only revokes partitions that must move.', 'Consumers'),
  ('q-0360', 'kafka-streaming', 'Stateful Stream Processing Design', 'Design a stateful stream processing job that computes per-user session counts over a Kafka topic with strict exactly-once guarantees. Describe how you would manage state, handle failures, and ensure the output is consistent even after a restart.', 'HARD', 'Use a state store backed by a changelog topic, with transactions for the output and idempotent producers.', 'State'),
  ('q-0361', 'data-visualization', 'Chart Selection Strategy', 'Given a dataset with a categorical variable and a continuous variable, how do you decide between a bar chart, a box plot, and a violin plot? What does each reveal about the distribution, and when would a bar chart be misleading?', 'EASY', 'Bar charts show summary statistics; box and violin plots reveal the distribution shape.', 'Chart Selection'),
  ('q-0362', 'data-visualization', 'Color Palette Types', 'Explain the difference between sequential, diverging, and categorical color palettes. Give an example of each and describe a situation where using the wrong palette would mislead the viewer.', 'EASY', 'Diverging palettes have a meaningful midpoint; using a rainbow palette for unordered categories is a common mistake.', 'Design'),
  ('q-0363', 'data-visualization', 'Common Chart Pitfalls', 'List three common pitfalls in data visualization (e.g., truncated y-axes, 3D pie charts, dual-axis charts) and explain why each is problematic. How would you redesign each to communicate more honestly?', 'EASY', 'Consider what the chart implies about magnitude, proportion, or correlation that is not supported by the data.', 'Design'),
  ('q-0364', 'data-visualization', 'Grammar of Graphics', 'Explain the Grammar of Graphics (as implemented in ggplot2). Describe the roles of data, aesthetics, geometries, scales, facets, and themes, and how they compose into a plot.', 'MEDIUM', 'Think of a plot as a layered composition where each component adds a visual encoding.', 'Theory'),
  ('q-0365', 'data-visualization', 'Interactive Dashboard Design', 'Describe how you would build an interactive dashboard for exploring sales data. What tools would you use (e.g., Plotly, Dash, Tableau), and what interactions (filtering, brushing, drill-down) would you expose to the user?', 'MEDIUM', 'Match the interaction to the analytical question; avoid adding interactivity that does not serve a purpose.', 'Interactivity'),
  ('q-0366', 'data-visualization', 'Effective Dashboard Principles', 'What principles make a dashboard effective for executive consumption versus analyst exploration? Discuss layout, information density, color use, and the role of summary KPIs versus detailed charts.', 'MEDIUM', 'Executives need quick answers and exceptions highlighted; analysts need flexibility to drill down.', 'Dashboards'),
  ('q-0367', 'data-visualization', 'Visual Perception Hierarchy', 'Discuss which visual encodings are most accurately perceived by humans, based on Cleveland and McGill''s hierarchy. Why is length (bar chart) more accurate than area (bubble chart) or color intensity, and what does this imply for chart choice?', 'MEDIUM', 'Position on a common scale is most accurate; area and color are less precise.', 'Perception'),
  ('q-0368', 'data-visualization', 'Data Storytelling Approach', 'Explain how to construct a narrative with data visualization, from setting context to delivering a recommendation. What role does annotation play, and how do you decide which details to include versus omit?', 'MEDIUM', 'A good data story has a clear message; annotation directs the viewer''s attention to the key insight.', 'Storytelling'),
  ('q-0369', 'data-visualization', 'Multivariate Data Visualization', 'Compare approaches for visualizing multivariate data: scatterplot matrices, parallel coordinates, and dimensionality-reduction plots (PCA, t-SNE, UMAP). What are the tradeoffs in terms of information loss, interpretability, and scalability to many dimensions?', 'HARD', 'Parallel coordinates preserve all dimensions but scale poorly; PCA, t-SNE, and UMAP trade fidelity for a 2D view.', 'Multivariate'),
  ('q-0370', 'data-visualization', 'Misleading Visualizations Analysis', 'Analyze how visualizations can be intentionally or unintentionally misleading: truncated axes, area scaling, cherry-picked time ranges, and confounded variables. Propose a checklist a data team could use to review charts before publication.', 'HARD', 'Check whether the visual encoding matches the quantitative claim and whether omitted context changes the interpretation.', 'Ethics'),
  ('q-0371', 'calculus', 'Derivative Definition and Application', 'State the formal definition of the derivative as a limit. Use it to derive the derivative of f(x) = x^2, showing each step. What does the derivative represent geometrically?', 'EASY', 'Apply the limit definition and expand (x+h)^2, then cancel terms before taking the limit.', 'Derivatives'),
  ('q-0372', 'calculus', 'Chain Rule Application', 'State the chain rule and use it to differentiate f(x) = sin(x^2). Explain when the chain rule is necessary and why the inner function''s derivative enters as a multiplicative factor.', 'EASY', 'Identify the outer and inner functions; multiply the outer derivative (evaluated at the inner) by the inner derivative.', 'Derivatives'),
  ('q-0373', 'calculus', 'Fundamental Theorem of Calculus', 'State the Fundamental Theorem of Calculus (both parts). Explain the relationship between differentiation and integration, and why integration can be viewed as anti-differentiation up to a constant.', 'EASY', 'Part 1 says the derivative of an integral function is the integrand; Part 2 connects definite integrals to antiderivatives.', 'Integrals'),
  ('q-0374', 'calculus', 'Profit Optimization with Derivatives', 'A company''s profit is modeled as P(x) = -2x^3 + 30x^2 - 100x + 500 where x is units produced. Find the production level that maximizes profit, and verify it is a maximum using the second derivative test.', 'MEDIUM', 'Set the first derivative to zero, solve for critical points, then check the sign of the second derivative at each.', 'Optimization'),
  ('q-0375', 'calculus', 'Taylor Series Derivation', 'Derive the Taylor series expansion of e^x around x=0, and write the general form of the Taylor series for a function f about a point a. When does the series converge to the function, and what is the remainder term?', 'MEDIUM', 'Repeatedly differentiate e^x and evaluate at 0; the remainder can be expressed via Lagrange''s form.', 'Series'),
  ('q-0376', 'calculus', 'Multivariable Chain Rule Derivation', 'Derive the multivariable chain rule for z = f(x(t), y(t)). Show how the total derivative dz/dt relates the partial derivatives of f to the derivatives of x and y, and give a physical interpretation.', 'MEDIUM', 'The total derivative is a sum of partial derivatives weighted by the rates of change of the intermediate variables.', 'Multivariable'),
  ('q-0377', 'calculus', 'Gradient and Directional Derivative', 'Define the gradient of a scalar field and the directional derivative. Show that the gradient points in the direction of steepest ascent and that the directional derivative is the dot product of the gradient with the unit direction vector.', 'MEDIUM', 'Use the Cauchy-Schwarz inequality to show the directional derivative is maximized when the direction aligns with the gradient.', 'Multivariable'),
  ('q-0378', 'calculus', 'Integration by Parts Application', 'Derive integration by parts from the product rule, and use it to compute the integral of x*e^x dx. Explain how to choose which factor to call u and which to call dv (LIATE rule).', 'MEDIUM', 'Start from d(uv) = u dv + v du and integrate both sides; the LIATE rule suggests picking u as the function that differentiates most simply.', 'Integrals'),
  ('q-0379', 'calculus', 'Lagrange Multipliers Application', 'Use the method of Lagrange multipliers to find the maximum of f(x,y) = xy subject to the constraint x + y = 10. Derive the system of equations, solve it, and explain geometrically why the gradient condition is necessary.', 'HARD', 'At the optimum, the gradient of f is parallel to the gradient of the constraint; set up the system with a multiplier lambda.', 'Optimization'),
  ('q-0380', 'calculus', 'Implicit Function Theorem', 'State the implicit function theorem and explain when an equation F(x,y) = 0 locally defines y as a function of x. Derive the formula dy/dx = -F_x / F_y and discuss what fails when F_y = 0.', 'HARD', 'The theorem requires the partial derivative with respect to the dependent variable to be nonzero at the point of interest.', 'Multivariable'),
  ('q-0381', 'linear-algebra', 'Vector Space Axioms', 'Define a vector space and list the eight axioms. Give an example of a set with two operations that is not a vector space, and identify which axiom fails.', 'EASY', 'Check closure under addition and scalar multiplication and the existence of additive inverses.', 'Vector Spaces'),
  ('q-0382', 'linear-algebra', 'Matrix Multiplication Mechanics', 'Given two matrices A (m x n) and B (n x p), describe how to compute the product AB. Why must the inner dimensions match, and what is the interpretation of the (i,j) entry of AB in terms of row-column dot products?', 'EASY', 'The (i,j) entry is the dot product of row i of A and column j of B.', 'Matrices'),
  ('q-0383', 'linear-algebra', 'Linear Independence Concept', 'Define linear independence of a set of vectors. Give a criterion for testing linear independence, and explain why a set containing the zero vector is always linearly dependent.', 'EASY', 'A set is linearly independent if no nontrivial linear combination gives the zero vector; the zero vector alone yields dependence.', 'Vector Spaces'),
  ('q-0384', 'linear-algebra', 'Eigenvalues and Eigenvectors Derivation', 'Define eigenvalues and eigenvectors of a square matrix A. Derive the characteristic equation det(A - lambda*I) = 0, and find the eigenvalues of the matrix [[2, 1], [1, 2]].', 'MEDIUM', 'Solve det(A - lambda*I) = 0 for lambda; for the given matrix, the eigenvalues are symmetric about 2.', 'Eigenvalues'),
  ('q-0385', 'linear-algebra', 'SVD and Low-Rank Approximation', 'Explain the singular value decomposition (SVD) of a matrix A = U*Sigma*V^T. What do the matrices U, Sigma, and V represent, and how is the SVD used for low-rank approximation and principal component analysis?', 'MEDIUM', 'Sigma holds the singular values in descending order; truncating it yields the best rank-k approximation by the Eckart-Young theorem.', 'Decompositions'),
  ('q-0386', 'linear-algebra', 'Vector and Subspace Projection', 'Derive the formula for the projection of a vector b onto a vector a: proj_a(b) = (a.b / a.a) * a. Generalize this to the projection of b onto the column space of a matrix A, and explain the role of A^T*A.', 'MEDIUM', 'The projection minimizes the distance from b to the subspace; set the residual orthogonal to the subspace.', 'Projections'),
  ('q-0387', 'linear-algebra', 'Rank-Nullity Theorem', 'State the rank-nullity theorem and explain it in terms of the dimensions of the column space and null space. For a 4x6 matrix of rank 2, what is the dimension of the null space?', 'MEDIUM', 'rank(A) + nullity(A) equals the number of columns of A.', 'Rank'),
  ('q-0388', 'linear-algebra', 'Positive Definite Matrices', 'Define a positive definite matrix and list three equivalent characterizations (eigenvalues, quadratic form, Cholesky decomposition). Why are positive definite matrices important in optimization and machine learning?', 'MEDIUM', 'Positive definiteness ensures the quadratic form is strictly positive, which corresponds to a convex (bowl-shaped) surface.', 'Matrices'),
  ('q-0389', 'linear-algebra', 'Spectral Theorem Proof', 'State and sketch a proof of the spectral theorem for symmetric matrices: every real symmetric matrix is orthogonally diagonalizable. Explain why symmetry guarantees real eigenvalues and orthogonal eigenvectors.', 'HARD', 'Use the fact that for a symmetric A, the quadratic form x^T*A*x is real, and show eigenvectors for distinct eigenvalues are orthogonal.', 'Decompositions'),
  ('q-0390', 'linear-algebra', 'PCA Derivation from Variance', 'Derive principal component analysis from the objective of maximizing the variance of the projected data. Show that the optimal projection direction is the leading eigenvector of the covariance matrix, and connect this to the SVD of the centered data matrix.', 'HARD', 'Maximize w^T*Cov*w subject to ||w||=1; the Lagrangian yields Cov*w = lambda*w.', 'Applications'),
  ('q-0391', 'discrete-math', 'Combinations Versus Permutations', 'A committee of 3 is to be chosen from 10 people. How many ways can this be done if order does not matter? How does the answer change if the committee has distinct roles (chair, secretary, member)?', 'EASY', 'Use combinations when order does not matter; permutations when roles make order matter.', 'Combinatorics'),
  ('q-0392', 'discrete-math', 'Pigeonhole Principle Application', 'State the pigeonhole principle. Prove that in any group of 367 people, at least two share a birthday, and explain how the principle generalizes to the ceiling function form.', 'EASY', 'There are 366 possible birthdays (including February 29); 367 people force a collision by the pigeonhole principle.', 'Counting'),
  ('q-0393', 'discrete-math', 'Set Operations and De Morgan', 'Define union, intersection, and complement of sets, and state De Morgan''s laws. Prove one of the laws using a membership table or a logical argument.', 'EASY', 'De Morgan''s laws relate the complement of a union to the intersection of complements and vice versa.', 'Set Theory'),
  ('q-0394', 'discrete-math', 'Linear Recurrence Solution', 'Solve the recurrence relation a(n) = 2*a(n-1) + 1 with a(0) = 0. Show your work by finding the homogeneous and particular solutions, and verify the closed form by substitution.', 'MEDIUM', 'Solve the homogeneous part a(n) = 2*a(n-1), then find a constant particular solution.', 'Recurrences'),
  ('q-0395', 'discrete-math', 'BFS Versus DFS Comparison', 'Compare breadth-first search and depth-first search on a graph. What data structures does each use, what are their time complexities, and what types of problems is each better suited for?', 'MEDIUM', 'BFS uses a queue and finds shortest paths in unweighted graphs; DFS uses a stack (or recursion) and is useful for cycle detection and topological sort.', 'Graphs'),
  ('q-0396', 'discrete-math', 'Modular Arithmetic and CRT', 'Explain modular arithmetic and the Chinese Remainder Theorem. Solve the system x = 2 (mod 3), x = 3 (mod 5), x = 2 (mod 7) and explain the structure of the solution set.', 'MEDIUM', 'The CRT guarantees a unique solution modulo the product of the moduli when they are pairwise coprime.', 'Number Theory'),
  ('q-0397', 'discrete-math', 'Proof Techniques and Irrationality', 'Explain the difference between direct proof, proof by contrapositive, and proof by contradiction. Prove that the square root of 2 is irrational using proof by contradiction, showing the parity argument clearly.', 'MEDIUM', 'Assume sqrt(2) = p/q in lowest terms, derive that both p and q are even, contradicting lowest terms.', 'Proofs'),
  ('q-0398', 'discrete-math', 'Generating Functions for Fibonacci', 'Explain how generating functions can be used to solve counting problems. Derive the generating function for the Fibonacci sequence, and explain how its closed form yields Binet''s formula.', 'MEDIUM', 'Set up G(x) = sum F(n)*x^n, use the recurrence to derive a rational function, and decompose via partial fractions.', 'Generating Functions'),
  ('q-0399', 'discrete-math', 'Master Theorem Derivation', 'State the Master Theorem for divide-and-conquer recurrences of the form T(n) = a*T(n/b) + f(n). Derive the three cases, and apply the theorem to T(n) = 4*T(n/2) + n^2 to determine the asymptotic complexity.', 'HARD', 'Compare f(n) to n^(log_b a); the relative growth determines which case applies.', 'Algorithms'),
  ('q-0400', 'discrete-math', 'Graph Coloring and Greedy Bound', 'Explain graph coloring and the four color theorem. Describe a greedy coloring algorithm, prove it uses at most (Delta + 1) colors where Delta is the max degree, and discuss why the chromatic number can be much smaller than this bound.', 'HARD', 'Order the vertices and color each with the smallest available color; at most Delta neighbors have been colored before any vertex.', 'Graphs'),
  ('q-0401', 'probability', 'Sample Spaces and Events', 'What is a sample space in probability theory, and how does it differ from an event? Give an example of a sample space for rolling two dice, and identify two events within it. Why is defining the sample space carefully important for probability calculations?', 'EASY', 'Think of the sample space as the universe of all possible outcomes, while events are subsets of that universe.', 'Sample Spaces'),
  ('q-0402', 'probability', 'Conditional Probability Definition', 'Define conditional probability and write its formula. If P(A) = 0.4, P(B) = 0.5, and P(A and B) = 0.2, what is P(A|B)? Explain what this value means in plain language.', 'EASY', 'Conditional probability restricts the universe to outcomes where the conditioning event has already occurred.', 'Conditional Probability'),
  ('q-0403', 'probability', 'Independence vs Mutual Exclusivity', 'Explain the difference between independent events and mutually exclusive events. Can two events with nonzero probability be both independent and mutually exclusive at the same time? Justify your answer mathematically.', 'EASY', 'Mutual exclusivity means P(A and B) = 0, while independence means P(A and B) = P(A)P(B).', 'Independence'),
  ('q-0404', 'probability', 'Bayes Theorem Application', 'State Bayes'' theorem and explain what each term represents. Apply it to a medical testing scenario with 1% disease prevalence, 99% sensitivity, and 95% specificity. What is the probability that a positive test indicates a true positive, and why does this surprise many people?', 'MEDIUM', 'Be careful to distinguish P(Disease|Positive) from P(Positive|Disease), and remember the base rate.', 'Bayesian'),
  ('q-0405', 'probability', 'Expected Value of a Dice Game', 'A game costs 3 dollars to play. You roll a fair six-sided die and win the dollar amount shown on the die. Compute the expected value of playing this game. Should a rational player play repeatedly, and what does the law of large numbers say about long-term outcomes?', 'MEDIUM', 'Compute the expected payout as the sum of (value times probability) and compare it to the cost of playing.', 'Expected Value'),
  ('q-0406', 'probability', 'Markov Chains and Stationarity', 'Define a Markov chain and explain the Markov property. What is a stationary distribution, and under what conditions does a unique stationary distribution exist? Describe one real-world application of Markov chains.', 'MEDIUM', 'The Markov property says the future depends only on the present, not on the past history.', 'Markov Chains'),
  ('q-0407', 'probability', 'Monty Hall Problem', 'Describe the Monty Hall problem and explain why switching doors gives a 2/3 chance of winning. Construct a clear argument using either conditional probability or enumeration of all cases. Why do most people intuitively guess that switching gives a 1/2 chance?', 'MEDIUM', 'Enumerate the three equally likely positions of the prize and track what happens under the switch strategy.', 'Counterintuitive'),
  ('q-0408', 'probability', 'Birthday Problem Derivation', 'In a room of n people, what is the probability that at least two share a birthday? Derive an approximate formula and compute the threshold n where the probability exceeds 50%. Explain why this answer surprises most people.', 'MEDIUM', 'It is easier to compute the complement: the probability that all n birthdays are distinct.', 'Combinatorics'),
  ('q-0409', 'probability', 'Gambler''s Ruin Derivation', 'Set up the gambler''s ruin problem: a gambler starts with i dollars, wins a dollar with probability p each round, loses a dollar with probability q = 1 - p, and stops at 0 or N. Derive the probability of reaching N before 0, and discuss the symmetric case p = 0.5.', 'HARD', 'Set up a recurrence relation for the probability of success from state i and solve the second-order difference equation.', 'Random Walks'),
  ('q-0410', 'probability', 'Poisson Process Properties', 'Define a Poisson process and list its key properties. Derive the inter-arrival time distribution from the Poisson distribution. Give an example of how a Poisson process models real-world events such as radioactive decay or call arrivals.', 'HARD', 'Use the relationship P(no arrivals in time t) = exp(-lambda*t) to extract the exponential inter-arrival distribution.', 'Poisson Processes'),
  ('q-0411', 'statistics', 'Mean Median and Mode', 'Define the mean, median, and mode of a dataset, and explain when each is most appropriate. Describe a skewed distribution where the median is a better measure of central tendency than the mean. Why does the mean get pulled toward outliers more than the median does?', 'EASY', 'Consider how each measure responds to extreme values; the median is based on rank, the mean on magnitude.', 'Central Tendency'),
  ('q-0412', 'statistics', 'Interpreting the P-value', 'What is a p-value, and what common misinterpretations do people make about it? Explain the difference between a p-value and the probability that the null hypothesis is true. How does the significance level alpha relate to the p-value in a hypothesis test?', 'EASY', 'A p-value is computed assuming the null hypothesis is true, not the other way around.', 'Significance Testing'),
  ('q-0413', 'statistics', 'Variance and Standard Deviation', 'Define variance and standard deviation, and explain the relationship between them. Why is the standard deviation often more interpretable than the variance? Compute the variance of the dataset {2, 4, 4, 4, 5, 5, 7, 9}.', 'EASY', 'Standard deviation has the same units as the data, while variance has squared units.', 'Dispersion'),
  ('q-0414', 'statistics', 'Central Limit Theorem', 'State the Central Limit Theorem and explain why it is foundational to statistics. Under what conditions does the CLT apply, and what is the role of sample size? Give an example of how the CLT justifies using the normal distribution for sample means.', 'MEDIUM', 'The CLT concerns the distribution of the sample mean, not the distribution of the underlying data itself.', 'Limit Theorems'),
  ('q-0415', 'statistics', 'Confidence Interval Construction', 'Construct a 95% confidence interval for a population mean given a sample mean, sample standard deviation, and sample size. Explain what ''95% confidence'' means in frequentist terms, and contrast this with a Bayesian credible interval.', 'MEDIUM', 'Under repeated sampling, 95% of similarly constructed intervals would contain the true mean.', 'Confidence Intervals'),
  ('q-0416', 'statistics', 'Maximum Likelihood Estimation', 'Explain the principle of maximum likelihood estimation (MLE). Derive the MLE for the mean of a normal distribution with known variance. What properties does the MLE have asymptotically, and under what conditions can it fail?', 'MEDIUM', 'Write the likelihood as a product of normal densities, take the log, and differentiate with respect to the mean.', 'Estimation'),
  ('q-0417', 'statistics', 'Two-Sample t-test Procedure', 'Describe the procedure for a two-sample t-test, including the null and alternative hypotheses, assumptions, and test statistic. What is the difference between a one-tailed and two-tailed test? Discuss the trade-off between Type I and Type II errors.', 'MEDIUM', 'Assume normality and equal or unequal variances; the test statistic standardizes the difference of means.', 'Hypothesis Testing'),
  ('q-0418', 'statistics', 'The Bias-Variance Tradeoff', 'Explain the bias-variance tradeoff in the context of statistical learning. Decompose the expected prediction error into bias squared, variance, and irreducible error. How does model complexity affect each component, and how does this guide regularization?', 'MEDIUM', 'As complexity increases, bias typically decreases while variance increases; the optimum balances them.', 'Learning Theory'),
  ('q-0419', 'statistics', 'Cramer-Rao Lower Bound', 'State the Cramer-Rao lower bound and explain what it tells us about estimators. Sketch a derivation using the Cauchy-Schwarz inequality applied to the score function. Give an example of an estimator that achieves this bound.', 'HARD', 'The bound is the inverse of the Fisher information, and equality holds when the estimator is a linear function of the score.', 'Estimation Theory'),
  ('q-0420', 'statistics', 'Bayesian vs Frequentist Inference', 'Contrast Bayesian and frequentist approaches to statistical inference. Discuss how each treats parameters, how each interprets probability, and how each handles uncertainty. Give one advantage and one criticism of each framework.', 'HARD', 'Bayesians treat parameters as random and update priors with data; frequentists treat parameters as fixed but unknown.', 'Inference Frameworks'),
  ('q-0421', 'physics-mechanics', 'Newton''s Three Laws', 'State Newton''s three laws of motion and give a real-world example of each. Explain how the second law reduces to the first when the net force is zero. Why is the third law often misunderstood in the context of action-reaction pairs?', 'EASY', 'Action and reaction act on different bodies, so they never cancel each other out on a single object.', 'Newtonian Dynamics'),
  ('q-0422', 'physics-mechanics', 'Deriving the Kinematic Equations', 'Derive the four kinematic equations for constant acceleration. Under what conditions do these equations apply, and what happens when acceleration varies with time? Apply one equation to compute the distance traveled by an object dropped from rest after 3 seconds.', 'EASY', 'Start from a = constant, integrate to get velocity, and integrate again to get position.', 'Kinematics'),
  ('q-0423', 'physics-mechanics', 'Conservation of Mechanical Energy', 'State the principle of conservation of mechanical energy. Apply it to a block sliding down a frictionless ramp of height h, and compute its speed at the bottom. When is mechanical energy not conserved, and how does the first law of thermodynamics generalize this principle?', 'EASY', 'Set initial potential energy m*g*h equal to final kinetic energy (1/2)*m*v^2 and solve for v.', 'Energy'),
  ('q-0424', 'physics-mechanics', 'Lagrangian of a Pendulum', 'Set up the Lagrangian L = T - V for a simple pendulum and derive its equation of motion using the Euler-Lagrange equation. Compare the result to the Newtonian derivation. What advantage does the Lagrangian approach offer for constrained systems?', 'MEDIUM', 'Express kinetic and potential energy in terms of the angle theta and its time derivative, then apply d/dt(dL/dtheta_dot) - dL/dtheta = 0.', 'Lagrangian Mechanics'),
  ('q-0425', 'physics-mechanics', 'Projectile Motion with Drag', 'Write the equations of motion for a projectile subject to linear air drag proportional to velocity. Qualitatively describe how the trajectory differs from the ideal parabola. Explain the concept of terminal velocity and how it emerges from these equations.', 'MEDIUM', 'The drag force opposes velocity, so the equations decouple into a horizontal exponentially decaying motion and a vertical motion approaching terminal velocity.', 'Drag Forces'),
  ('q-0426', 'physics-mechanics', 'Moment of Inertia of a Sphere', 'Define moment of inertia and explain its role in rotational dynamics analogous to mass in linear motion. Derive the moment of inertia of a uniform solid sphere about an axis through its center. How does the parallel axis theorem generalize this to off-center axes?', 'MEDIUM', 'Integrate over spherical shells or disks, weighting each mass element by the square of its distance from the axis.', 'Rotational Dynamics'),
  ('q-0427', 'physics-mechanics', 'Simple Harmonic Oscillator', 'Set up the differential equation for a simple harmonic oscillator with mass m and spring constant k, and solve it. Explain the physical meaning of the angular frequency omega = sqrt(k/m). How does adding a damping term change the solution and its regimes?', 'MEDIUM', 'The equation is m*x'''' + k*x = 0, a second-order linear ODE with sinusoidal solutions.', 'Oscillations'),
  ('q-0428', 'physics-mechanics', 'Elastic Collisions in 1D', 'Distinguish elastic, inelastic, and perfectly inelastic collisions in terms of conservation laws. Derive the final velocities for a one-dimensional elastic collision between two masses. Why is kinetic energy not conserved in inelastic collisions, and where does the energy go?', 'MEDIUM', 'Apply both conservation of momentum and conservation of kinetic energy, then solve the resulting system.', 'Collisions'),
  ('q-0429', 'physics-mechanics', 'Hamiltonian Mechanics Derivation', 'Derive Hamilton''s equations from the Lagrangian via the Legendre transform for a particle in one dimension. Explain the symplectic structure of phase space and how it differs from the Lagrangian formulation. What is Liouville''s theorem, and why does it matter for statistical mechanics?', 'HARD', 'Define the conjugate momentum p = dL/dx_dot, form H = p*x_dot - L, and take partial derivatives of H.', 'Hamiltonian Mechanics'),
  ('q-0430', 'physics-mechanics', 'Coriolis and Centrifugal Forces', 'Derive the Coriolis and centrifugal fictitious forces that appear in a rotating reference frame. Explain why hurricanes rotate counterclockwise in the Northern Hemisphere. How does the choice of reference frame affect the equations of motion without changing physical predictions?', 'HARD', 'Apply the time-derivative transformation between inertial and rotating frames to the position vector.', 'Non-Inertial Frames'),
  ('q-0431', 'physics-quantum', 'Wave-Particle Duality and Light', 'Explain the concept of wave-particle duality and cite the double-slit experiment as evidence. What happens to the interference pattern when which-path information is obtained? How does de Broglie''s relation lambda = h/p connect particles and waves?', 'EASY', 'Complementarity: observing which path destroys the interference pattern because measurement collapses the state.', 'Duality'),
  ('q-0432', 'physics-quantum', 'Heisenberg Uncertainty Principle', 'State the Heisenberg uncertainty principle in terms of position and momentum, and explain its physical meaning. Is this a limitation of measurement or a fundamental property of nature? Estimate the minimum uncertainty in position for an electron confined to a 1 nm region.', 'EASY', 'The bound is delta_x * delta_p >= hbar/2, and confining position forces momentum to spread.', 'Uncertainty'),
  ('q-0433', 'physics-quantum', 'Schrodinger Equation Basics', 'Write the time-dependent and time-independent Schrodinger equations and explain the relationship between them. What is the physical meaning of the wavefunction psi? State Born''s interpretation of |psi|^2.', 'EASY', 'The time-independent equation comes from separation of variables when the potential is time-independent.', 'Schrodinger Equation'),
  ('q-0434', 'physics-quantum', 'Particle in a Box', 'Solve the time-independent Schrodinger equation for a particle in a one-dimensional infinite potential well of width L. Derive the quantized energy levels and explain why the ground-state energy is nonzero. Sketch the first three wavefunctions and probability densities.', 'MEDIUM', 'Apply boundary conditions psi(0) = psi(L) = 0 to a sinusoidal solution, which forces integer half-wavelengths.', 'Bound States'),
  ('q-0435', 'physics-quantum', 'Quantum Harmonic Oscillator', 'Set up the Hamiltonian for the quantum harmonic oscillator and explain the ladder operator method of solution. What are the energy eigenvalues, and how do they compare to the classical oscillator? Discuss the correspondence principle in this context.', 'MEDIUM', 'Define raising and lowering operators a and a_dagger in terms of x and p; the energies are E_n = (n + 1/2) * hbar * omega.', 'Harmonic Oscillator'),
  ('q-0436', 'physics-quantum', 'Hydrogen Atom Solution', 'Outline the solution of the Schrodinger equation for the hydrogen atom and describe the resulting quantum numbers n, l, and m_l. Explain the origin of the 2n^2 degeneracy. How does the addition of spin and fine structure modify the energy spectrum?', 'MEDIUM', 'Separate variables in spherical coordinates; the boundary conditions quantize all three quantum numbers.', 'Hydrogen Atom'),
  ('q-0437', 'physics-quantum', 'The Stern-Gerlach Experiment', 'Describe the Stern-Gerlach experiment and explain what it revealed about electron spin. Why was silver used, and why does the beam split into exactly two components? How does this experiment demonstrate quantization of angular momentum?', 'MEDIUM', 'A silver atom has a single unpaired electron, so its magnetic moment is dominated by that electron''s spin.', 'Spin'),
  ('q-0438', 'physics-quantum', 'Quantum Tunneling Through Barriers', 'Explain quantum tunneling and set up the problem of a particle incident on a rectangular potential barrier. How does the transmission probability depend on barrier width and height? Give two real-world applications of tunneling, such as scanning tunneling microscopy and alpha decay.', 'MEDIUM', 'Inside the barrier the wavefunction decays exponentially, so transmission scales with exp(-2*kappa*width).', 'Tunneling'),
  ('q-0439', 'physics-quantum', 'Bell''s Inequality and EPR', 'Explain the EPR paradox and Bell''s theorem. What does Bell''s inequality state, and how do experimental violations of it rule out local hidden variable theories? Discuss the implications for quantum entanglement and locality.', 'HARD', 'Any local hidden variable theory must satisfy Bell''s inequality; quantum mechanics predicts and experiments confirm a violation.', 'Entanglement'),
  ('q-0440', 'physics-quantum', 'Dirac Notation and Commutators', 'Introduce Dirac bra-ket notation and explain how operators, eigenvalues, and expectation values are expressed in it. Derive the commutator relation [x, p] = i*hbar and discuss its connection to the uncertainty principle. How does this formalism generalize to finite-dimensional spin systems?', 'HARD', 'Work in the position representation where x is multiplication and p = -i*hbar*d/dx, then compute the commutator on a test function.', 'Formalism'),
  ('q-0441', 'chemistry', 'Atomic Structure Basics', 'Describe the structure of an atom in terms of protons, neutrons, and electrons. Define atomic number, mass number, and isotopes. How does the arrangement of electrons in shells determine an element''s chemical properties?', 'EASY', 'Electron configuration, especially in the outermost shell, governs bonding behavior and reactivity.', 'Atomic Structure'),
  ('q-0442', 'chemistry', 'Mole Concept and Avogadro''s Number', 'Explain the mole concept and Avogadro''s number. Convert 18 grams of water to moles and to molecules. Why is the mole useful for relating macroscopic masses to atomic-scale counts in stoichiometry?', 'EASY', 'One mole is 6.022 x 10^23 particles, and the molar mass of water is 18 g/mol.', 'Mole Concept'),
  ('q-0443', 'chemistry', 'Periodic Table Trends', 'Describe the trends in atomic radius, ionization energy, and electronegativity across the periodic table. Explain the underlying reasons in terms of effective nuclear charge and electron shielding. How do these trends predict the reactivity of metals versus nonmetals?', 'EASY', 'Moving across a period increases nuclear charge while shielding stays roughly constant, affecting radius and ionization energy.', 'Periodic Trends'),
  ('q-0444', 'chemistry', 'Stoichiometry of Propane Combustion', 'Balance the combustion reaction of propane (C3H8) with oxygen, and compute the mass of CO2 produced from 100 g of propane. Explain how limiting reagents affect the yield. Walk through the mole-to-mole conversion steps explicitly.', 'MEDIUM', 'Balance C, then H, then O to get C3H8 + 5 O2 -> 3 CO2 + 4 H2O, then convert grams of propane to moles.', 'Stoichiometry'),
  ('q-0445', 'chemistry', 'Le Chatelier and the Haber Process', 'State Le Chatelier''s principle and apply it to the Haber process for ammonia synthesis. How do changes in pressure, temperature, and concentration shift the equilibrium? Explain why the industrial process uses moderate, not extreme, conditions.', 'MEDIUM', 'N2 + 3 H2 <-> 2 NH3 is exothermic and reduces moles of gas, so pressure and temperature shift it in opposite ways.', 'Equilibrium'),
  ('q-0446', 'chemistry', 'pH of Strong and Weak Acids', 'Define pH and explain the autoionization of water. Calculate the pH of a 0.025 M solution of HCl and a 0.025 M solution of acetic acid (Ka = 1.8 x 10^-5). Contrast strong and weak acids using these calculations.', 'MEDIUM', 'For the weak acid, set up an ICE table and solve the equilibrium expression for [H+].', 'Acid-Base'),
  ('q-0447', 'chemistry', 'Integrated Rate Laws', 'Explain the difference between zero-order, first-order, and second-order rate laws. Derive the integrated rate law for a first-order reaction and define the half-life. How does the Arrhenius equation describe the temperature dependence of rate constants?', 'MEDIUM', 'For first order, separate variables in d[A]/dt = -k[A] and integrate to get ln[A] = ln[A0] - k*t.', 'Kinetics'),
  ('q-0448', 'chemistry', 'Gibbs Free Energy and Spontaneity', 'Define Gibbs free energy and explain how it determines spontaneity through delta G = delta H - T * delta S. For a reaction with delta H = -50 kJ/mol and delta S = -100 J/(mol*K), at what temperature does the reaction become non-spontaneous? Give one experimental example.', 'MEDIUM', 'Set delta G = 0 and solve for T to find the crossover temperature where spontaneity flips.', 'Thermodynamics'),
  ('q-0449', 'chemistry', 'Molecular Orbital Theory of O2', 'Construct the molecular orbital diagram for O2 and explain why it is paramagnetic, contrary to valence bond theory predictions. Define bonding, antibonding, and the bond order formula. How does MO theory explain the relative bond lengths of O2, O2+, and O2-?', 'HARD', 'Fill the MO diagram with 12 valence electrons and note the unpaired electrons in pi* antibonding orbitals.', 'Bonding'),
  ('q-0450', 'chemistry', 'Reaction Mechanisms and Catalysis', 'Explain how experimental rate laws are used to deduce reaction mechanisms, using the reaction of NO2 with CO as an example. Discuss the rate-determining step and how catalysts lower activation energy. Distinguish homogeneous and heterogeneous catalysis with examples.', 'HARD', 'The observed rate law reflects the slowest elementary step; catalysts provide an alternative pathway with lower activation energy.', 'Mechanisms'),
  ('q-0451', 'biology', 'Principles of Cell Theory', 'State the three principles of cell theory. Distinguish prokaryotic and eukaryotic cells in terms of major structural features. Why is the cell considered the basic unit of life?', 'EASY', 'Cell theory states that all living things are made of cells, cells are the basic unit of life, and cells come from pre-existing cells.', 'Cell Theory'),
  ('q-0452', 'biology', 'Organelles and Endosymbiosis', 'List three membrane-bound organelles in eukaryotic cells and describe the primary function of each. Explain how the endosymbiotic theory accounts for the origin of mitochondria and chloroplasts. What evidence supports this theory?', 'EASY', 'Mitochondria and chloroplasts have their own circular DNA, double membranes, and bacterial-like ribosomes.', 'Organelles'),
  ('q-0453', 'biology', 'Fluid Mosaic Model', 'Describe the fluid mosaic model of the cell membrane. Explain the roles of phospholipids, cholesterol, and membrane proteins. Why is selective permeability essential for maintaining homeostasis?', 'EASY', 'Phospholipids form a bilayer with hydrophilic heads and hydrophobic tails; proteins float within this fluid structure.', 'Membranes'),
  ('q-0454', 'biology', 'Stages of Cellular Respiration', 'Outline the four stages of aerobic cellular respiration and the location of each in the cell. Compare the ATP yield of aerobic respiration to anaerobic fermentation. How is the proton-motive force harnessed in oxidative phosphorylation?', 'MEDIUM', 'Glycolysis, pyruvate oxidation, the Krebs cycle, and oxidative phosphorylation produce roughly 36 to 38 ATP per glucose.', 'Metabolism'),
  ('q-0455', 'biology', 'Eukaryotic Cell Cycle', 'Describe the phases of the eukaryotic cell cycle, including interphase (G1, S, G2) and mitosis. Explain the role of checkpoints and cyclin-CDK complexes in regulating the cycle. What happens when checkpoint control fails?', 'MEDIUM', 'Cyclins bind CDKs to drive transitions; checkpoint failure can lead to uncontrolled division and cancer.', 'Cell Cycle'),
  ('q-0456', 'biology', 'Protein Synthesis Pathway', 'Trace the flow of genetic information from DNA to protein through transcription and translation. Distinguish the roles of mRNA, tRNA, and ribosomes. How does the genetic code''s redundancy affect the impact of point mutations?', 'MEDIUM', 'Multiple codons often code for the same amino acid, so silent mutations can leave the protein unchanged.', 'Gene Expression'),
  ('q-0457', 'biology', 'Membrane Transport Mechanisms', 'Compare passive diffusion, facilitated diffusion, and active transport across cell membranes. Explain how the sodium-potassium pump maintains the resting membrane potential. Why does active transport require ATP?', 'MEDIUM', 'Active transport moves substances against their gradients, which is thermodynamically unfavorable without energy input.', 'Membrane Transport'),
  ('q-0458', 'biology', 'The Endomembrane System', 'Describe the endomembrane system, including the endoplasmic reticulum, Golgi apparatus, lysosomes, and vesicles. Trace the pathway of a secreted protein from synthesis to exocytosis. How do signal peptides direct proteins to the correct compartment?', 'MEDIUM', 'A signal peptide on the nascent polypeptide is recognized by SRP, which targets the ribosome to the ER.', 'Endomembrane'),
  ('q-0459', 'biology', 'GPCR Signal Transduction', 'Explain how a typical G-protein-coupled receptor (GPCR) signaling cascade amplifies an extracellular signal. Use the beta-adrenergic receptor pathway involving cAMP and protein kinase A as an example. How do cells terminate or desensitize the signal?', 'HARD', 'Ligand binding activates a Gs alpha subunit, which stimulates adenylyl cyclase to produce many cAMP molecules per activated receptor.', 'Signaling'),
  ('q-0460', 'biology', 'Apoptosis Pathways and Caspases', 'Distinguish apoptosis from necrosis in terms of mechanism and cellular consequences. Outline the intrinsic and extrinsic pathways of apoptosis, including the roles of caspases and mitochondria. Why is regulated cell death essential for development and tissue homeostasis?', 'HARD', 'Both pathways converge on executioner caspases; the intrinsic pathway is triggered by cytochrome c release from mitochondria.', 'Cell Death'),
  ('q-0461', 'genetics', 'Mendel''s Laws of Inheritance', 'State Mendel''s law of segregation and law of independent assortment. Use a monohybrid cross of two heterozygous tall pea plants (Tt x Tt) to illustrate the 3:1 phenotypic ratio. Under what conditions does the law of independent assortment fail?', 'EASY', 'Independent assortment fails when genes are linked on the same chromosome and do not recombine sufficiently.', 'Mendelian'),
  ('q-0462', 'genetics', 'DNA Double Helix Structure', 'Describe the Watson-Crick double helix model of DNA, including base pairing rules and antiparallel strands. Explain how the structure suggests a mechanism for replication. What experimental evidence, including Chargaff''s rules, supported this model?', 'EASY', 'Chargaff''s rules showed A = T and G = C, hinting at specific complementary base pairing.', 'DNA Structure'),
  ('q-0463', 'genetics', 'Dihybrid Cross and Punnett Squares', 'Use a Punnett square to predict the offspring of a dihybrid cross between two pea plants heterozygous for both seed color and seed shape. Explain the expected 9:3:3:1 phenotypic ratio. When would deviations from this ratio occur?', 'EASY', 'Each gene segregates independently, producing four gamete types in equal proportions.', 'Crosses'),
  ('q-0464', 'genetics', 'Genetic Linkage and Recombination', 'Explain genetic linkage and how it violates Mendel''s law of independent assortment. Define recombination frequency and explain how it is used to construct genetic maps. What does a recombination frequency of 50% indicate?', 'MEDIUM', 'Recombination frequency reflects how far apart genes are on a chromosome; 50% means they assort as if unlinked.', 'Linkage'),
  ('q-0465', 'genetics', 'Hardy-Weinberg Equilibrium Conditions', 'State the Hardy-Weinberg equilibrium conditions and equations. In a population where the recessive allele frequency q = 0.2, what fraction of individuals are heterozygous carriers? List the five assumptions and one realistic way each is violated.', 'MEDIUM', 'Use p + q = 1 and p^2 + 2pq + q^2 = 1; heterozygotes are 2pq.', 'Population Genetics'),
  ('q-0466', 'genetics', 'Human Pedigree Analysis', 'Interpret a human pedigree to determine whether a trait is autosomal dominant, autosomal recessive, or X-linked. What patterns distinguish each inheritance mode? Why are X-linked recessive traits more common in males than in females?', 'MEDIUM', 'Males are hemizygous for X-linked genes, so a single recessive allele is expressed.', 'Pedigree Analysis'),
  ('q-0467', 'genetics', 'Lac Operon Regulation', 'Explain how gene expression is regulated in prokaryotes using the lac operon as a model. Distinguish positive and negative control and the roles of the repressor and CAP. How does this compare to eukaryotic transcriptional regulation?', 'MEDIUM', 'The lac repressor blocks transcription when lactose is absent; CAP activates transcription when glucose is low.', 'Regulation'),
  ('q-0468', 'genetics', 'CRISPR-Cas9 Genome Editing', 'Describe the mechanism of CRISPR-Cas9 genome editing, including the roles of guide RNA, Cas9, and PAM sequences. Explain how double-strand breaks are repaired by NHEJ or HDR. Discuss one therapeutic application and one ethical concern.', 'MEDIUM', 'The guide RNA directs Cas9 to a complementary genomic sequence adjacent to the PAM, where Cas9 cuts.', 'Genome Editing'),
  ('q-0469', 'genetics', 'Quantitative Trait Loci', 'Explain what a quantitative trait locus (QTL) is and how QTL mapping identifies genomic regions contributing to complex traits. Contrast this approach with genome-wide association studies (GWAS). What statistical and biological challenges limit QTL resolution?', 'HARD', 'QTL mapping links phenotypic variation to genetic markers in controlled crosses; GWAS uses population-level associations.', 'Quantitative Genetics'),
  ('q-0470', 'genetics', 'Epigenetics and Gene Regulation', 'Define epigenetics and describe three molecular mechanisms: DNA methylation, histone modification, and non-coding RNAs. Explain how epigenetic changes can be inherited across cell divisions without altering DNA sequence. Discuss one example of epigenetic regulation, such as X-chromosome inactivation.', 'HARD', 'DNA methylation at CpG islands typically silences transcription, and these marks are copied during replication.', 'Epigenetics'),
  ('q-0471', 'neuroscience', 'Neuron Structure and Function', 'Describe the major structural components of a neuron, including dendrites, soma, axon, and synaptic terminals. Explain how these structures support the flow of electrical and chemical signals. What distinguishes neurons from glial cells in function?', 'EASY', 'Dendrites receive input, the axon conducts action potentials, and terminals release neurotransmitter; glia support but do not fire.', 'Neuroanatomy'),
  ('q-0472', 'neuroscience', 'Action Potential Phases', 'Outline the phases of an action potential and the ion movements underlying each. Explain the roles of voltage-gated sodium and potassium channels. Why is the refractory period important for unidirectional signal propagation?', 'EASY', 'Depolarization opens Na+ channels; repolarization follows K+ efflux; the refractory period prevents backward firing.', 'Electrophysiology'),
  ('q-0473', 'neuroscience', 'Cerebral Cortex Lobes', 'Name the four major lobes of the cerebral cortex and describe a primary function of each. Explain the concept of cortical localization with an example such as Broca''s area. How do the lobes communicate to integrate sensory and motor information?', 'EASY', 'Frontal, parietal, temporal, and occipital lobes specialize in motor planning, somatosensation, audition, and vision.', 'Brain Anatomy'),
  ('q-0474', 'neuroscience', 'Chemical Synapse Transmission', 'Describe the sequence of events at a chemical synapse from action potential arrival to postsynaptic response. Distinguish between ionotropic and metabotropic receptors. How do excitatory and inhibitory postsynaptic potentials integrate at the axon hillock?', 'MEDIUM', 'Calcium influx triggers vesicle fusion; ionotropic receptors are fast ligand-gated channels, metabotropic receptors act via G-proteins.', 'Synapses'),
  ('q-0475', 'neuroscience', 'Major Neurotransmitter Systems', 'List four major neurotransmitters and describe their primary roles in the nervous system. Explain how the same neurotransmitter can have different effects depending on receptor subtype. Give one example of a disorder associated with neurotransmitter dysfunction.', 'MEDIUM', 'Glutamate, GABA, dopamine, and serotonin each act on multiple receptor subtypes with distinct effects.', 'Neurochemistry'),
  ('q-0476', 'neuroscience', 'Monosynaptic Stretch Reflex', 'Describe the components of a monosynaptic stretch reflex, including the sensory receptor, afferent neuron, synapse, and motor neuron. Why are reflexes faster than voluntary responses? How does the knee-jerk reflex illustrate spinal integration?', 'MEDIUM', 'The stretch reflex bypasses the brain, so the delay is only one synapse long.', 'Reflex Circuits'),
  ('q-0477', 'neuroscience', 'Long-Term Potentiation and Memory', 'Define long-term potentiation (LTP) and its proposed role in learning and memory. Describe the NMDA receptor''s role as a coincidence detector and how calcium influx triggers LTP. How does LTP differ from long-term depression (LTD)?', 'MEDIUM', 'NMDA receptors require both presynaptic glutamate release and postsynaptic depolarization to open and admit calcium.', 'Synaptic Plasticity'),
  ('q-0478', 'neuroscience', 'Visual Transduction in Photoreceptors', 'Explain how photoreceptors in the retina transduce light into neural signals. Contrast rod and cone function in terms of sensitivity, acuity, and color vision. How does the visual pathway from retina to primary visual cortex preserve spatial information?', 'MEDIUM', 'Photons activate opsins that close Na+ channels, hyperpolarizing the cell; the retinotopic map is preserved through the LGN.', 'Sensory Systems'),
  ('q-0479', 'neuroscience', 'The Hodgkin-Huxley Model', 'Describe the Hodgkin-Huxley model of the action potential, including the gating variables m, h, and n. Explain how the model reproduces the threshold, spike, and refractory period. What was the significance of this work for computational neuroscience?', 'HARD', 'm and h gate the Na+ conductance, n gates K+; the coupled ODEs predict spike initiation and refractory behavior.', 'Computational'),
  ('q-0480', 'neuroscience', 'Parkinson''s Disease Mechanisms', 'Explain the pathophysiology of Parkinson''s disease, focusing on dopaminergic neuron degeneration in the substantia nigra. How do Lewy bodies and alpha-synuclein contribute to the disease? Discuss the mechanism of action of L-DOPA therapy and its limitations.', 'HARD', 'L-DOPA crosses the blood-brain barrier and is converted to dopamine, but it does not halt ongoing neurodegeneration.', 'Pathology'),
  ('q-0481', 'astronomy', 'Solar System Formation', 'Describe the structure of our solar system, including the terrestrial and gas giant planets and the Kuiper Belt. Explain how the nebular hypothesis accounts for the observed ordering and composition of planets. What evidence supports this formation model?', 'EASY', 'Inner planets formed where it was too hot for volatiles, leaving rocky worlds; outer planets retained gas and ice.', 'Solar System'),
  ('q-0482', 'astronomy', 'Stellar Lifecycle Stages', 'Outline the lifecycle of a star from protostar to end state, distinguishing low-mass and high-mass stars. Explain the role of nuclear fusion in stabilizing a star against gravitational collapse. What determines whether a star ends as a white dwarf, neutron star, or black hole?', 'EASY', 'The initial mass determines how far up the fusion chain the star can go and the nature of the remnant.', 'Stellar Evolution'),
  ('q-0483', 'astronomy', 'The Hertzsprung-Russell Diagram', 'Explain the Hertzsprung-Russell diagram and its main regions: main sequence, giants, and white dwarfs. What is the significance of the main sequence, and how does a star''s position on it relate to its mass and lifetime? Describe how the Sun will evolve on this diagram.', 'EASY', 'Main sequence stars fuse hydrogen; more massive stars sit at the hot, luminous, short-lived upper left.', 'Stellar Classification'),
  ('q-0484', 'astronomy', 'Hubble''s Law and Expansion', 'State Hubble''s law and explain how it provides evidence for the expansion of the universe. Define the Hubble constant and discuss the current tension between measured values. How does Hubble''s law relate to the Big Bang model?', 'MEDIUM', 'v = H0 * d; the recession velocity is proportional to distance, implying a beginning in time.', 'Cosmology'),
  ('q-0485', 'astronomy', 'Blackbody Radiation and Stars', 'Explain blackbody radiation and Wien''s displacement law. Given a star''s peak wavelength of 500 nm, estimate its surface temperature. How does the Stefan-Boltzmann law relate luminosity, temperature, and radius of a star?', 'MEDIUM', 'Wien''s law: lambda_max * T = 2.9 x 10^-3 m*K; Stefan-Boltzmann: L = 4*pi*R^2*sigma*T^4.', 'Stellar Physics'),
  ('q-0486', 'astronomy', 'Kepler''s Laws of Orbits', 'State Kepler''s three laws of planetary motion and derive the third law for circular orbits using Newton''s law of gravitation. Explain how the semi-major axis and period relate for planets in the solar system. What does the second law imply about orbital speed?', 'MEDIUM', 'Set gravitational force equal to centripetal force and solve for T^2 in terms of a^3.', 'Orbital Mechanics'),
  ('q-0487', 'astronomy', 'Cosmic Microwave Background', 'Describe the cosmic microwave background (CMB) and its discovery. What does its near-perfect blackbody spectrum at 2.7 K tell us about the early universe? How do anisotropies in the CMB inform cosmological parameters?', 'MEDIUM', 'The CMB is redshifted radiation from the epoch of recombination; its anisotropies seed large-scale structure.', 'Early Universe'),
  ('q-0488', 'astronomy', 'Galaxy Morphology Classification', 'Describe Edwin Hubble''s classification scheme for galaxies: elliptical, spiral, and irregular. What physical properties, such as star formation rate and gas content, distinguish these types? How does galaxy morphology relate to the galaxy''s evolutionary history?', 'MEDIUM', 'Ellipticals are gas-poor and red; spirals have ongoing star formation in their disks; irregulars are often tidally disturbed.', 'Galactic Astronomy'),
  ('q-0489', 'astronomy', 'Stellar Nucleosynthesis Processes', 'Outline the processes of stellar nucleosynthesis, including hydrogen burning, helium burning, and the s-process and r-process for heavy elements. Why does nucleosynthesis stall at iron? How do supernovae and neutron star mergers distribute heavy elements across the galaxy?', 'HARD', 'Fusion beyond iron is endothermic, so massive stars collapse and explode, seeding the interstellar medium.', 'Nucleosynthesis'),
  ('q-0490', 'astronomy', 'Evidence for Dark Matter', 'List three independent lines of evidence for the existence of dark matter, such as galaxy rotation curves, gravitational lensing, and the CMB power spectrum. What distinguishes cold dark matter from hot dark matter candidates? Why is dark matter not simply baryonic matter in unseen form?', 'HARD', 'Big Bang nucleosynthesis and CMB constraints limit baryonic density to a fraction of the total matter density.', 'Dark Matter'),
  ('q-0491', 'earth-science', 'Plate Tectonics Theory', 'Explain the theory of plate tectonics and the three main types of plate boundaries. Describe how convection in the mantle drives plate motion. What evidence, including seafloor spreading and paleomagnetism, supports this theory?', 'EASY', 'Divergent, convergent, and transform boundaries correspond to plates moving apart, together, or sliding past one another.', 'Plate Tectonics'),
  ('q-0492', 'earth-science', 'The Rock Cycle', 'Describe the rock cycle and the processes that transform igneous, sedimentary, and metamorphic rocks. Give an example pathway starting with an igneous rock and ending as a sedimentary rock. Why is the rock cycle considered a cycle rather than a linear process?', 'EASY', 'Any rock type can be transformed into any other through melting, erosion, or heat and pressure.', 'Rock Cycle'),
  ('q-0493', 'earth-science', 'Layered Structure of Earth', 'Describe the layered structure of Earth: crust, mantle, outer core, and inner core. Explain how seismic wave velocities reveal these layers. Why is the outer core liquid while the inner core is solid despite higher temperatures?', 'EASY', 'S-waves do not pass through the outer core, indicating it is liquid; immense pressure solidifies the inner core.', 'Earth Structure'),
  ('q-0494', 'earth-science', 'Igneous Rocks and Bowen''s Series', 'Distinguish intrusive and extrusive igneous rocks in terms of formation environment and texture. Explain how Bowen''s reaction series predicts mineral crystallization order from magma. Give an example of a mafic and a felsic igneous rock and how they differ.', 'MEDIUM', 'Slow cooling underground gives coarse crystals; rapid cooling at the surface gives fine-grained or glassy textures.', 'Petrology'),
  ('q-0495', 'earth-science', 'Weathering and Soil Formation', 'Distinguish physical and chemical weathering with two examples of each. Explain how climate, particularly temperature and rainfall, influences the dominant weathering regime. How does weathering contribute to soil formation and the global carbon cycle?', 'MEDIUM', 'Chemical weathering consumes atmospheric CO2 through silicate mineral reactions, acting as a long-term climate regulator.', 'Surface Processes'),
  ('q-0496', 'earth-science', 'Layers of the Atmosphere', 'Describe the four main layers of Earth''s atmosphere and the temperature trends within each. Explain why the ozone layer in the stratosphere is critical for life. How does temperature inversion in the troposphere affect air quality?', 'MEDIUM', 'Troposphere cools with altitude; stratosphere warms due to ozone absorbing UV; inversions trap pollutants near the ground.', 'Atmospheric Science'),
  ('q-0497', 'earth-science', 'Ocean Currents and Circulation', 'Distinguish surface ocean currents from deep thermohaline circulation. Explain how the Coriolis effect, wind patterns, and density differences drive these currents. How does the global ocean conveyor belt influence regional climates?', 'MEDIUM', 'Surface currents are wind-driven; thermohaline circulation is driven by density differences from temperature and salinity.', 'Oceanography'),
  ('q-0498', 'earth-science', 'Seismic Waves and Earthquakes', 'Explain how P-waves and S-waves differ in velocity and the media they travel through. Describe how seismologists use the time delay between P and S arrivals to locate an earthquake''s epicenter. What is the Richter scale and how does the moment magnitude scale improve on it?', 'MEDIUM', 'P-waves are faster and travel through both solids and fluids; S-waves are slower and only travel through solids.', 'Seismology'),
  ('q-0499', 'earth-science', 'Isostasy and Mantle Convection', 'Explain the principle of isostasy and how it relates to buoyancy of the lithosphere on the asthenosphere. Describe how post-glacial rebound demonstrates isostatic adjustment. How does isostasy explain the difference in elevation between continents and ocean basins?', 'HARD', 'Thicker, less dense continental crust floats higher than thin, dense oceanic crust on the plastic asthenosphere.', 'Geophysics'),
  ('q-0500', 'earth-science', 'Paleoclimate Proxy Reconstruction', 'Describe three paleoclimate proxies used to reconstruct past climate, such as ice cores, tree rings, and oxygen isotopes in foraminifera. Explain how delta-18-O values indicate past temperature. What limitations and uncertainties affect proxy-based climate reconstructions?', 'HARD', 'Heavier O-18 is preferentially removed from seawater during cold periods, so foraminifera shells record temperature.', 'Paleoclimate'),
  ('q-0501', 'environmental-science', 'Food Chains and Webs', 'Explain the difference between a food chain and a food web. Why do ecologists prefer the food web concept when analyzing the stability and resilience of an ecosystem?', 'EASY', 'Think about trophic levels, energy flow, and what happens when one species is removed.', 'Ecosystems'),
  ('q-0502', 'environmental-science', 'Carrying Capacity Overshoot', 'Define carrying capacity and explain what ecological dynamics occur when a population overshoots it. Why does overshoot frequently lead to a crash rather than a smooth return to equilibrium?', 'EASY', 'Consider lag times, resource depletion, and the difference between r-selected and K-selected species.', 'Population Ecology'),
  ('q-0503', 'environmental-science', 'Natural vs Enhanced Greenhouse Effect', 'Describe the natural greenhouse effect and distinguish it from its anthropogenic enhancement. Which gases matter most and why does the distinction matter for climate policy?', 'EASY', 'Think about radiative forcing, the role of water vapor as a feedback, and the incremental CO2 added by humans.', 'Climate Change'),
  ('q-0504', 'environmental-science', 'Fast and Slow Carbon Cycles', 'Compare the fast biological carbon cycle with the slow geological carbon cycle. Why do human fossil-fuel emissions disproportionately disrupt the balance, and over what timescales can the system re-equilibrate?', 'MEDIUM', 'Consider residence times in atmosphere vs. rocks, and the asymmetry between slow sequestration and rapid release.', 'Biogeochemistry'),
  ('q-0505', 'environmental-science', 'Biodiversity Hotspots Strategy', 'Analyze the concept of biodiversity hotspots. Why are they prioritized for conservation despite covering only a small fraction of Earth''s land surface, and what criticisms have been raised about the hotspot strategy?', 'MEDIUM', 'Think about endemism, threat level, and whether hotspots neglect coldspots of high ecological value.', 'Conservation'),
  ('q-0506', 'environmental-science', 'Tragedy in Fisheries', 'Apply Hardin''s tragedy of the commons to a contemporary fisheries collapse. What institutional responses (state regulation, privatization, co-management) can prevent overuse, and what are the trade-offs of each?', 'MEDIUM', 'Consider Elinor Ostrom''s design principles for common-pool resources as a counterpoint to Hardin.', 'Resource Governance'),
  ('q-0507', 'environmental-science', 'Renewable Energy Trade-offs', 'Compare the environmental and social trade-offs of utility-scale solar, wind, and hydroelectric power. What factors determine which is most appropriate for a given region?', 'MEDIUM', 'Consider land use, intermittency, habitat impact, and life-cycle emissions.', 'Energy Policy'),
  ('q-0508', 'environmental-science', 'Climate Tipping Points', 'Evaluate the concept of climate tipping points using the Amazon rainforest and the Atlantic Meridional Overturning Circulation as examples. Why are tipping points difficult to incorporate into cost-benefit climate models?', 'MEDIUM', 'Think about non-linearity, hysteresis, and deep uncertainty in integrated assessment models.', 'Climate Change'),
  ('q-0509', 'environmental-science', 'Planetary Boundaries Framework', 'Critically evaluate the Rockstrom planetary boundaries framework. Which boundaries are most interconnected, and what are the limitations of treating them as separable thresholds?', 'HARD', 'Consider biosphere integrity, biogeochemical flows, and the critique that boundaries are socially constructed.', 'Earth Systems'),
  ('q-0510', 'environmental-science', 'Environmental Justice Frameworks', 'Analyze why environmental harms disproportionately affect marginalized communities. Propose a policy framework that integrates distributive, procedural, and recognitional justice, and explain why all three dimensions are necessary.', 'HARD', 'Draw on the three-fold justice typology from Schlosberg and consider siting decisions and participation.', 'Environmental Justice'),
  ('q-0511', 'biochemistry', 'Competitive vs Noncompetitive Inhibition', 'Explain how competitive and noncompetitive enzyme inhibitors differ in their effects on Vmax and apparent Km. Why does adding more substrate reverse one type of inhibition but not the other?', 'EASY', 'Consider whether the inhibitor binds the active site or an allosteric site, and the Michaelis-Menten plot.', 'Enzyme Kinetics'),
  ('q-0512', 'biochemistry', 'Levels of Protein Structure', 'Describe the four levels of protein structure (primary through quaternary). Give an example of how a disruption at one level propagates to affect function at another.', 'EASY', 'Think about sickle-cell hemoglobin as a single amino acid change with quaternary consequences.', 'Protein Structure'),
  ('q-0513', 'biochemistry', 'ATP as Energy Currency', 'Why is ATP described as the energy currency of the cell? What property of its phosphoanhydride bonds makes it suited for this role, and why is it not the most energy-dense molecule available?', 'EASY', 'Consider the resonance stabilization of products, the intermediate phosphoryl transfer potential, and coupling.', 'Bioenergetics'),
  ('q-0514', 'biochemistry', 'Glycolysis vs Gluconeogenesis', 'Compare glycolysis and gluconeogenesis. How do cells avoid a futile cycle when both pathways operate, and what is the metabolic cost of running gluconeogenesis?', 'MEDIUM', 'Consider the three bypass enzymes and hormonal regulation by insulin and glucagon.', 'Metabolism'),
  ('q-0515', 'biochemistry', 'Allosteric Regulation of PFK-1', 'Analyze the role of allosteric regulation in metabolic control using phosphofructokinase-1 as an example. What cellular signals does PFK-1 integrate, and why is allosteric rather than covalent regulation advantageous here?', 'MEDIUM', 'Think about ATP, AMP, citrate, and fructose-2,6-bisphosphate as effectors of PFK-1.', 'Metabolic Regulation'),
  ('q-0516', 'biochemistry', 'Bicarbonate Buffer System', 'Apply the Henderson-Hasselbalch equation to explain how the bicarbonate buffer system maintains blood pH near 7.4. Why is this open system more effective than a closed buffer of the same pKa would predict?', 'MEDIUM', 'Consider the role of respiratory CO2 removal and renal bicarbonate reabsorption.', 'Acid-Base Chemistry'),
  ('q-0517', 'biochemistry', 'Membrane Lipid Composition', 'Compare the thermodynamic properties of saturated and unsaturated fatty acids, and explain how their ratio affects membrane fluidity. How do cells homeostatically adjust this ratio in response to temperature?', 'MEDIUM', 'Think about van der Waals packing, the transition temperature, and desaturase enzymes.', 'Lipids'),
  ('q-0518', 'biochemistry', 'NADH vs FADH2 as Electron Carriers', 'Evaluate the role of NAD+/NADH and FAD/FADH2 as electron carriers. Why does the cell use multiple carriers with different reduction potentials rather than a single universal carrier?', 'MEDIUM', 'Consider reduction potential, substrate specificity, and the thermodynamic funneling of electrons.', 'Redox Biochemistry'),
  ('q-0519', 'biochemistry', 'Anfinsen Hypothesis Revisited', 'Critically assess the Anfinsen hypothesis that native protein structure is determined solely by amino acid sequence. What phenomena (molecular chaperones, prions, intrinsically disordered proteins) complicate this view, and does each constitute a genuine refutation?', 'HARD', 'Consider ribonuclease refolding experiments and the distinction between thermodynamic and kinetic control.', 'Protein Folding'),
  ('q-0520', 'biochemistry', 'Uncoupling Oxidative Phosphorylation', 'A drug candidate uncouples oxidative phosphorylation by carrying protons across the inner mitochondrial membrane. Predict its metabolic effects on a hepatocyte, and explain why such compounds are biologically dangerous yet have been explored therapeutically.', 'HARD', 'Think about heat production, respiratory rate, the chemiosmotic gradient, and historical use of dinitrophenol.', 'Bioenergetics'),
  ('q-0521', 'world-history', 'Primary vs Secondary Sources', 'Explain the difference between primary and secondary historical sources. How does a historian weigh them when they conflict, and what makes a source primary in one inquiry but secondary in another?', 'EASY', 'Consider the relationship between the source and the question being asked, not just the source''s age.', 'Historiography'),
  ('q-0522', 'world-history', 'Industrial Revolution Consequences', 'Describe two major social consequences of the Industrial Revolution in 19th-century Europe. How did these changes reshape the relationship between state and society?', 'EASY', 'Think about urbanization, class formation, labor conditions, and the rise of reform movements.', 'Economic History'),
  ('q-0523', 'world-history', 'Silk Road as Conduit', 'Explain how the Silk Road functioned as both an economic and a cultural conduit. Why do some historians argue that its cultural impact outlasted its commercial importance?', 'EASY', 'Consider the transmission of religions, technologies, and pathogens alongside goods.', 'Pre-Modern Eurasia'),
  ('q-0524', 'world-history', 'Great Man vs Longue Duree', 'Compare the great-man theory of history with Braudel''s longue duree approach. What kinds of questions does each frame well, and what kinds of phenomena does each tend to obscure?', 'MEDIUM', 'Consider different time scales: event, conjuncture, and structure in Braudel''s terminology.', 'Historiography'),
  ('q-0525', 'world-history', 'WWII and Decolonization', 'Analyze the role of World War II in accelerating decolonization in Asia and Africa. Which causal mechanisms (economic exhaustion, ideological delegitimization, metropolitan weakness) were most decisive, and how would you weigh them?', 'MEDIUM', 'Consider the Atlantic Charter, Japanese occupation of Southeast Asia, and the bankruptcy of imperial myth.', 'Decolonization'),
  ('q-0526', 'world-history', 'Columbian Exchange Demography', 'Apply the concept of the Columbian Exchange to explain the demographic and ecological transformations of the 16th and 17th centuries. Why did the demographic impact fall so asymmetrically on indigenous populations?', 'MEDIUM', 'Think about virgin-soil epidemics, the exchange of crops and livestock, and the role of forced migration.', 'Global Encounters'),
  ('q-0527', 'world-history', 'Cold War Ideology vs Geopolitics', 'Evaluate the argument that the Cold War was driven primarily by ideology rather than geopolitics. What evidence would support or undermine each interpretation, and can the two be cleanly separated?', 'MEDIUM', 'Consider the Sino-Soviet split, non-aligned movement, and realist accounts of superpower behavior.', 'Cold War'),
  ('q-0528', 'world-history', 'Printing Press and Authority', 'Analyze how the printing press altered religious and political authority in early modern Europe. Did the press cause the Reformation, or did the Reformation create the conditions for the press''s impact?', 'MEDIUM', 'Consider Elizabeth Eisenstein''s arguments about standardization and the causal debate with Adrian Johns.', 'Early Modern Europe'),
  ('q-0529', 'world-history', 'Comparing Three Revolutions', 'Compare the French, Haitian, and Russian revolutions. What does each reveal about the relationship between universalist revolutionary ideology and racial or class hierarchy? Why is Haiti frequently excluded from comparative revolutionary scholarship?', 'HARD', 'Consider the contradictions between universal rights and slavery, and the historiographical marginalization of Haiti.', 'Comparative Revolutions'),
  ('q-0530', 'world-history', 'Climate Proxy Data in History', 'Critically evaluate the use of climate proxy data in explaining historical collapses such as the Late Bronze Age crisis or the Classic Maya decline. What methodological pitfalls do environmental historians face when correlating climate events with social outcomes?', 'HARD', 'Consider chronological resolution, the danger of environmental determinism, and the role of social resilience.', 'Environmental History'),
  ('q-0531', 'philosophy', 'Descartes'' Cogito Argument', 'Explain Descartes'' cogito argument in the Meditations. What exactly does it establish, and what does it not establish? Why has the argument been so influential despite well-known objections?', 'EASY', 'Consider the method of doubt, the evil demon, and the shift from thinking to existing.', 'Epistemology'),
  ('q-0532', 'philosophy', 'Rationalism vs Empiricism', 'Compare the core commitments of rationalism and empiricism about the source of knowledge. Where does Kant''s critical philosophy fit, and why is the simple dichotomy often misleading?', 'EASY', 'Think about innate ideas, the role of sensation, and Kant''s synthesis of a priori forms with empirical content.', 'Epistemology'),
  ('q-0533', 'philosophy', 'Compatibilism vs Libertarianism', 'Define compatibilism and contrast it with libertarian free will. What is the compatibilist''s response to the consequence argument, and is it successful?', 'EASY', 'Consider how compatibilists redefine freedom as acting on one''s reasons without external coercion.', 'Metaphysics'),
  ('q-0534', 'philosophy', 'Kant''s Categorical Imperative', 'Analyze Kant''s categorical imperative, focusing on the formula of humanity and the formula of universal law. How does Kantian moral reasoning differ from consequentialist reasoning, and what dilemmas expose tensions within it?', 'MEDIUM', 'Consider the lying promise example and whether perfect duties can ever conflict.', 'Ethics'),
  ('q-0535', 'philosophy', 'The Gettier Problem', 'Explain the Gettier problem for the justified-true-belief account of knowledge. Why did two short pages reshape 20th-century epistemology, and what are the main strategies for repairing the JTB account?', 'MEDIUM', 'Consider no-false-lema, causal, and reliabilist responses.', 'Epistemology'),
  ('q-0536', 'philosophy', 'Identity Theory vs Functionalism', 'Compare mind-brain identity theory with functionalism. What does functionalism''s commitment to multiple realizability imply about the prospects of artificial minds, and what is the strongest objection to it?', 'MEDIUM', 'Consider Putnam''s argument about octopus and alien pain, and Searle''s Chinese Room as a critique.', 'Philosophy of Mind'),
  ('q-0537', 'philosophy', 'Husserl''s Epoche Method', 'Apply Husserl''s concept of the epoche (bracketing) to a contemporary debate about whether perception is theory-laden. What does phenomenological method reveal that naturalistic psychology might miss?', 'MEDIUM', 'Think about the natural attitude, intentionality, and the difference between noesis and noema.', 'Phenomenology'),
  ('q-0538', 'philosophy', 'Sartre on Freedom', 'Evaluate Sartre''s claim that humans are condemned to be free. What are the strongest objections (determinism, bad faith, social structuration), and how might a Sartrean respond to each?', 'MEDIUM', 'Consider the relationship between facticity and transcendence in Being and Nothingness.', 'Existentialism'),
  ('q-0539', 'philosophy', 'Hegel vs Kierkegaard', 'Compare Hegel''s dialectical system with Kierkegaard''s existential critique of it. Which better captures the relationship between universal reason and individual subjectivity, and where does each overreach?', 'HARD', 'Consider Kierkegaard''s critique of Hegel in Concluding Unscientific Postscript and the role of existence.', '19th Century Philosophy'),
  ('q-0540', 'philosophy', 'Moore''s Open Question', 'Critically assess Moore''s open-question argument and its implications for ethical naturalism. How have naturalists responded, and is the argument as decisive as Moore supposed?', 'HARD', 'Consider the concept of analyticity, Cornell realism, and the response from Boyd and Brink.', 'Metaethics'),
  ('q-0541', 'ethics', 'Act vs Rule Utilitarianism', 'Explain the difference between act and rule utilitarianism. Use a case (such as punishing an innocent person to prevent a riot) to show how the two versions can reach different verdicts.', 'EASY', 'Consider whether the rule, if universally adopted, would maximize utility, and the rule-worship objection.', 'Normative Ethics'),
  ('q-0542', 'ethics', 'Humanity as an End', 'Describe what Kant means by treating humanity as an end in itself. How does this principle ground duties against deception and exploitation, and how does it differ from consequentialist prohibitions?', 'EASY', 'Think about the difference between price and dignity in the Groundwork.', 'Normative Ethics'),
  ('q-0543', 'ethics', 'Aristotle''s Doctrine of the Mean', 'Explain Aristotle''s doctrine of the mean with a concrete example such as courage. Is the doctrine merely relativistic, or does it provide substantive ethical guidance?', 'EASY', 'Consider the mean relative to us, the role of practical wisdom (phronesis), and the agent''s circumstances.', 'Virtue Ethics'),
  ('q-0544', 'ethics', 'Trolley Problem Analysis', 'Analyze the trolley problem and what it reveals about the tension between deontological and consequentialist intuitions. Do thought experiments of this kind illuminate moral reasoning, or do they distort it?', 'MEDIUM', 'Consider the difference between killing and letting die, the footbridge variant, and recent empirical critiques.', 'Normative Ethics'),
  ('q-0545', 'ethics', 'Four Principles in Psychiatric Treatment', 'Apply the four-principles framework (autonomy, beneficence, nonmaleficence, justice) to a case of involuntary psychiatric treatment of a patient who poses a risk to others. Which principles conflict, and how should they be balanced?', 'MEDIUM', 'Think about capacity, the threshold for intervention, and the role of least-restrictive alternative.', 'Bioethics'),
  ('q-0546', 'ethics', 'Nagel on Moral Luck', 'Evaluate Nagel and Williams''s concept of moral luck. Does the existence of luck in outcomes, constitution, and circumstances undermine the fairness of moral responsibility, and if so, what follows?', 'MEDIUM', 'Consider the case of the unlucky driver and the tension between the control principle and our practices.', 'Metaethics'),
  ('q-0547', 'ethics', 'Scanlon vs Rawls Contractualism', 'Compare Scanlon''s contractualism with Rawls''s contractualism grounded in the original position. How do their conceptions of the contracting parties and the source of moral motivation differ?', 'MEDIUM', 'Consider Rawls''s veil of ignorance versus Scanlon''s principle of principles no one could reasonably reject.', 'Normative Ethics'),
  ('q-0548', 'ethics', 'Singer vs Regan on Animals', 'Compare Singer''s utilitarian and Regan''s rights-based approaches to the moral status of nonhuman animals. Where do they converge and diverge, and what practical conclusions follow from each?', 'MEDIUM', 'Consider Singer''s argument from speciesism and Regan''s concept of subject-of-a-life.', 'Animal Ethics'),
  ('q-0549', 'ethics', 'Effective Altruism Assessed', 'Critically evaluate the effective altruism movement. What are its strengths as a moral innovation, and what do critics mean by calling it philosophically austere or politically complacent?', 'HARD', 'Consider GiveWell-style cost-effectiveness analysis and critiques from Wittwer, Berger, and decolonial thinkers.', 'Applied Ethics'),
  ('q-0550', 'ethics', 'Ethics of Autonomous Vehicles', 'Apply two competing ethical frameworks (e.g., utilitarian and Kantian) to the design of autonomous vehicles facing unavoidable crashes. Who should decide how the car acts, and what democratic procedures could legitimate that decision?', 'HARD', 'Consider the trolley-problem literature, the Mercedes lane-keeping controversy, and regulatory legitimacy.', 'Technology Ethics'),
  ('q-0551', 'literature', 'Narrative Point of View', 'Explain how first-person and third-person limited narration shape reader sympathy differently. What kinds of knowledge can each mode make available or withhold, and how does this affect moral judgment of characters?', 'EASY', 'Consider focalization, reliability, and the reader''s access to interior states.', 'Narrative Theory'),
  ('q-0552', 'literature', 'Metaphor and Simile', 'Define metaphor and distinguish it from simile with examples. Why have theorists from Aristotle to Ricoeur treated metaphor as central to thought rather than mere ornament?', 'EASY', 'Consider metaphor as cognitive transfer (epiphora) and Lakoff and Johnson''s conceptual metaphor theory.', 'Poetics'),
  ('q-0553', 'literature', 'Aristotle on Catharsis', 'Describe Aristotle''s concept of catharsis in tragedy. What are the main interpretive options (purgation, purification, clarification), and why does the ambiguity matter?', 'EASY', 'Think about the function of pity and fear in the Poetics and the debate since Bernays.', 'Classical Theory'),
  ('q-0554', 'literature', 'Stream of Consciousness', 'Analyze how stream-of-consciousness technique in Woolf or Joyce conveys interiority in ways traditional narration cannot. What does the technique sacrifice in exchange for psychological immediacy?', 'MEDIUM', 'Consider free indirect discourse, temporal fragmentation, and the loss of stable external plot.', 'Modernism'),
  ('q-0555', 'literature', 'Achebe vs Conrad', 'Compare Achebe''s Things Fall Apart with Conrad''s Heart of Darkness as competing accounts of the colonial encounter. What does Achebe''s critique of Conrad reveal about the politics of canon formation?', 'MEDIUM', 'Consider Achebe''s 1975 lecture ''An Image of Africa'' and the question of who is permitted to narrate.', 'Postcolonial Literature'),
  ('q-0556', 'literature', 'Iser''s Implied Reader', 'Apply Wolfgang Iser''s concept of the implied reader to a short story of your choice. What gaps (Leerstellen) must the reader fill, and how do these gaps structure the experience of meaning?', 'MEDIUM', 'Think about the distinction between the implied reader and real readers, and the role of indeterminacy.', 'Reader Response'),
  ('q-0557', 'literature', 'Magical Realism as Genre', 'Evaluate whether magical realism is a distinct genre or a regional variant of postmodern fiction. What formal and political features distinguish works by Garcia Marquez or Rushdie from European postmodernism?', 'MEDIUM', 'Consider the matter-of-fact tone, decolonial context, and the debate over the term''s usefulness.', 'Genre Theory'),
  ('q-0558', 'literature', 'The Unreliable Narrator', 'Analyze the function of the unreliable narrator in Nabokov''s Lolita or Ishiguro''s Remains of the Day. How does unreliability generate ethical judgment, and what cues allow the reader to detect it?', 'MEDIUM', 'Consider Wayne Booth''s coinage of the term and the difference between misinforming and misreading narrators.', 'Narrative Theory'),
  ('q-0559', 'literature', 'Lukacs vs Jameson', 'Compare the Marxist literary theories of Georg Lukacs and Fredric Jameson. How does each theorize the relationship between narrative form and historical totality, and what does the historical distance between them reveal?', 'HARD', 'Consider Lukacs on the historical novel and Jameson''s ''always historicize'' and the political unconscious.', 'Critical Theory'),
  ('q-0560', 'literature', 'Canon Formation Revisited', 'Critically evaluate the case for and against revising the literary canon to include historically marginalized voices. What principles should guide canon formation, and is the project of a canon itself defensible?', 'HARD', 'Consider Bloom''s Western Canon against the critiques of Guillory, Spivak, and the curriculum reform debates.', 'Critical Theory'),
  ('q-0561', 'linguistics', 'What Is a Phoneme', 'Define a phoneme and explain why it is a mental category rather than a physical sound. How does the concept of the allophone capture the relationship between phonetics and phonology?', 'EASY', 'Consider minimal pairs and complementary distribution in your explanation.', 'Phonology'),
  ('q-0562', 'linguistics', 'Descriptive vs Prescriptive Grammar', 'Distinguish descriptive from prescriptive grammar and explain why modern linguists privilege the former. What social functions does prescriptivism serve even if it lacks scientific validity?', 'EASY', 'Think about standard language ideology, class markers, and the role of education in enforcing norms.', 'Sociolinguistics'),
  ('q-0563', 'linguistics', 'Morpheme vs Syllable', 'Explain the difference between a morpheme and a syllable with examples. Why is the morpheme the central unit of morphological analysis even when it does not coincide with a pronounceable unit?', 'EASY', 'Consider cranberry morphemes and the mismatch between meaning-bearing units and phonological grouping.', 'Morphology'),
  ('q-0564', 'linguistics', 'Universal Grammar Debate', 'Analyze Chomsky''s argument for an innate universal grammar. What evidence (poverty of stimulus, rapid acquisition, creolization) supports it, and what evidence from usage-based and statistical learning theories challenges it?', 'MEDIUM', 'Consider the shift from principles-and-parameters to the Minimalist Program and recent critiques.', 'Language Acquisition'),
  ('q-0565', 'linguistics', 'The Sapir-Whorf Hypothesis', 'Evaluate the strong and weak forms of the Sapir-Whorf hypothesis using evidence from color terminology research (Berlin and Kay, Lucy). What survives of linguistic relativity after the failure of the strong version?', 'MEDIUM', 'Consider the difference between deterministic and probabilistic effects on cognition.', 'Psycholinguistics'),
  ('q-0566', 'linguistics', 'Gricean Conversational Implicature', 'Apply Grice''s conversational maxims to explain how conversational implicature arises when a maxim is deliberately flouted. Provide an example where the speaker means the opposite of what she literally says.', 'MEDIUM', 'Think about the maxim of quality, quantity, relation, and manner, and the cooperative principle.', 'Pragmatics'),
  ('q-0567', 'linguistics', 'Diglossia vs Code Switching', 'Compare diglossia and code-switching as sociolinguistic phenomena. What social functions does each serve, and what does the distinction reveal about the relationship between language and power?', 'MEDIUM', 'Consider Ferguson''s classic treatment of diglossia and Myers-Scotton''s markedness model.', 'Sociolinguistics'),
  ('q-0568', 'linguistics', 'Great Vowel Shift', 'Analyze how the Great Vowel Shift illustrates regular sound change. Why is the regularity of sound change important for the comparative method, and what are the main exceptions to regularity?', 'MEDIUM', 'Consider the Neogrammarian hypothesis and the role of analogy as a counterforce to regular change.', 'Historical Linguistics'),
  ('q-0569', 'linguistics', 'Poverty of Stimulus Assessed', 'Critically assess the poverty of the stimulus argument. What alternative accounts (usage-based, statistical learning, Bayesian induction) have been proposed, and how compelling are they as refutations of the original argument?', 'HARD', 'Consider Pullum and Scholz''s critique and the empirical work on child-directed speech by Lieven and Tomasello.', 'Language Acquisition'),
  ('q-0570', 'linguistics', 'Speech Act Theory', 'Compare Austin''s speech act theory with Searle''s systematic development of it. Apply the framework to analyze how performatives function in legal or institutional contexts, and identify the limits of the analysis.', 'HARD', 'Consider locutionary, illocutionary, and perlocutionary acts, and felicity conditions.', 'Pragmatics'),
  ('q-0571', 'sociology', 'Durkheim on Anomie', 'Explain Durkheim''s concept of anomie and how it relates to social regulation. Why did Durkheim see anomie as a pathological state rather than a simple absence of rules?', 'EASY', 'Consider Suicide as the empirical anchor and the link to the division of labor.', 'Classical Theory'),
  ('q-0572', 'sociology', 'Primary vs Secondary Socialization', 'Describe the difference between primary and secondary socialization (Berger and Luckmann). What makes primary socialization so much harder to undo, and what does this imply for adult identity change?', 'EASY', 'Think about significant others, emotional attachment, and the taken-for-granted reality of childhood.', 'Socialization'),
  ('q-0573', 'sociology', 'Weber on Class, Status, Party', 'Define Weber''s distinction between class, status, and party as dimensions of stratification. Why is this three-fold scheme more analytically powerful than a purely economic account of inequality?', 'EASY', 'Consider how status honor and political power can diverge from economic position.', 'Stratification'),
  ('q-0574', 'sociology', 'Bourdieu on Cultural Capital', 'Analyze Bourdieu''s concept of cultural capital. How does it reproduce inequality across generations, and what makes it more effective than economic capital alone at legitimating class position?', 'MEDIUM', 'Consider embodied, objectified, and institutionalized states of cultural capital, and misrecognition.', 'Stratification'),
  ('q-0575', 'sociology', 'Marx vs Weber on Class', 'Compare Marx''s and Weber''s theories of class. Where does Weber''s multidimensional approach improve on Marx, and where does Weber''s framework lose the explanatory power of Marx''s structural account of capitalism?', 'MEDIUM', 'Consider market situation, life chances, and the relationship between class consciousness and class-in-itself.', 'Classical Theory'),
  ('q-0576', 'sociology', 'Goffman''s Dramaturgy at Work', 'Apply Goffman''s dramaturgical analysis to a workplace setting. What does the distinction between front-stage and back-stage behavior reveal about organizational life, and what are the limits of the metaphor?', 'MEDIUM', 'Consider impression management, props, and the audience, as well as critiques of Goffman''s cynicism.', 'Symbolic Interactionism'),
  ('q-0577', 'sociology', 'Education and Mobility', 'Evaluate the claim that education is the great equalizer in light of evidence on intergenerational mobility. Which mechanisms produce the gap between the ideal and observed outcomes?', 'MEDIUM', 'Consider credentialism, tracking, and Bourdieu''s cultural reproduction, plus cross-national variation.', 'Social Mobility'),
  ('q-0578', 'sociology', 'Foucault on Disciplinary Power', 'Analyze Foucault''s concept of disciplinary power using the prison or the school as an example. How does disciplinary power differ from sovereign power, and what are the implications for the modern subject?', 'MEDIUM', 'Consider panopticism, normalization, and the production of docile bodies in Discipline and Punish.', 'Social Theory'),
  ('q-0579', 'sociology', 'Giddens vs Bourdieu on Agency', 'Critically compare Giddens''s structuration theory with Bourdieu''s theory of practice. Which better resolves the structure-agency problem, and what does each leave unresolved?', 'HARD', 'Consider the duality of structure, habitus and field, and the role of practical consciousness.', 'Social Theory'),
  ('q-0580', 'sociology', 'Race and Colorblind Policy', 'Apply the social constructionist account of race to analyze colorblind policy. What does the empirical evidence say about whether ignoring race reduces racial inequality, and what alternative frameworks have sociologists proposed?', 'HARD', 'Consider Bonilla-Silva''s colorblind racism, structural racism, and the limits of formal equality.', 'Race and Ethnicity'),
  ('q-0581', 'psychology', 'Classical Conditioning Defined', 'Explain Pavlovian conditioning using the terms CS, UCS, CR, and UCR. How does the timing and reliability of CS-UCS pairing determine the strength and form of conditioning?', 'EASY', 'Consider the Rescorla-Wagner model''s emphasis on predictiveness rather than mere contiguity.', 'Behavioral'),
  ('q-0582', 'psychology', 'Working vs Long-Term Memory', 'Describe the difference between working memory and long-term memory, including the subsystems proposed by Baddeley. Why is the capacity of working memory so limited, and how does it interact with long-term storage?', 'EASY', 'Consider the phonological loop, visuospatial sketchpad, central executive, and chunking.', 'Cognitive'),
  ('q-0583', 'psychology', 'Festinger on Cognitive Dissonance', 'Define cognitive dissonance and give an everyday example. How does Festinger''s theory explain seemingly irrational belief persistence, and what are the main alternative explanations for the same phenomena?', 'EASY', 'Consider the insufficient-justification paradigm and self-perception theory as a rival account.', 'Social'),
  ('q-0584', 'psychology', 'Piaget vs Vygotsky', 'Compare Piaget''s and Vygotsky''s theories of cognitive development, especially the role of social interaction and language. Where do the theories genuinely conflict and where do they complement each other?', 'MEDIUM', 'Consider stages versus zones of proximal development, and egocentric speech versus inner speech.', 'Developmental'),
  ('q-0585', 'psychology', 'Bowlby''s Attachment Theory', 'Analyze Bowlby''s attachment theory and the contribution of Ainsworth''s Strange Situation procedure. What are the strengths and limitations of inferring adult attachment patterns from infant behavior?', 'MEDIUM', 'Consider secure, anxious-ambivalent, and avoidant patterns, and the critiques by Main and others.', 'Developmental'),
  ('q-0586', 'psychology', 'Heuristics in Policy', 'Apply Kahneman and Tversky''s work on heuristics and biases to a public policy decision involving risk perception (such as vaccination or nuclear power). What interventions could mitigate bias without abandoning lay judgment?', 'MEDIUM', 'Consider availability, representativeness, framing, and the nudging versus boosting debate.', 'Cognitive'),
  ('q-0587', 'psychology', 'Social Identity and Conflict', 'Evaluate Tajfel''s social identity theory as an explanation of intergroup conflict. What can it explain (minimal group effects, ingroup favoritism) and what does it struggle to account for (extreme violence, identity change)?', 'MEDIUM', 'Consider self-categorization theory as an extension and the role of relative deprivation.', 'Social'),
  ('q-0588', 'psychology', 'Positive vs Negative Reinforcement', 'Compare positive and negative reinforcement, and explain why the distinction matters for behavior modification. What common confusions (especially with punishment) does this terminology invite?', 'MEDIUM', 'Consider the four-quadrant operant conditioning table and the ethical issues in aversive control.', 'Behavioral'),
  ('q-0589', 'psychology', 'Replication Crisis Causes', 'Critically assess the causes of psychology''s replication crisis (publication bias, p-hacking, small samples, questionably flexible analyses). Which methodological reforms (preregistration, large-scale replications, Bayesian inference) are most promising, and what are their limits?', 'HARD', 'Consider the Open Science Collaboration 2015 findings and the debate about effect sizes versus significance.', 'Research Methods'),
  ('q-0590', 'psychology', 'Modularity vs Predictive Processing', 'Compare Fodor''s modularity of mind with connectionist and predictive processing accounts of cognition. Which framework best accounts for flexible higher cognition, and what evidence would distinguish them?', 'HARD', 'Consider Fodor''s isolation and encapsulation criteria, and Clark''s predictive coding model.', 'Cognitive Neuroscience'),
  ('q-0591', 'political-science', 'Procedural vs Substantive Democracy', 'Define democracy and distinguish procedural from substantive conceptions. Why has the minimalist Schumpeterian definition been so influential, and what does it leave out?', 'EASY', 'Consider Dahl''s polyarchy criteria and the debate over whether elections are sufficient.', 'Democratic Theory'),
  ('q-0592', 'political-science', 'Sovereignty Under Globalization', 'Explain the concept of state sovereignty and how it is challenged by globalization. Which dimensions of sovereignty (internal, external, Westphalian) are most affected, and which remain robust?', 'EASY', 'Consider Stephen Krasner''s typology of sovereignty and the role of international institutions.', 'International Relations'),
  ('q-0593', 'political-science', 'Separation of Powers', 'Describe the rationale for separating legislative, executive, and judicial powers. How did Madison''s argument in Federalist 51 envision the system of checks and balances, and what pathologies does separation of powers create?', 'EASY', 'Consider ambition counteracting ambition, and the risk of gridlock or democratic backsliding.', 'Political Theory'),
  ('q-0594', 'political-science', 'Rawls'' Veil of Ignorance', 'Analyze Rawls''s veil of ignorance and how it generates the two principles of justice. What are the main libertarian objections (Nozick, Hayek), and how successfully does Rawls respond to them?', 'MEDIUM', 'Consider the difference principle, the liberty principle''s lexical priority, and the entitlement theory.', 'Political Theory'),
  ('q-0595', 'political-science', 'Realism vs Liberalism in IR', 'Compare realist and liberal theories of international relations. What predictions does each make about cooperation under anarchy, and how does each interpret the durability of institutions such as NATO?', 'MEDIUM', 'Consider Waltz''s structural realism versus Keohane and Nye''s complex interdependence.', 'International Relations'),
  ('q-0596', 'political-science', 'Dual vs Cooperative Federalism', 'Apply the distinction between dual and cooperative federalism to a contemporary policy dispute such as healthcare or immigration. How has the balance shifted historically, and what constitutional and political forces drive the shift?', 'MEDIUM', 'Consider the commerce clause, the New Deal transformation, and the devolution debates of the 1990s.', 'Federalism'),
  ('q-0597', 'political-science', 'Electoral Systems Compared', 'Evaluate the effects of plurality (first-past-the-post) versus proportional representation on party systems and governance. What does Duverger''s law predict, and what exceptions and qualifications matter?', 'MEDIUM', 'Consider the mechanical and psychological effects, and the role of district magnitude.', 'Electoral Systems'),
  ('q-0598', 'political-science', 'Theories of Democratization', 'Compare modernization theory with the bureaucratic-authoritarian and transitologist critiques of it. What does each explain well, and what does the fourth wave of autocratization reveal about the limits of all three?', 'MEDIUM', 'Consider Lipset, O''Donnell, and O''Donnell-Schmitter, plus Levitsky and Ziblatt on contemporary decline.', 'Democratization'),
  ('q-0599', 'political-science', 'Habermas on Deliberative Democracy', 'Critically evaluate Habermas''s model of deliberative democracy. What empirical conditions (equality, absence of coercive power, rational discourse) must hold for it to work, and how realistic are they in contemporary democracies?', 'HARD', 'Consider the ideal speech situation, the public sphere, and empirical work by Fishkin and others.', 'Democratic Theory'),
  ('q-0600', 'political-science', 'Three Faces of Power', 'Compare the three faces of power framework (Dahl, Bachrach and Baratz, Lukes). Apply it to analyze why a policy option (such as single-payer healthcare or carbon taxation) may never appear on the political agenda.', 'HARD', 'Consider decision-making, non-decision-making, and the shaping of wants, plus later feminist critiques.', 'Power Theory'),
  ('q-0601', 'economics', 'Supply and Demand', 'Explain the law of supply and demand and how equilibrium price is determined in a competitive market. What happens to price and quantity when demand shifts rightward while supply remains constant? Illustrate with a brief example from a market you know.', 'EASY', 'Start with the intersection of the supply and demand curves and think about what shifts each.', 'Supply/Demand'),
  ('q-0602', 'economics', 'Opportunity Cost', 'Define opportunity cost and explain why it is central to economic decision-making. Give an example of a trade-off a government might face when allocating a fixed budget between two programs. Why do economists say there is no such thing as a free lunch?', 'EASY', 'Consider what is given up whenever a resource is committed to one use rather than another.', 'Opportunity Cost'),
  ('q-0603', 'economics', 'Gross Domestic Product', 'What does GDP measure and what are the three main approaches to calculating it? Identify two limitations of GDP as a measure of a country''s well-being. Why might GDP growth not translate to improved living standards for all citizens?', 'EASY', 'GDP tracks market production, not distribution, leisure, or non-market activity.', 'National Accounts'),
  ('q-0604', 'economics', 'Price Elasticity', 'Explain price elasticity of demand and how it is calculated. Compare the elasticity of demand for insulin versus luxury watches, and discuss how this affects pricing strategy. How would a firm use elasticity estimates when setting prices during a recession?', 'MEDIUM', 'Elasticity depends on availability of substitutes, necessity, and share of income.', 'Elasticity'),
  ('q-0605', 'economics', 'Monetary vs Fiscal Policy', 'Compare monetary and fiscal policy as tools for managing a recession. Describe the key actors, instruments, and typical lag times for each. In what circumstances might one be preferred over the other, and what are the risks of using both aggressively at once?', 'MEDIUM', 'Think about who controls each lever, how fast it acts, and the risk of crowding out or inflation.', 'Macro Policy'),
  ('q-0606', 'economics', 'Comparative Advantage', 'Explain the principle of comparative advantage and how it differs from absolute advantage. Use a two-country, two-good numerical example to show that trade can benefit both parties even when one is more productive in both goods. What real-world factors might prevent these gains from being fully realized?', 'MEDIUM', 'Focus on opportunity cost ratios rather than absolute productivity levels.', 'Trade'),
  ('q-0607', 'economics', 'Market Structures', 'Describe the four main market structures (perfect competition, monopolistic competition, oligopoly, monopoly) and the key features that distinguish them. For each, give an example industry and discuss the firm''s pricing power. How do barriers to entry shape long-run outcomes in each structure?', 'MEDIUM', 'Barriers to entry and product differentiation are the key distinguishing dimensions.', 'Market Structure'),
  ('q-0608', 'economics', 'Inflation Causes', 'Distinguish between demand-pull and cost-push inflation, including their typical causes and policy responses. Why is deflation also a concern for central bankers, not just high inflation? How would you diagnose which type of inflation an economy is experiencing from macroeconomic data?', 'MEDIUM', 'Look at whether output is above or below potential and whether wages or supply shocks are driving prices.', 'Inflation'),
  ('q-0609', 'economics', 'Nash Equilibrium', 'Explain the concept of Nash equilibrium using the prisoner''s dilemma as your example. Why can individually rational choices lead to collectively poor outcomes, and what mechanisms can help firms escape such equilibria? Apply this reasoning to a duopoly deciding whether to advertise heavily or lightly.', 'HARD', 'Each player''s strategy is optimal given the other''s strategy, but the joint outcome may be Pareto inferior.', 'Game Theory'),
  ('q-0610', 'economics', 'Externalities and Public Goods', 'Define a negative externality and explain why competitive markets overproduce goods that generate them. Compare Pigouvian taxes, cap-and-trade, and direct regulation as corrective instruments, including their efficiency and distributional effects. How would you decide which instrument to use for carbon emissions versus traffic congestion?', 'HARD', 'Internalize the externality by aligning private marginal cost with social marginal cost.', 'Externalities'),
  ('q-0611', 'art-history', 'Renaissance Characteristics', 'What were the defining characteristics of Italian Renaissance art, and how did they differ from medieval precedents? Mention two innovations in technique or subject matter that emerged during this period. Why is Florence often cited as the birthplace of the Renaissance?', 'EASY', 'Think about humanism, linear perspective, and patronage by wealthy merchant families.', 'Renaissance'),
  ('q-0612', 'art-history', 'Impressionism Overview', 'Describe the key visual characteristics of Impressionist painting and the historical context in which it emerged. Which earlier movements or technologies (such as photography) influenced the Impressionists? Name two artists associated with the movement and what subjects they typically painted.', 'EASY', 'Consider plein air painting, broken brushwork, and the capture of fleeting light.', 'Impressionism'),
  ('q-0613', 'art-history', 'Cubism Overview', 'What is Cubism and which two artists are credited with developing it? Describe how Cubist works break from traditional Renaissance perspective and what they aim to represent. Distinguish between Analytic and Synthetic Cubism in one or two sentences.', 'EASY', 'Cubism fragments objects into facets and shows multiple viewpoints simultaneously.', 'Cubism'),
  ('q-0614', 'art-history', 'Baroque vs Rococo', 'Compare Baroque and Rococo art in terms of subject matter, style, and the political or social contexts that produced them. Which visual techniques did Baroque painters use to create drama, and how did Rococo artists respond to or reject them? Give one representative artist for each style.', 'MEDIUM', 'Baroque drama and grandeur contrast with Rococo lightness, pastel palette, and aristocratic leisure.', 'Baroque'),
  ('q-0615', 'art-history', 'Linear Perspective', 'Explain the system of linear perspective developed in the early Renaissance and why it was revolutionary. How does one-point perspective differ from two-point and atmospheric perspective? Analyze how a specific work, such as Masaccio''s Trinity, uses perspective to structure meaning.', 'MEDIUM', 'Linear perspective uses a vanishing point and orthogonals to create the illusion of depth on a flat surface.', 'Perspective'),
  ('q-0616', 'art-history', 'Greek vs Roman Architecture', 'Compare Greek and Roman approaches to architecture, focusing on column orders, building materials, and structural innovations. What did the Romans borrow from the Greeks, and what new engineering techniques (such as the arch and concrete) did they introduce? Give an example of a building that synthesizes both traditions.', 'MEDIUM', 'The Romans added the arch, vault, dome, and concrete to the Greek orders and post-and-lintel system.', 'Architecture'),
  ('q-0617', 'art-history', 'Romanticism vs Realism', 'Contrast Romanticism and Realism as 19th-century movements in terms of subject matter, political leanings, and stylistic priorities. How did each movement respond to the Industrial Revolution and to Enlightenment rationality? Discuss one painting from each movement to illustrate the contrast.', 'MEDIUM', 'Romanticism emphasized emotion and the sublime; Realism sought to depict ordinary modern life truthfully.', '19th Century'),
  ('q-0618', 'art-history', 'Color and Symbolism', 'How do artists use color theory and symbolic imagery to communicate meaning beyond the literal subject? Compare the use of color in a Renaissance altarpiece with a Post-Impressionist work such as Van Gogh''s. What role does cultural context play in interpreting symbolic elements?', 'MEDIUM', 'Color can carry iconographic, emotional, and formal functions that vary by period and culture.', 'Visual Analysis'),
  ('q-0619', 'art-history', 'Formal Analysis', 'Conduct a formal analysis of a painting of your choice, addressing composition, line, color, light, and texture. How do these formal elements work together to produce emotional and thematic effects? What would be lost in a purely iconographic reading that ignores form?', 'HARD', 'Describe what you see before what it means; let the visual structure carry the argument.', 'Formal Analysis'),
  ('q-0620', 'art-history', 'Postmodern Critique', 'Explain how postmodern artists challenged modernist assumptions about originality, authorship, and progress. Discuss appropriation, pastiche, and the breakdown of high and low culture distinctions using two specific artworks. What critical theories underpinned these strategies, and what are their limits?', 'HARD', 'Think about how artists like Sherrie Levine or Richard Prince question authorship through copying.', 'Postmodern'),
  ('q-0621', 'project-management', 'Agile vs Waterfall', 'Compare Agile and Waterfall project management methodologies. For each, describe the project type, team structure, and risk profile where it excels. When would you choose a hybrid approach, and what would that look like in practice?', 'EASY', 'Think about uncertainty, customer involvement, and how requirements evolve over time.', 'Methodology'),
  ('q-0622', 'project-management', 'Critical Path Method', 'Define the critical path in a project schedule and explain why it determines the shortest possible project duration. What happens to the project end date if a critical-path task is delayed by one week? How can a project manager use float on non-critical tasks to manage risk?', 'EASY', 'Only tasks with zero float lie on the critical path; everything else has slack.', 'Scheduling'),
  ('q-0623', 'project-management', 'Stakeholder Management', 'Identify the typical stakeholders in a software implementation project and their likely interests. How would you prioritize communication with each group using a stakeholder mapping framework? Give an example of a stakeholder conflict and how you would resolve it.', 'EASY', 'Use a power-and-interest grid to decide who to manage closely versus keep informed.', 'Communication'),
  ('q-0624', 'project-management', 'Risk Management Process', 'Walk through a structured risk management process from identification through monitoring. Distinguish between mitigating, transferring, accepting, and avoiding a risk, with one example of each. How do you decide how much effort to spend managing a low-probability, high-impact risk?', 'MEDIUM', 'Rank risks by probability times impact, then match response strategy to the residual exposure.', 'Risk'),
  ('q-0625', 'project-management', 'Controlling Scope Creep', 'What is scope creep, and what are its most common causes on software projects? Describe three techniques a project manager can use to control scope without alienating stakeholders. How should a PM handle a change request from a senior sponsor late in the project?', 'MEDIUM', 'A documented change control process and a clear baseline make trade-offs explicit.', 'Scope'),
  ('q-0626', 'project-management', 'Resource Leveling', 'Explain the difference between resource leveling and resource smoothing in project scheduling. When would you use each, and what trade-offs do they create for the project timeline? Describe a scenario where over-allocated resources force a re-baselining of the schedule.', 'MEDIUM', 'Leveling can extend the critical path; smoothing only adjusts within existing float.', 'Resources'),
  ('q-0627', 'project-management', 'Earned Value Management', 'Explain the three core metrics of Earned Value Management: Planned Value, Earned Value, and Actual Cost. Show how Schedule Variance and Cost Variance are derived and what each tells the project manager. What corrective action would you take if both variances were negative at month four?', 'MEDIUM', 'EV measures work performed in budget terms; compare it against PV and AC to find variances.', 'Metrics'),
  ('q-0628', 'project-management', 'Sprint Planning', 'Describe how a Scrum team should plan a sprint, including the inputs, participants, and outputs of sprint planning. How does the team decide how much work to commit to, and what role does velocity play? What would you do if mid-sprint the team realized it had overcommitted?', 'MEDIUM', 'Negotiate scope within the sprint rather than extending time or compromising quality.', 'Scrum'),
  ('q-0629', 'project-management', 'Recovering a Failing Project', 'A project you have taken over is six months behind schedule, over budget, and the team morale is low. Outline a structured recovery plan covering scope, schedule, team, and stakeholder communication. How would you decide whether to push for recovery versus recommend cancellation?', 'HARD', 'Triage by re-baselining scope, validating the business case, and rebuilding trust with quick wins.', 'Recovery'),
  ('q-0630', 'project-management', 'Hybrid Governance Model', 'Design a governance model for a large program that combines Waterfall at the portfolio level with Agile delivery teams. How will scope, budget, and dependencies be managed across the boundary? What reporting artifacts satisfy both executive steering committees and Agile teams?', 'HARD', 'Use rolling-wave planning and a backlog-based scope contract to bridge fixed budgets with iterative delivery.', 'Governance'),
  ('q-0631', 'product-management', 'Product Vision', 'What is a product vision and why is it important for aligning cross-functional teams? Draft a one-sentence vision for a fictional productivity app aimed at remote workers. How would you test whether the vision is resonating with the team six months later?', 'EASY', 'A strong vision is concise, aspirational, and connects user outcomes to business outcomes.', 'Vision'),
  ('q-0632', 'product-management', 'Minimum Viable Product', 'Define a Minimum Viable Product and explain its purpose in the product development cycle. What are the risks of shipping too much versus too little in an MVP? Describe how you would decide which features to cut from a first release.', 'EASY', 'An MVP tests the riskiest assumption with the least effort, not a stripped-down final product.', 'MVP'),
  ('q-0633', 'product-management', 'Product KPIs', 'List five KPIs a product manager might track for a consumer mobile app and explain what each reveals. Distinguish between vanity metrics and actionable metrics with an example. How would you choose a North Star metric for the app?', 'EASY', 'A North Star metric captures core value delivered to users and correlates with long-term revenue.', 'Metrics'),
  ('q-0634', 'product-management', 'Prioritization Frameworks', 'Compare RICE, MoSCoW, and Kano as prioritization frameworks for a feature backlog. For each, describe the inputs required and the type of decision it best supports. When would prioritization by customer ask volume be the wrong approach?', 'MEDIUM', 'Each framework optimizes for something different: effort-impact, necessity, or delight.', 'Prioritization'),
  ('q-0635', 'product-management', 'Roadmap Planning', 'Explain the purpose of a product roadmap and how it differs from a release plan or a backlog. How do you balance committed deliverables with discovery work when communicating to executives? Describe how you would adjust the roadmap after a major competitor launch.', 'MEDIUM', 'Roadmaps communicate strategy and sequencing, not fixed feature deadlines.', 'Roadmapping'),
  ('q-0636', 'product-management', 'Product-Market Fit', 'Define product-market fit and describe how you would measure it quantitatively and qualitatively. What signals indicate that a product has NOT yet achieved product-market fit? Outline a discovery plan to find it when early metrics are ambiguous.', 'MEDIUM', 'The Sean Ellis test, retention curves, and organic growth all indicate PMF.', 'Product-Market Fit'),
  ('q-0637', 'product-management', 'User Research Methods', 'Compare generative and evaluative user research methods, giving two examples of each. When in the product lifecycle is each most valuable, and what pitfalls should a PM avoid when interpreting findings? How do you reconcile conflicting signals from quantitative analytics and qualitative interviews?', 'MEDIUM', 'Generative research explores problems; evaluative research tests solutions.', 'Research'),
  ('q-0638', 'product-management', 'Go-to-Market Strategy', 'Outline the components of a go-to-market plan for launching a B2B SaaS feature to existing customers. How do you coordinate product, sales, marketing, and customer success to maximize adoption? What leading indicators would tell you in the first 30 days whether the launch is working?', 'MEDIUM', 'A GTM plan aligns audience, positioning, channels, pricing, and enablement around a launch goal.', 'GTM'),
  ('q-0639', 'product-management', 'Cannibalization Strategy', 'You are launching a lower-priced product that may cannibalize your premium offering. Describe a framework for evaluating whether cannibalization is acceptable. How would you segment customers to minimize unwanted switching, and what metrics would you track post-launch?', 'HARD', 'Net incremental revenue and customer lifetime value matter more than gross cannibalization.', 'Cannibalization'),
  ('q-0640', 'product-management', 'Pricing Strategy Trade-offs', 'Compare value-based, cost-plus, and competitive pricing strategies for a new enterprise software product. How does the choice interact with packaging, tiering, and freemium offers? Walk through how you would set the initial price and iterate based on early customer data.', 'HARD', 'Anchor on willingness to pay, then use packaging and tiering to capture different segments.', 'Pricing'),
  ('q-0641', 'marketing', 'Four Ps of Marketing', 'Define the Four Ps of the marketing mix and give an example of each for a consumer packaged good. How do the Four Ps need to shift when marketing a digital service instead? Why do modern marketers sometimes argue for a customer-centric 4 Cs framework?', 'EASY', 'Product, Price, Place, Promotion map roughly to Customer, Cost, Convenience, Communication.', 'Fundamentals'),
  ('q-0642', 'marketing', 'Brand Positioning', 'Explain what brand positioning means and why a positioning statement is useful. Draft a positioning statement for a fictional sustainable footwear brand in one sentence. How would you test whether the intended positioning is landing with target customers?', 'EASY', 'A positioning statement specifies target, category, point of difference, and reason to believe.', 'Branding'),
  ('q-0643', 'marketing', 'Market Segmentation', 'Describe the main bases for segmenting a consumer market (demographic, geographic, psychographic, behavioral). Which basis is most useful for a streaming music service, and why? Give an example of how segmentation informs media buying decisions.', 'EASY', 'Behavioral segments like listening frequency and genre preference drive both product and media strategy.', 'Strategy'),
  ('q-0644', 'marketing', 'Marketing Funnel', 'Walk through a standard marketing funnel (awareness, consideration, conversion, loyalty) and the metrics used at each stage. Where do most B2B funnels leak, and what tactics can address the leak? How does the funnel concept change in an age of non-linear customer journeys?', 'MEDIUM', 'Identify the stage with the biggest drop-off relative to its input before optimizing anywhere else.', 'Funnel'),
  ('q-0645', 'marketing', 'A/B Testing Design', 'Explain how to design a valid A/B test for a website call-to-action, including hypothesis, sample size, and stopping rule. What are common pitfalls such as peeking and multiple comparisons, and how do you avoid them? How would you decide between conflicting qualitative and quantitative results?', 'MEDIUM', 'Power analysis sets sample size, and pre-registration of one primary metric prevents false positives.', 'Experimentation'),
  ('q-0646', 'marketing', 'Customer Journey Mapping', 'What is a customer journey map and what components should it include? Describe how a journey map can reveal unmet needs that traditional analytics dashboards miss. How would you operationalize findings from a journey map into prioritized roadmap items?', 'MEDIUM', 'Layer emotions, touchpoints, and pain points across stages to find moments of truth.', 'CX'),
  ('q-0647', 'marketing', 'Content Marketing Metrics', 'Identify five metrics for evaluating a content marketing program and what each indicates. How do you balance engagement metrics (such as time on page) with business metrics (such as qualified leads)? Describe a scenario where high engagement is actually a warning sign.', 'MEDIUM', 'Tie content metrics to funnel stages and watch for engagement without progression.', 'Content'),
  ('q-0648', 'marketing', 'SEO vs SEM', 'Compare SEO and SEM in terms of cost structure, time to results, and strategic role in the marketing mix. When would a startup with limited budget prioritize one over the other? How should you measure the combined ROI of paid and organic search working together?', 'MEDIUM', 'SEM buys immediate traffic and learning; SEO compounds an asset that pays off over time.', 'Channels'),
  ('q-0649', 'marketing', 'Multi-Channel Attribution', 'Compare first-touch, last-touch, linear, and time-decay attribution models for a multi-channel campaign. What biases does each introduce, and when is a data-driven attribution model worth the investment? How would you communicate attribution uncertainty to a CFO demanding a single ROI number?', 'HARD', 'Each model credits touchpoints differently; combine incrementality testing with attribution to bound the truth.', 'Analytics'),
  ('q-0650', 'marketing', 'Brand Repositioning', 'Describe the strategic challenges of repositioning an established brand whose core audience is aging. What research inputs would inform the new positioning, and how would you mitigate the risk of alienating loyal customers? Outline a 12-month plan including messaging, channel, and measurement milestones.', 'HARD', 'Bridge from existing brand equity to new meaning rather than replacing it wholesale.', 'Repositioning'),
  ('q-0651', 'finance', 'Discounted Cash Flow', 'Explain the concept of discounted cash flow valuation and why future cash flows are discounted. What role does the discount rate play, and how does it reflect risk? Walk through the inputs you would need to build a simple DCF for a small business.', 'EASY', 'A dollar today is worth more than a dollar tomorrow because of time value and risk.', 'Valuation'),
  ('q-0652', 'finance', 'Weighted Average Cost of Capital', 'Define the Weighted Average Cost of Capital and explain how it is calculated. Why do debt and equity have different costs, and how do taxes affect the cost of debt? When would a company use WACC as a hurdle rate for new projects?', 'EASY', 'WACC weights the after-tax cost of debt and the cost of equity by their market value shares.', 'Cost of Capital'),
  ('q-0653', 'finance', 'Balance Sheet Basics', 'Describe the three sections of a balance sheet and how they relate through the accounting equation. Give an example of a transaction that affects two sections simultaneously. Why is the balance sheet considered a snapshot rather than a flow statement?', 'EASY', 'Assets equal liabilities plus equity at a single point in time, unlike the income statement.', 'Financial Statements'),
  ('q-0654', 'finance', 'Capital Asset Pricing Model', 'Explain the Capital Asset Pricing Model and what each component of the formula represents. How is beta estimated, and what are the limitations of using historical beta for forward-looking decisions? Describe how CAPM is used to set the cost of equity in a WACC calculation.', 'MEDIUM', 'CAPM relates expected return to systematic risk measured by beta relative to the market.', 'Asset Pricing'),
  ('q-0655', 'finance', 'Capital Structure Theories', 'Compare the trade-off theory and pecking order theory of capital structure. How does each explain a firm''s choice between debt and equity financing? What practical implications does each theory have for a CFO setting long-term leverage targets?', 'MEDIUM', 'Trade-off theory balances tax shields against distress costs; pecking order follows information asymmetry.', 'Capital Structure'),
  ('q-0656', 'finance', 'Financial Ratio Analysis', 'Group key financial ratios into liquidity, profitability, leverage, and efficiency categories, with one example each. How would you use DuPont analysis to decompose return on equity? Describe a scenario where improving one ratio deteriorates another.', 'MEDIUM', 'DuPont splits ROE into margin, asset turnover, and leverage to isolate drivers.', 'Analysis'),
  ('q-0657', 'finance', 'Working Capital Management', 'Define working capital and the cash conversion cycle, and explain why each matters for operations. What levers can a company pull to shorten its cash conversion cycle? Identify one risk of aggressively reducing working capital.', 'MEDIUM', 'Days inventory plus days receivable minus days payable equals the cash conversion cycle.', 'Working Capital'),
  ('q-0658', 'finance', 'M&A Valuation Methods', 'Compare comparable company analysis, precedent transactions, and DCF as valuation methods for an acquisition target. What are the strengths and weaknesses of each, and when would one be more reliable? How do control premiums and synergies factor into the offer price?', 'MEDIUM', 'Triangulate across methods; precedents capture control premiums, comps reflect market sentiment.', 'M&A'),
  ('q-0659', 'finance', 'Leveraged Buyout Modeling', 'Walk through the structure of a leveraged buyout model, including sources and uses, debt schedule, and returns calculation. What assumptions most drive the IRR in an LBO, and how do sponsors use operational improvements to create value? Describe how a rising rate environment changes the LBO thesis.', 'HARD', 'Returns come from leverage, multiple expansion, EBITDA growth, and debt paydown.', 'LBO'),
  ('q-0660', 'finance', 'Real Options Valuation', 'Explain how real options analysis applies financial option theory to capital budgeting decisions. Compare the option to expand, the option to abandon, and the option to delay, with one example each. When is real options analysis preferable to standard NPV, and what are its practical limitations?', 'HARD', 'Real options value managerial flexibility that NPV treats as fixed decisions.', 'Real Options'),
  ('q-0661', 'ux-design', 'UX vs UI Distinction', 'Distinguish between user experience (UX) and user interface (UI) design, including the typical deliverables each produces. Where do the two disciplines overlap, and why is the boundary often blurred in small teams? Give an example where strong UI cannot rescue weak UX.', 'EASY', 'UX covers research, flows, and structure; UI covers visual layout, color, and interaction detail.', 'Fundamentals'),
  ('q-0662', 'ux-design', 'Wireframing Purpose', 'Explain the purpose of wireframes in the design process and how they differ from mockups and prototypes. What level of fidelity is appropriate for wireframes shown in early stakeholder reviews? Why do designers often avoid color and imagery at this stage?', 'EASY', 'Wireframes focus attention on structure and content hierarchy rather than visual polish.', 'Process'),
  ('q-0663', 'ux-design', 'User Personas', 'Describe what a user persona is and the typical components it includes. How are personas derived from research data, and what are the risks of relying on stereotypes instead? Give an example of how a persona might influence a specific design decision.', 'EASY', 'Personas should be synthesized from observed behaviors and goals, not invented demographics.', 'Personas'),
  ('q-0664', 'ux-design', 'Usability Testing', 'Outline how to plan and run a moderated usability test with five participants. What metrics should you collect, and why is the think-aloud protocol useful? How do you decide whether a finding warrants a design change versus being an outlier?', 'MEDIUM', 'Five participants usually surface the majority of usability problems; severity and frequency drive prioritization.', 'Usability Testing'),
  ('q-0665', 'ux-design', 'Information Architecture', 'Define information architecture and explain its role in helping users find and understand content. Compare card sorting, tree testing, and reverse sorting as IA research methods. How would you restructure a confusing e-commerce navigation using these methods?', 'MEDIUM', 'Card sorting reveals mental models; tree testing validates a proposed structure.', 'IA'),
  ('q-0666', 'ux-design', 'Heuristic Evaluation', 'List five of Nielsen''s usability heuristics and give an example of a violation for each. How does heuristic evaluation complement user testing, and what are its main limitations? Describe how you would prioritize heuristic violations found by three separate evaluators.', 'MEDIUM', 'Heuristics are quick expert checks; user testing reveals problems experts miss.', 'Evaluation'),
  ('q-0667', 'ux-design', 'Accessibility in Design', 'Explain why accessibility is a core requirement rather than an add-on, referencing WCAG principles. Describe three concrete design changes that improve accessibility for users with visual impairments. How would you build accessibility into a design system so it scales across products?', 'MEDIUM', 'WCAG organizes guidance under perceivable, operable, understandable, and robust.', 'Accessibility'),
  ('q-0668', 'ux-design', 'Mobile vs Desktop Patterns', 'Compare common interaction patterns for mobile and desktop applications, focusing on navigation, input, and feedback. Why is direct manipulation more central on mobile, and how does context of use change design priorities? Give an example of a pattern that works well on one platform but poorly on the other.', 'MEDIUM', 'Touch targets, thumb reach, and interruptions shape mobile patterns differently than mouse and keyboard.', 'Patterns'),
  ('q-0669', 'ux-design', 'Design System Trade-offs', 'Discuss the trade-offs of adopting a design system across a portfolio of products. What governance model balances consistency with the need for product teams to innovate? How would you measure the success of a design system two years after launch?', 'HARD', 'Track adoption, contribution velocity, defect reduction, and designer or developer efficiency.', 'Systems'),
  ('q-0670', 'ux-design', 'Mixed-Methods Research Synthesis', 'Describe how to synthesize findings from a mixed-methods study combining quantitative analytics with qualitative interviews. What frameworks help triangulate conflicting signals, and how do you avoid cherry-picking? How would you communicate synthesized insights to executives who want a single number?', 'HARD', 'Triangulate by looking for convergence across methods and weight each by its limitations.', 'Synthesis'),
  ('q-0671', 'anatomy', 'Skeletal System Overview', 'Describe the two main divisions of the human skeleton and the number of bones in the adult body. Identify two functions of the skeletal system beyond structural support. Why are red bone marrow and mineral storage considered skeletal functions?', 'EASY', 'The axial and appendicular divisions together comprise about 206 bones in adults.', 'Skeletal'),
  ('q-0672', 'anatomy', 'Heart Chambers and Flow', 'Name the four chambers of the heart and trace the path of a red blood cell from the superior vena cava to the aorta. Which valves separate the atria from the ventricles, and what prevents backflow? Why is the left ventricle more muscular than the right?', 'EASY', 'Follow the unidirectional flow through right atrium, right ventricle, lungs, left atrium, left ventricle.', 'Cardiovascular'),
  ('q-0673', 'anatomy', 'Muscle Types Compared', 'Compare skeletal, cardiac, and smooth muscle in terms of control, striation, and location. Which type is responsible for peristalsis, and which is voluntary? Why is cardiac muscle uniquely described as autorhythmic?', 'EASY', 'Striation reflects organized sarcomeres; autorhythmicity comes from pacemaker cells.', 'Muscular'),
  ('q-0674', 'anatomy', 'Nervous System Divisions', 'Outline the major divisions of the nervous system (central versus peripheral, somatic versus autonomic, sympathetic versus parasympathetic). What physiological state does sympathetic dominance produce, and how does parasympathetic activity counter it? Give an example of an organ regulated by both branches.', 'MEDIUM', 'Sympathetic drives fight-or-flight; parasympathetic drives rest-and-digest.', 'Nervous'),
  ('q-0675', 'anatomy', 'Pulmonary and Systemic Circulation', 'Distinguish between pulmonary and systemic circulation, including the chambers and vessels involved in each. How does the circulation pattern change at birth, and what fetal structures are no longer needed? Explain why this transition is clinically significant.', 'MEDIUM', 'At birth the foramen ovale and ductus arteriosus close as the lungs take over gas exchange.', 'Circulation'),
  ('q-0676', 'anatomy', 'Endocrine Glands', 'Identify the major endocrine glands and one hormone each produces, along with the hormone''s primary effect. Distinguish between a hormone and a neurotransmitter, and explain how the hypothalamus links the nervous and endocrine systems. How does negative feedback regulate hormone levels?', 'MEDIUM', 'The hypothalamus releases factors that control the pituitary, which controls peripheral glands.', 'Endocrine'),
  ('q-0677', 'anatomy', 'Joint Classifications', 'Classify joints structurally (fibrous, cartilaginous, synovial) and functionally (synarthrosis, amphiarthrosis, diarthrosis). Give one example of each structural type and describe its range of motion. Why are synovial joints the most vulnerable to injury?', 'MEDIUM', 'Synovial joints trade wide range of motion for reduced stability.', 'Joints'),
  ('q-0678', 'anatomy', 'Digestive Tract Pathway', 'Trace the path of food through the digestive tract from mouth to anus, naming each major organ and one function. Where does most chemical digestion and absorption occur, and what structural features increase surface area? How do the liver, gallbladder, and pancreas contribute without being part of the tract itself?', 'MEDIUM', 'Villi and microvilli in the small intestine enormously expand absorptive surface area.', 'Digestive'),
  ('q-0679', 'anatomy', 'Cranial Nerves', 'List the twelve cranial nerves and classify each as sensory, motor, or mixed. Describe two clinical tests that would help localize a lesion of the facial nerve (CN VII). Why is the vagus nerve (CN X) clinically significant beyond head and neck function?', 'HARD', 'Use the mnemonic Some Say Marry Money for sensory, sensory, mixed, motor patterns.', 'Cranial Nerves'),
  ('q-0680', 'anatomy', 'Brachial Plexus', 'Describe the organization of the brachial plexus from roots through trunks, divisions, cords, and branches. Which terminal nerves innervate the major muscle groups of the upper limb? Explain how an upper trunk lesion (Erb''s palsy) produces a different posture than a lower trunk lesion (Klumpke''s palsy).', 'HARD', 'Erb''s palsy affects C5 and C6; Klumpke''s affects C8 and T1.', 'Plexus'),
  ('q-0681', 'pharmacology', 'Pharmacokinetics vs Pharmacodynamics', 'Distinguish between pharmacokinetics and pharmacodynamics, and explain why both must be understood to use a drug safely. Which discipline deals with what the body does to the drug, and which with what the drug does to the body? Give an example of how a change in one affects the other.', 'EASY', 'Pharmacokinetics covers absorption, distribution, metabolism, and excretion.', 'Fundamentals'),
  ('q-0682', 'pharmacology', 'Drug Half-Life', 'Define the elimination half-life of a drug and explain how it relates to dosing interval and steady state. Approximately how many half-lives are required to reach steady state with repeated dosing? How would half-life influence your decision between once-daily and twice-daily dosing?', 'EASY', 'About four to five half-lives are needed to approach steady state under fixed dosing.', 'Half-Life'),
  ('q-0683', 'pharmacology', 'Routes of Administration', 'Compare oral, intravenous, intramuscular, and subcutaneous routes of administration in terms of onset, bioavailability, and patient convenience. Which route avoids first-pass metabolism entirely, and why is that clinically useful? Identify one disadvantage of the IV route despite its rapid onset.', 'EASY', 'IV delivery gives 100 percent bioavailability but carries infection and embolism risk.', 'Administration'),
  ('q-0684', 'pharmacology', 'Drug-Drug Interactions', 'Classify drug-drug interactions as pharmacokinetic, pharmacodynamic, or pharmaceutical, with one example of each. How do cytochrome P450 inducers and inhibitors alter the effect of warfarin? What strategies can a clinician use to manage a clinically important interaction without stopping either drug?', 'MEDIUM', 'Inducers lower warfarin levels; inhibitors raise them, requiring INR monitoring and dose adjustment.', 'Interactions'),
  ('q-0685', 'pharmacology', 'Agonists and Antagonists', 'Compare full agonists, partial agonists, and antagonists in terms of affinity, efficacy, and maximal response. How does a partial agonist behave in the presence of a full agonist, and what is its clinical relevance? Explain the concept of inverse agonism and how it differs from competitive antagonism.', 'MEDIUM', 'A partial agonist has affinity but lower efficacy, so it can act as an antagonist in the presence of a full agonist.', 'Receptors'),
  ('q-0686', 'pharmacology', 'First-Pass Metabolism', 'Explain the first-pass effect and how it reduces the bioavailability of orally administered drugs. Which alternative routes bypass first-pass metabolism, and what are the trade-offs of each? Describe one clinical scenario in which first-pass metabolism would lead you to choose a non-oral route.', 'MEDIUM', 'Drugs absorbed from the gut pass through the portal vein and liver before reaching systemic circulation.', 'Metabolism'),
  ('q-0687', 'pharmacology', 'Therapeutic Index', 'Define the therapeutic index and explain why a narrow therapeutic index requires closer monitoring. How is the index derived from LD50 and ED50, and what are the limitations of this calculation? Give two examples of drugs with narrow therapeutic indices and the monitoring required for each.', 'MEDIUM', 'A narrow gap between toxic and effective dose demands individualized dosing and level monitoring.', 'Therapeutic Index'),
  ('q-0688', 'pharmacology', 'Adverse Drug Reactions', 'Classify adverse drug reactions using the Rawlins and Thompson system (Type A through F), with one example of each. How do Type A reactions differ from Type B in predictability and dose dependence? Outline a clinical approach when a patient on multiple medications develops a suspected reaction.', 'MEDIUM', 'Type A reactions are augmented and dose-dependent; Type B are bizarre and unpredictable.', 'Toxicology'),
  ('q-0689', 'pharmacology', 'Cytochrome P450 Induction', 'Explain how enzyme induction and inhibition alter the metabolism of co-administered drugs, focusing on the cytochrome P450 system. Compare the time course of induction versus inhibition and the clinical implications for dose adjustment. Outline how you would manage a patient starting rifampin while already on a CYP3A4 substrate.', 'HARD', 'Induction requires new protein synthesis and takes days to weeks; inhibition can occur within hours.', 'Enzymes'),
  ('q-0690', 'pharmacology', 'Pharmacogenomics in Dosing', 'Describe how genetic variation in drug-metabolizing enzymes such as CYP2D6 and CYP2C19 affects drug response. Give two examples of clinically actionable pharmacogenomic findings and how dosing would change. Discuss the barriers to widespread adoption of pharmacogenomic testing in routine clinical practice.', 'HARD', 'Poor metabolizers, extensive metabolizers, and ultra-rapid metabolizers need different doses.', 'Pharmacogenomics'),
  ('q-0691', 'behavioral-interview', 'Overcoming a Challenge', 'Tell me about a time you faced a significant challenge at work or school and how you overcame it. Use the STAR method to describe the situation, the task you were responsible for, the actions you took, and the result. What did you learn about your own problem-solving style from the experience?', 'EASY', 'Make sure the actions you describe are yours specifically, not the team''s in general.', 'Resilience'),
  ('q-0692', 'behavioral-interview', 'Team Collaboration', 'Describe a time when you worked on a team to achieve a shared goal. Walk me through the situation, your specific role, the actions you took to support the team, and the outcome. What would you do differently if you faced the same situation today?', 'EASY', 'Highlight your individual contribution within the team context rather than the team''s overall work.', 'Teamwork'),
  ('q-0693', 'behavioral-interview', 'Handling Conflict', 'Tell me about a time you had a disagreement with a colleague and how you resolved it. Use the STAR format to cover the situation, your responsibility, the steps you took to address the conflict, and the result. What did the experience teach you about your communication style?', 'EASY', 'Focus on what you did to understand the other perspective and find a workable path forward.', 'Conflict'),
  ('q-0694', 'behavioral-interview', 'Learning from Failure', 'Describe a project or initiative that did not go as planned and what you learned from the failure. Walk me through the situation, your role, the actions you took, and the result, including how you followed up. How have you applied the lessons learned to a later situation?', 'MEDIUM', 'Own the failure honestly and emphasize what changed in your approach afterward.', 'Growth'),
  ('q-0695', 'behavioral-interview', 'Leading Without Authority', 'Tell me about a time you had to influence a group without formal authority. Use the STAR method to describe the situation, the task you faced, the actions you took to persuade others, and the outcome. What strategies were most effective, and which would you change?', 'MEDIUM', 'Influence without authority usually relies on expertise, relationships, and shared goals.', 'Leadership'),
  ('q-0696', 'behavioral-interview', 'Delivering Under a Tight Deadline', 'Describe a situation in which you had to deliver under a tight deadline. Walk through the situation, the task, the actions you took to prioritize and execute, and the result. How did you balance quality against speed, and what trade-offs did you make?', 'MEDIUM', 'Show how you scoped, sequenced, and communicated rather than simply working longer hours.', 'Time Management'),
  ('q-0697', 'behavioral-interview', 'Disagreeing with a Manager', 'Tell me about a time you disagreed with your manager''s direction and how you handled it. Use STAR to describe the situation, your responsibility, the actions you took to raise your concern, and the result. What did you learn about when to push back and when to commit?', 'MEDIUM', 'Demonstrate respectful disagreement, evidence-based reasoning, and commitment once decided.', 'Communication'),
  ('q-0698', 'behavioral-interview', 'Adapting to Change', 'Describe a significant change at work or school that required you to adapt quickly. Walk through the situation, your task, the actions you took to adjust, and the result. What helped you stay effective during the transition, and what would you do differently next time?', 'MEDIUM', 'Show how you re-prioritized, sought new information, and maintained momentum.', 'Adaptability'),
  ('q-0699', 'behavioral-interview', 'Navigating an Ethical Dilemma', 'Tell me about a time you faced an ethical dilemma in a professional or academic setting. Use the STAR method to describe the situation, the responsibilities you had to balance, the actions you took, and the result. What principles guided your decision, and what were the consequences?', 'HARD', 'Identify the competing values explicitly and explain how you weighed them.', 'Ethics'),
  ('q-0700', 'behavioral-interview', 'Building Consensus Across Groups', 'Describe a situation where you had to build consensus across teams or departments with competing priorities. Walk me through the situation, your role, the actions you took to align stakeholders, and the result. How did you measure whether the consensus would hold over time?', 'HARD', 'Surface the underlying interests of each group and find shared outcomes rather than compromising on positions.', 'Influence')
