-- =============================================================
-- Flyway migration V2: Seed decks and questions
-- =============================================================
-- Target: PostgreSQL 12+
-- Seeds: 70 decks, 700 questions
-- Idempotent: each INSERT uses ON CONFLICT (id) DO NOTHING so the
-- migration can be re-applied safely during dev without duplicates.
-- =============================================================
-- Difficulty mix: 210 EASY / 350 MEDIUM / 140 HARD (3/5/2 per deck)
-- =============================================================

-- -------------------------------------------------------------
-- Decks
-- -------------------------------------------------------------
ON CONFLICT (id) DO NOTHING;

-- -------------------------------------------------------------
-- Questions
-- -------------------------------------------------------------
ON CONFLICT (id) DO NOTHING;

